// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "../interfaces/IModularCompliance.sol";
import "../interfaces/IModule.sol";
import "../libraries/Constants.sol";

/**
 * @title ModularCompliance
 * @dev Modular compliance contract for ERC-3643
 */
contract ModularCompliance is 
    Initializable, 
    OwnableUpgradeable, 
    UUPSUpgradeable,
    IModularCompliance 
{
    address private _tokenBound;
    address[] private _modules;
    mapping(address => bool) private _isModuleBound;

    modifier onlyToken() {
        require(msg.sender == _tokenBound, "ModularCompliance: caller is not the token");
        _;
    }

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(address _owner) external initializer {
        __Ownable_init();
        __UUPSUpgradeable_init();
        _transferOwnership(_owner);
    }

    // ============ Token Binding ============

    /**
     * @dev Bind token to compliance
     */
    function bindToken(address _token) external override {
        require(_token != address(0), "ModularCompliance: invalid token");
        require(_tokenBound == address(0), "ModularCompliance: token already bound");
        
        _tokenBound = _token;
        emit TokenBound(_token);
    }

    /**
     * @dev Unbind token from compliance
     */
    function unbindToken(address _token) external override onlyOwner {
        require(_token == _tokenBound, "ModularCompliance: token not bound");
        
        _tokenBound = address(0);
        emit TokenUnbound(_token);
    }

    // ============ Module Management ============

    /**
     * @dev Add compliance module
     */
    function addModule(address _module) external override onlyOwner {
        require(_module != address(0), "ModularCompliance: invalid module");
        require(!_isModuleBound[_module], "ModularCompliance: module already bound");
        require(_modules.length < Constants.MAX_MODULES, "ModularCompliance: max modules reached");
        require(
            IModule(_module).canComplianceBind(address(this)), 
            "ModularCompliance: module cannot bind"
        );

        _modules.push(_module);
        _isModuleBound[_module] = true;
        
        IModule(_module).bindCompliance(address(this));

        emit ModuleAdded(_module);
    }

    /**
     * @dev Remove compliance module
     */
    function removeModule(address _module) external override onlyOwner {
        require(_isModuleBound[_module], "ModularCompliance: module not bound");

        uint256 length = _modules.length;
        for (uint256 i = 0; i < length; i++) {
            if (_modules[i] == _module) {
                _modules[i] = _modules[length - 1];
                _modules.pop();
                break;
            }
        }

        _isModuleBound[_module] = false;
        IModule(_module).unbindCompliance(address(this));

        emit ModuleRemoved(_module);
    }

    /**
     * @dev Call function on module
     */
    function callModuleFunction(
        bytes calldata _callData, 
        address _module
    ) external override onlyOwner {
        require(_isModuleBound[_module], "ModularCompliance: module not bound");
        require(_callData.length >= 4, "ModularCompliance: invalid call data");

        (bool success, ) = _module.call(_callData);
        require(success, "ModularCompliance: module call failed");

        bytes4 selector = bytes4(_callData[:4]);
        emit ModuleInteraction(_module, selector);
    }

    // ============ Transfer Hooks ============

    /**
     * @dev Called on transfer
     */
    function transferred(
        address _from, 
        address _to, 
        uint256 _amount
    ) external override onlyToken {
        for (uint256 i = 0; i < _modules.length; i++) {
            IModule(_modules[i]).moduleTransferAction(_from, _to, _amount);
        }
    }

    /**
     * @dev Called on mint
     */
    function created(address _to, uint256 _amount) external override onlyToken {
        for (uint256 i = 0; i < _modules.length; i++) {
            IModule(_modules[i]).moduleMintAction(_to, _amount);
        }
    }

    /**
     * @dev Called on burn
     */
    function destroyed(address _from, uint256 _amount) external override onlyToken {
        for (uint256 i = 0; i < _modules.length; i++) {
            IModule(_modules[i]).moduleBurnAction(_from, _amount);
        }
    }

    // ============ Compliance Check ============

    /**
     * @dev Check if transfer is compliant
     */
    function canTransfer(
        address _from, 
        address _to, 
        uint256 _amount
    ) external view override returns (bool) {
        for (uint256 i = 0; i < _modules.length; i++) {
            if (!IModule(_modules[i]).moduleCheck(_from, _to, _amount, address(this))) {
                return false;
            }
        }
        return true;
    }

    // ============ View Functions ============

    /**
     * @dev Get bound modules
     */
    function getModules() external view override returns (address[] memory) {
        return _modules;
    }

    /**
     * @dev Get bound token
     */
    function getTokenBound() external view override returns (address) {
        return _tokenBound;
    }

    /**
     * @dev Check if module is bound
     */
    function isModuleBound(address _module) external view override returns (bool) {
        return _isModuleBound[_module];
    }

    function _authorizeUpgrade(address) internal override onlyOwner {}
}

contracts/compliance/modules/AbstractMod.content:
// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.20;

import "../../interfaces/IModule.sol";
import "../../interfaces/IModularCompliance.sol";

/**
 * @title AbstractModule
 * @dev Base contract for compliance modules
 */
abstract contract AbstractModule is IModule {
    // ============ State Variables ============
    
    mapping(address => bool) internal _boundCompliances;
    
    // ============ Events ============
    // Events are declared here (not in interface) to avoid duplication
    
    event ComplianceBound(address indexed compliance);
    event ComplianceUnbound(address indexed compliance);
    
    // ============ Modifiers ============
    
    modifier onlyBoundCompliance() {
        require(_boundCompliances[msg.sender], "AbstractModule: caller not bound compliance");
        _;
    }
    
    modifier onlyComplianceCall() {
        require(_boundCompliances[msg.sender], "AbstractModule: only compliance can call");
        _;
    }
    
    // ============ External Functions ============
    
    /**
     * @dev Binds compliance contract to this module
     */
    function bindCompliance(address _compliance) external override {
        require(_compliance != address(0), "AbstractModule: zero address");
        require(!_boundCompliances[_compliance], "AbstractModule: already bound");
        require(canComplianceBind(_compliance), "AbstractModule: compliance cannot bind");
        
        _boundCompliances[_compliance] = true;
        emit ComplianceBound(_compliance);
    }
    
    /**
     * @dev Unbinds compliance contract from this module
     */
    function unbindCompliance(address _compliance) external override {
        require(_boundCompliances[_compliance], "AbstractModule: not bound");
        require(msg.sender == _compliance, "AbstractModule: only compliance can unbind itself");
        
        _boundCompliances[_compliance] = false;
        emit ComplianceUnbound(_compliance);
    }
    
    /**
     * @dev Checks if compliance can bind to this module
     */
    function canComplianceBind(address _compliance) public view virtual override returns (bool) {
        return _compliance != address(0) && !_boundCompliances[_compliance];
    }
    
    /**
     * @dev Checks if compliance is bound
     */
    function isComplianceBound(address _compliance) public view override returns (bool) {
        return _boundCompliances[_compliance];
    }
    
    // ============ Virtual Functions ============
    
    function moduleTransferAction(address _from, address _to, uint256 _value) external virtual override;
    function moduleMintAction(address _to, uint256 _value) external virtual override;
    function moduleBurnAction(address _from, uint256 _value) external virtual override;
    function moduleCheck(address _from, address _to, uint256 _value, address _compliance) external view virtual override returns (bool);
    function name() external pure virtual override returns (string memory);
}

