// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.20;

import "./AbstractModule.sol";
import "../../interfaces/IIdentityRegistry.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";

/**
 * @title AccreditedInvestorModule
 * @dev Compliance module that restricts transfers to accredited investors only
 * Accreditation is verified through claims on the identity registry
 */
contract AccreditedInvestorModule is 
    Initializable, 
    AbstractModule, 
    UUPSUpgradeable,
    OwnableUpgradeable 
{
    // ============ Constants ============
    
    uint256 public constant ACCREDITED_INVESTOR_TOPIC = 4; // Claim topic for accreditation
    
    // ============ State Variables ============
    
    IIdentityRegistry public identityRegistry;
    
    // Mapping of addresses that are exempt from accreditation check
    mapping(address => bool) public exemptAddresses;
    
    // Whether the module is enabled
    bool public moduleEnabled;
    
    // ============ Events ============
    
    event IdentityRegistrySet(address indexed identityRegistry);
    event AddressExempted(address indexed account, bool exempt);
    event ModuleEnabledSet(bool enabled);
    
    // ============ Initializer ============
    
    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }
    
    /**
     * @dev Initializes the module
     * @param _identityRegistry Address of the identity registry
     * @param _owner Owner of the module
     */
    function initialize(
        address _identityRegistry,
        address _owner
    ) external initializer {
        require(_identityRegistry != address(0), "AccreditedInvestorModule: zero address");
        require(_owner != address(0), "AccreditedInvestorModule: zero owner");
        
        __Ownable_init();
_transferOwnership(_owner);
        __UUPSUpgradeable_init();
        
        identityRegistry = IIdentityRegistry(_identityRegistry);
        moduleEnabled = true;
        
        emit IdentityRegistrySet(_identityRegistry);
    }
    
    // ============ Admin Functions ============
    
    /**
     * @dev Sets the identity registry
     * @param _identityRegistry New identity registry address
     */
    function setIdentityRegistry(address _identityRegistry) external onlyOwner {
        require(_identityRegistry != address(0), "AccreditedInvestorModule: zero address");
        identityRegistry = IIdentityRegistry(_identityRegistry);
        emit IdentityRegistrySet(_identityRegistry);
    }
    
    /**
     * @dev Sets address exemption status
     * @param _address Address to set exemption for
     * @param _exempt Whether the address is exempt
     */
    function setExemptAddress(address _address, bool _exempt) external onlyOwner {
        exemptAddresses[_address] = _exempt;
        emit AddressExempted(_address, _exempt);
    }
    
    /**
     * @dev Batch set exempt addresses
     * @param _addresses Array of addresses
     * @param _exempt Array of exemption statuses
     */
    function batchSetExemptAddresses(
        address[] calldata _addresses, 
        bool[] calldata _exempt
    ) external onlyOwner {
        require(_addresses.length == _exempt.length, "AccreditedInvestorModule: length mismatch");
        
        for (uint256 i = 0; i < _addresses.length; i++) {
            exemptAddresses[_addresses[i]] = _exempt[i];
            emit AddressExempted(_addresses[i], _exempt[i]);
        }
    }
    
    /**
     * @dev Enables or disables the module
     * @param _enabled Whether the module should be enabled
     */
    function setModuleEnabled(bool _enabled) external onlyOwner {
        moduleEnabled = _enabled;
        emit ModuleEnabledSet(_enabled);
    }
    
    // ============ Module Functions ============
    
    /**
     * @dev Called on token transfer
     */
    function moduleTransferAction(
        address _from, 
        address _to, 
        uint256 _value
    ) external override onlyBoundCompliance {
        // No action needed on transfer, check happens in moduleCheck
    }
    
    /**
     * @dev Called on token mint
     */
    function moduleMintAction(
        address _to, 
        uint256 _value
    ) external override onlyBoundCompliance {
        // No action needed on mint, check happens in moduleCheck
    }
    
    /**
     * @dev Called on token burn
     */
    function moduleBurnAction(
        address _from, 
        uint256 _value
    ) external override onlyBoundCompliance {
        // No action needed on burn
    }
    
    /**
     * @dev Checks if transfer is compliant
     * @param _from Sender address
     * @param _to Recipient address
     * @param _value Transfer amount
     * @param _compliance Compliance contract address
     * @return bool True if transfer is compliant
     */
    function moduleCheck(
        address _from, 
        address _to, 
        uint256 _value, 
        address _compliance
    ) external view override returns (bool) {
        // If module is disabled, allow all transfers
        if (!moduleEnabled) {
            return true;
        }
        
        // Check if sender is exempt (for minting from zero address)
        if (_from == address(0) || exemptAddresses[_from]) {
            // Still need to check recipient
        } else {
            // Check sender is accredited (optional, usually only check recipient)
        }
        
        // Check if recipient is exempt
        if (_to == address(0) || exemptAddresses[_to]) {
            return true;
        }
        
        // Check if recipient is accredited
        return _isAccredited(_to);
    }
    
    /**
     * @dev Returns the module name
     */
    function name() external pure override returns (string memory) {
        return "AccreditedInvestorModule";
    }
    
    // ============ Internal Functions ============
    
    /**
     * @dev Checks if an address is accredited
     * @param _address Address to check
     * @return bool True if accredited
     */
    function _isAccredited(address _address) internal view returns (bool) {
        // Check if identity is registered
        if (!identityRegistry.isVerified(_address)) {
            return false;
        }
        
        // Get the identity contract
        IIdentity userIdentity = identityRegistry.identity(_address);
        if (address(userIdentity) == address(0)) {
            return false;
        }
        
        // Check for accreditation claim
        bytes32[] memory claimIds = userIdentity.getClaimIdsByTopic(ACCREDITED_INVESTOR_TOPIC);
        
        // If has at least one accreditation claim, consider accredited
        return claimIds.length > 0;
    }
    
    /**
     * @dev Authorizes upgrade (only owner)
     */
    function _authorizeUpgrade(address newImplementation) internal override onlyOwner {}
    
    // ============ View Functions ============
    
    /**
     * @dev Checks if an address is accredited (external view)
     * @param _address Address to check
     * @return bool True if accredited
     */
    function isAccredited(address _address) external view returns (bool) {
        return _isAccredited(_address);
    }
}

contracts/compliance/modules/ComplianceM.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";

interface IIdentityRegistry {
    function isVerified(address _userAddress) external view returns (bool);
    function getCountry(address _userAddress) external view returns (uint16);
    function getInvestorCategory(address _userAddress) external view returns (uint8);
}

/**
 * @title ComplianceModule
 * @notice Enforces transfer restrictions for RWA security tokens
 */
contract ComplianceModule is AccessControl {
    bytes32 public constant COMPLIANCE_ROLE = keccak256("COMPLIANCE_ROLE");

    IIdentityRegistry public identityRegistry;

    // Restricted countries (cannot receive tokens)
    mapping(uint16 => bool) public restrictedCountries;
    
    // Country-to-country transfer restrictions
    mapping(uint16 => mapping(uint16 => bool)) public countryRestrictions;
    
    // Maximum holding per investor category
    mapping(uint8 => uint256) public maxHolding;
    
    // Maximum number of investors per token
    uint256 public maxInvestors;
    mapping(address => uint256) public investorCount;
    mapping(address => mapping(address => bool)) public isInvestor;
    
    // Minimum investment amount
    uint256 public minInvestment;
    
    // Accreditation requirements by token
    mapping(address => bool) public requiresAccreditation;

    event CountryRestricted(uint16 indexed country, bool restricted);
    event MaxHoldingSet(uint8 indexed category, uint256 amount);
    event MaxInvestorsSet(uint256 maxInvestors);

    constructor(address _identityRegistry) {
        identityRegistry = IIdentityRegistry(_identityRegistry);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(COMPLIANCE_ROLE, msg.sender);
    }

    /**
     * @notice Check if a transfer is compliant
     */
    function canTransfer(
        address _from,
        address _to,
        uint256 _amount
    ) external view returns (bool) {
        // Recipient must be verified
        if (!identityRegistry.isVerified(_to)) {
            return false;
        }
        
        // Check country restrictions
        uint16 toCountry = identityRegistry.getCountry(_to);
        if (restrictedCountries[toCountry]) {
            return false;
        }
        
        // Check country-to-country restrictions
        if (_from != address(0)) {
            uint16 fromCountry = identityRegistry.getCountry(_from);
            if (countryRestrictions[fromCountry][toCountry]) {
                return false;
            }
        }
        
        // Check investor category restrictions
        uint8 category = identityRegistry.getInvestorCategory(_to);
        if (maxHolding[category] > 0 && _amount > maxHolding[category]) {
            return false;
        }
        
        // Check minimum investment
        if (_amount < minInvestment) {
            return false;
        }
        
        return true;
    }

    /**
     * @notice Called after a successful transfer to update state
     */
    function transferred(
        address _from,
        address _to,
        uint256 /* _amount */
    ) external {
        address token = msg.sender;
        
        // Track investor count
        if (!isInvestor[token][_to]) {
            isInvestor[token][_to] = true;
            investorCount[token]++;
        }
        
        // Remove from investor count if balance is zero (handled by token)
    }

    /**
     * @notice Restrict a country from receiving tokens
     */
    function setCountryRestriction(uint16 _country, bool _restricted) 
        external 
        onlyRole(COMPLIANCE_ROLE) 
    {
        restrictedCountries[_country] = _restricted;
        emit CountryRestricted(_country, _restricted);
    }

    /**
     * @notice Set country-to-country transfer restriction
     */
    function setCountryToCountryRestriction(
        uint16 _fromCountry,
        uint16 _toCountry,
        bool _restricted
    ) external onlyRole(COMPLIANCE_ROLE) {
        countryRestrictions[_fromCountry][_toCountry] = _restricted;
    }

    /**
     * @notice Set maximum holding per investor category
     */
    function setMaxHolding(uint8 _category, uint256 _amount) 
        external 
        onlyRole(COMPLIANCE_ROLE) 
    {
        maxHolding[_category] = _amount;
        emit MaxHoldingSet(_category, _amount);
    }

    /**
     * @notice Set maximum number of investors
     */
    function setMaxInvestors(uint256 _maxInvestors) 
        external 
        onlyRole(COMPLIANCE_ROLE) 
    {
        maxInvestors = _maxInvestors;
        emit MaxInvestorsSet(_maxInvestors);
    }

    /**
     * @notice Set minimum investment amount
     */
    function setMinInvestment(uint256 _minInvestment) 
        external 
        onlyRole(COMPLIANCE_ROLE) 
    {
        minInvestment = _minInvestment;
    }

    /**
     * @notice Batch restrict countries
     */
    function batchRestrictCountries(uint16[] calldata _countries, bool _restricted)
        external
        onlyRole(COMPLIANCE_ROLE)
    {
        for (uint i = 0; i < _countries.length; i++) {
            restrictedCountries[_countries[i]] = _restricted;
        }
    }
}

contracts/compliance/modules/CountryRest.content:
// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.20;

import "./AbstractModule.sol";
import "../../interfaces/IIdentityRegistry.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";

/**
 * @title CountryRestrictModule
 * @dev Compliance module that restricts transfers based on country codes
 * Can operate in whitelist or blacklist mode
 */
contract CountryRestrictModule is 
    Initializable, 
    AbstractModule, 
    UUPSUpgradeable,
    OwnableUpgradeable 
{
    // ============ State Variables ============
    
    IIdentityRegistry public identityRegistry;
    
    // Country restriction mappings
    mapping(uint16 => bool) public restrictedCountries;
    
    // If true, restrictedCountries acts as a blacklist (blocked countries)
    // If false, restrictedCountries acts as a whitelist (allowed countries)
    bool public isBlacklistMode;
    
    // Whether the module is enabled
    bool public moduleEnabled;
    
    // ============ Events ============
    
    event IdentityRegistrySet(address indexed identityRegistry);
    event CountryRestrictionSet(uint16 indexed countryCode, bool restricted);
    event BlacklistModeSet(bool isBlacklist);
    event ModuleEnabledSet(bool enabled);
    
    // ============ Initializer ============
    
    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }
    
    /**
     * @dev Initializes the module
     * @param _identityRegistry Address of the identity registry
     * @param _owner Owner of the module
     * @param _isBlacklistMode Whether to operate in blacklist mode
     */
    function initialize(
        address _identityRegistry,
        address _owner,
        bool _isBlacklistMode
    ) external initializer {
        require(_identityRegistry != address(0), "CountryRestrictModule: zero address");
        require(_owner != address(0), "CountryRestrictModule: zero owner");
        
        __Ownable_init();
_transferOwnership(_owner);
        __UUPSUpgradeable_init();
        
        identityRegistry = IIdentityRegistry(_identityRegistry);
        isBlacklistMode = _isBlacklistMode;
        moduleEnabled = true;
        
        emit IdentityRegistrySet(_identityRegistry);
        emit BlacklistModeSet(_isBlacklistMode);
    }
    
    // ============ Admin Functions ============
    
    /**
     * @dev Sets the identity registry
     * @param _identityRegistry New identity registry address
     */
    function setIdentityRegistry(address _identityRegistry) external onlyOwner {
        require(_identityRegistry != address(0), "CountryRestrictModule: zero address");
        identityRegistry = IIdentityRegistry(_identityRegistry);
        emit IdentityRegistrySet(_identityRegistry);
    }
    
    /**
     * @dev Sets country restriction status
     * @param _countryCode ISO 3166-1 numeric country code
     * @param _restricted Whether the country is restricted
     */
    function setCountryRestriction(uint16 _countryCode, bool _restricted) external onlyOwner {
        restrictedCountries[_countryCode] = _restricted;
        emit CountryRestrictionSet(_countryCode, _restricted);
    }
    
    /**
     * @dev Batch set country restrictions
     * @param _countryCodes Array of country codes
     * @param _restricted Array of restriction statuses
     */
    function batchSetCountryRestrictions(
        uint16[] calldata _countryCodes,
        bool[] calldata _restricted
    ) external onlyOwner {
        require(_countryCodes.length == _restricted.length, "CountryRestrictModule: length mismatch");
        
        for (uint256 i = 0; i < _countryCodes.length; i++) {
            restrictedCountries[_countryCodes[i]] = _restricted[i];
            emit CountryRestrictionSet(_countryCodes[i], _restricted[i]);
        }
    }
    
    /**
     * @dev Sets blacklist mode
     * @param _isBlacklist True for blacklist mode, false for whitelist mode
     */
    function setBlacklistMode(bool _isBlacklist) external onlyOwner {
        isBlacklistMode = _isBlacklist;
        emit BlacklistModeSet(_isBlacklist);
    }
    
    /**
     * @dev Enables or disables the module
     * @param _enabled Whether the module should be enabled
     */
    function setModuleEnabled(bool _enabled) external onlyOwner {
        moduleEnabled = _enabled;
        emit ModuleEnabledSet(_enabled);
    }
    
    // ============ Module Functions ============
    
    /**
     * @dev Called on token transfer
     */
    function moduleTransferAction(
        address _from,
        address _to,
        uint256 _value
    ) external override onlyBoundCompliance {
        // No action needed on transfer, check happens in moduleCheck
    }
    
    /**
     * @dev Called on token mint
     */
    function moduleMintAction(
        address _to,
        uint256 _value
    ) external override onlyBoundCompliance {
        // No action needed on mint
    }
    
    /**
     * @dev Called on token burn
     */
    function moduleBurnAction(
        address _from,
        uint256 _value
    ) external override onlyBoundCompliance {
        // No action needed on burn
    }
    
    /**
     * @dev Checks if transfer is compliant based on country restrictions
     * @param _from Sender address
     * @param _to Recipient address
     * @param _value Transfer amount (unused)
     * @param _compliance Compliance contract address (unused)
     * @return bool True if transfer is compliant
     */
    function moduleCheck(
        address _from,
        address _to,
        uint256 _value,
        address _compliance
    ) external view override returns (bool) {
        // If module is disabled, allow all transfers
        if (!moduleEnabled) {
            return true;
        }
        
        // Skip check for zero addresses (mint/burn)
        if (_from == address(0) || _to == address(0)) {
            return true;
        }
        
        // Check sender country
        if (!_isCountryAllowed(_from)) {
            return false;
        }
        
        // Check recipient country
        if (!_isCountryAllowed(_to)) {
            return false;
        }
        
        return true;
    }
    
    /**
     * @dev Returns the module name
     */
    function name() external pure override returns (string memory) {
        return "CountryRestrictModule";
    }
    
    // ============ Internal Functions ============
    
    /**
     * @dev Checks if a user's country is allowed
     * @param _user Address to check
     * @return bool True if country is allowed
     */
    function _isCountryAllowed(address _user) internal view returns (bool) {
        // Get user's country from identity registry
        uint16 countryCode = identityRegistry.investorCountry(_user);
        
        // If no country is set, default behavior depends on mode
        if (countryCode == 0) {
            // In blacklist mode, allow if no country (not explicitly blocked)
            // In whitelist mode, deny if no country (not explicitly allowed)
            return isBlacklistMode;
        }
        
        bool isInList = restrictedCountries[countryCode];
        
        if (isBlacklistMode) {
            // Blacklist mode: country is allowed if NOT in the restricted list
            return !isInList;
        } else {
            // Whitelist mode: country is allowed if IN the restricted list
            return isInList;
        }
    }
    
    /**
     * @dev Authorizes upgrade (only owner)
     */
    function _authorizeUpgrade(address newImplementation) internal override onlyOwner {}
    
    // ============ View Functions ============
    
    /**
     * @dev Checks if a country is restricted
     * @param _countryCode Country code to check
     * @return bool True if country is in the restricted list
     */
    function isCountryRestricted(uint16 _countryCode) external view returns (bool) {
        return restrictedCountries[_countryCode];
    }
    
    /**
     * @dev Checks if a user's country is allowed
     * @param _user Address to check
     * @return bool True if user's country is allowed
     */
    function isUserCountryAllowed(address _user) external view returns (bool) {
        return _isCountryAllowed(_user);
    }
}

contracts/compliance/modules/LockupModul.content:
// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.20;

import "./AbstractModule.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";

/**
 * @title LockupModule
 * @dev Compliance module that enforces token lockup periods
 * Tokens cannot be transferred until the lockup period expires
 */
contract LockupModule is 
    Initializable, 
    AbstractModule, 
    UUPSUpgradeable,
    OwnableUpgradeable 
{
    // ============ Structs ============
    
    struct LockupInfo {
        uint256 amount;
        uint256 releaseTime;
    }
    
    // ============ State Variables ============
    
    // Default lockup period in seconds (90 days)
    uint256 public defaultLockupPeriod;
    
    // User => array of lockups
    mapping(address => LockupInfo[]) public userLockups;
    
    // User => total locked amount
    mapping(address => uint256) public totalLockedAmount;
    
    // Whether the module is enabled
    bool public moduleEnabled;
    
    // Addresses exempt from lockup
    mapping(address => bool) public exemptAddresses;
    
    // ============ Constants ============
    
    uint256 public constant MIN_LOCKUP_PERIOD = 1 days;
    uint256 public constant MAX_LOCKUP_PERIOD = 10 * 365 days; // 10 years
    
    // ============ Events ============
    
    event LockupCreated(address indexed user, uint256 amount, uint256 releaseTime);
    event LockupReleased(address indexed user, uint256 amount);
    event DefaultLockupPeriodSet(uint256 period);
    event AddressExempted(address indexed account, bool exempt);
    event ModuleEnabledSet(bool enabled);
    
    // ============ Initializer ============
    
    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }
    
    /**
     * @dev Initializes the module
     * @param _owner Owner of the module
     * @param _defaultLockupPeriod Default lockup period in seconds
     */
    function initialize(
        address _owner,
        uint256 _defaultLockupPeriod
    ) external initializer {
        require(_owner != address(0), "LockupModule: zero owner");
        require(
            _defaultLockupPeriod >= MIN_LOCKUP_PERIOD && 
            _defaultLockupPeriod <= MAX_LOCKUP_PERIOD,
            "LockupModule: invalid lockup period"
        );
        
        __Ownable_init();
_transferOwnership(_owner);
        __UUPSUpgradeable_init();
        
        defaultLockupPeriod = _defaultLockupPeriod;
        moduleEnabled = true;
        
        emit DefaultLockupPeriodSet(_defaultLockupPeriod);
    }
    
    // ============ Admin Functions ============
    
    /**
     * @dev Sets the default lockup period
     * @param _period New default lockup period in seconds
     */
    function setDefaultLockupPeriod(uint256 _period) external onlyOwner {
        require(
            _period >= MIN_LOCKUP_PERIOD && _period <= MAX_LOCKUP_PERIOD,
            "LockupModule: invalid lockup period"
        );
        defaultLockupPeriod = _period;
        emit DefaultLockupPeriodSet(_period);
    }
    
    /**
     * @dev Sets address exemption status
     * @param _address Address to set exemption for
     * @param _exempt Whether the address is exempt
     */
    function setExemptAddress(address _address, bool _exempt) external onlyOwner {
        exemptAddresses[_address] = _exempt;
        emit AddressExempted(_address, _exempt);
    }
    
    /**
     * @dev Batch set exempt addresses
     * @param _addresses Array of addresses
     * @param _exempt Array of exemption statuses
     */
    function batchSetExemptAddresses(
        address[] calldata _addresses,
        bool[] calldata _exempt
    ) external onlyOwner {
        require(_addresses.length == _exempt.length, "LockupModule: length mismatch");
        
        for (uint256 i = 0; i < _addresses.length; i++) {
            exemptAddresses[_addresses[i]] = _exempt[i];
            emit AddressExempted(_addresses[i], _exempt[i]);
        }
    }
    
    /**
     * @dev Enables or disables the module
     * @param _enabled Whether the module should be enabled
     */
    function setModuleEnabled(bool _enabled) external onlyOwner {
        moduleEnabled = _enabled;
        emit ModuleEnabledSet(_enabled);
    }
    
    /**
     * @dev Creates a lockup for a user (admin function)
     * @param _user User address
     * @param _amount Amount to lock
     * @param _releaseTime Unix timestamp when tokens can be released
     */
    function createLockup(
        address _user,
        uint256 _amount,
        uint256 _releaseTime
    ) external onlyOwner {
        require(_user != address(0), "LockupModule: zero address");
        require(_amount > 0, "LockupModule: zero amount");
        require(_releaseTime > block.timestamp, "LockupModule: release time in past");
        
        userLockups[_user].push(LockupInfo({
            amount: _amount,
            releaseTime: _releaseTime
        }));
        
        totalLockedAmount[_user] += _amount;
        
        emit LockupCreated(_user, _amount, _releaseTime);
    }
    
    // ============ Module Functions ============
    
    /**
     * @dev Called on token transfer - no action needed
     */
    function moduleTransferAction(
        address _from,
        address _to,
        uint256 _value
    ) external override onlyBoundCompliance {
        // Lockups are checked in moduleCheck, no action needed here
    }
    
    /**
     * @dev Called on token mint - creates lockup for new tokens
     */
    function moduleMintAction(
        address _to,
        uint256 _value
    ) external override onlyBoundCompliance {
        // Skip if module disabled or address is exempt
        if (!moduleEnabled || exemptAddresses[_to] || _to == address(0)) {
            return;
        }
        
        // Create lockup for newly minted tokens
        uint256 releaseTime = block.timestamp + defaultLockupPeriod;
        
        userLockups[_to].push(LockupInfo({
            amount: _value,
            releaseTime: releaseTime
        }));
        
        totalLockedAmount[_to] += _value;
        
        emit LockupCreated(_to, _value, releaseTime);
    }
    
    /**
     * @dev Called on token burn - reduces locked amount
     */
    function moduleBurnAction(
        address _from,
        uint256 _value
    ) external override onlyBoundCompliance {
        // Reduce locked amount if burning locked tokens
        if (totalLockedAmount[_from] > 0) {
            if (_value >= totalLockedAmount[_from]) {
                totalLockedAmount[_from] = 0;
            } else {
                totalLockedAmount[_from] -= _value;
            }
        }
    }
    
    /**
     * @dev Checks if transfer is compliant based on lockup rules
     * @param _from Sender address
     * @param _to Recipient address
     * @param _value Transfer amount
     * @param _compliance Compliance contract address (unused)
     * @return bool True if transfer is compliant
     */
    function moduleCheck(
        address _from,
        address _to,
        uint256 _value,
        address _compliance
    ) external view override returns (bool) {
        // If module is disabled, allow all transfers
        if (!moduleEnabled) {
            return true;
        }
        
        // Skip check for minting (from zero address)
        if (_from == address(0)) {
            return true;
        }
        
        // Skip check for exempt addresses
        if (exemptAddresses[_from]) {
            return true;
        }
        
        // Calculate available (unlocked) balance
        uint256 lockedAmount = getLockedAmount(_from);
        uint256 availableAmount = _getAvailableAmount(_from, lockedAmount);
        
        // Check if transfer amount is within available balance
        return _value <= availableAmount;
    }
    
    /**
     * @dev Returns the module name
     */
    function name() external pure override returns (string memory) {
        return "LockupModule";
    }
    
    // ============ Internal Functions ============
    
    /**
     * @dev Gets available (unlocked) amount for a user
     * @param _user User address
     * @param _lockedAmount Current locked amount
     * @return uint256 Available amount
     */
    function _getAvailableAmount(
        address _user, 
        uint256 _lockedAmount
    ) internal view returns (uint256) {
        // This would need the token balance, which we don't have access to here
        // In practice, the compliance contract would need to provide this
        // For now, we assume the check is: transfer amount <= (balance - lockedAmount)
        // The actual balance check happens at the token level
        
        // Return max uint if no lockups (no restriction from this module)
        if (_lockedAmount == 0) {
            return type(uint256).max;
        }
        
        // The compliance/token contract should ensure:
        // transferAmount <= balanceOf(user) - lockedAmount
        return type(uint256).max - _lockedAmount;
    }
    
    /**
     * @dev Authorizes upgrade (only owner)
     */
    function _authorizeUpgrade(address newImplementation) internal override onlyOwner {}
    
    // ============ View Functions ============
    
    /**
     * @dev Gets the currently locked amount for a user
     * @param _user User address
     * @return uint256 Total locked amount
     */
    function getLockedAmount(address _user) public view returns (uint256) {
        uint256 locked = 0;
        LockupInfo[] storage lockups = userLockups[_user];
        
        for (uint256 i = 0; i < lockups.length; i++) {
            if (lockups[i].releaseTime > block.timestamp) {
                locked += lockups[i].amount;
            }
        }
        
        return locked;
    }
    
    /**
     * @dev Gets all lockups for a user
     * @param _user User address
     * @return LockupInfo[] Array of lockups
     */
    function getUserLockups(address _user) external view returns (LockupInfo[] memory) {
        return userLockups[_user];
    }
    
    /**
     * @dev Gets the number of lockups for a user
     * @param _user User address
     * @return uint256 Number of lockups
     */
    function getLockupCount(address _user) external view returns (uint256) {
        return userLockups[_user].length;
    }
    
    /**
     * @dev Gets unlocked amount for a user
     * @param _user User address
     * @return uint256 Total unlocked amount
     */
    function getUnlockedAmount(address _user) external view returns (uint256) {
        return totalLockedAmount[_user] - getLockedAmount(_user);
    }
}

contracts/compliance/modules/MaxBalanceM.content:
// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.20;

import "./AbstractModule.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";

/**
 * @title MaxBalanceModule
 * @dev Compliance module that enforces maximum token balance per holder
 */
contract MaxBalanceModule is 
    Initializable, 
    AbstractModule, 
    UUPSUpgradeable,
    OwnableUpgradeable 
{
    // ============ State Variables ============
    
    // Default maximum balance (0 = no limit)
    uint256 public defaultMaxBalance;
    
    // Custom max balance per address (0 = use default)
    mapping(address => uint256) public customMaxBalance;
    
    // Addresses exempt from max balance check
    mapping(address => bool) public exemptAddresses;
    
    // Whether the module is enabled
    bool public moduleEnabled;
    
    // Token contract address for balance checks
    address public tokenAddress;
    
    // ============ Events ============
    
    event DefaultMaxBalanceSet(uint256 maxBalance);
    event CustomMaxBalanceSet(address indexed account, uint256 maxBalance);
    event AddressExempted(address indexed account, bool exempt);
    event ModuleEnabledSet(bool enabled);
    event TokenAddressSet(address indexed token);
    
    // ============ Initializer ============
    
    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }
    
    /**
     * @dev Initializes the module
     * @param _owner Owner of the module
     * @param _defaultMaxBalance Default maximum balance
     */
    function initialize(
        address _owner,
        uint256 _defaultMaxBalance
    ) external initializer {
        require(_owner != address(0), "MaxBalanceModule: zero owner");
        
        __Ownable_init();
_transferOwnership(_owner);
        __UUPSUpgradeable_init();
        
        defaultMaxBalance = _defaultMaxBalance;
        moduleEnabled = true;
        
        emit DefaultMaxBalanceSet(_defaultMaxBalance);
    }
    
    // ============ Admin Functions ============
    
    /**
     * @dev Sets the token address for balance checks
     * @param _token Token contract address
     */
    function setTokenAddress(address _token) external onlyOwner {
        require(_token != address(0), "MaxBalanceModule: zero address");
        tokenAddress = _token;
        emit TokenAddressSet(_token);
    }
    
    /**
     * @dev Sets the default maximum balance
     * @param _maxBalance New default maximum balance (0 = no limit)
     */
    function setDefaultMaxBalance(uint256 _maxBalance) external onlyOwner {
        defaultMaxBalance = _maxBalance;
        emit DefaultMaxBalanceSet(_maxBalance);
    }
    
    /**
     * @dev Sets custom maximum balance for an address
     * @param _address Address to set custom max for
     * @param _maxBalance Custom maximum balance (0 = use default)
     */
    function setCustomMaxBalance(address _address, uint256 _maxBalance) external onlyOwner {
        customMaxBalance[_address] = _maxBalance;
        emit CustomMaxBalanceSet(_address, _maxBalance);
    }
    
    /**
     * @dev Batch set custom maximum balances
     * @param _addresses Array of addresses
     * @param _maxBalances Array of maximum balances
     */
    function batchSetCustomMaxBalance(
        address[] calldata _addresses,
        uint256[] calldata _maxBalances
    ) external onlyOwner {
        require(_addresses.length == _maxBalances.length, "MaxBalanceModule: length mismatch");
        
        for (uint256 i = 0; i < _addresses.length; i++) {
            customMaxBalance[_addresses[i]] = _maxBalances[i];
            emit CustomMaxBalanceSet(_addresses[i], _maxBalances[i]);
        }
    }
    
    /**
     * @dev Sets address exemption status
     * @param _address Address to set exemption for
     * @param _exempt Whether the address is exempt
     */
    function setExemptAddress(address _address, bool _exempt) external onlyOwner {
        exemptAddresses[_address] = _exempt;
        emit AddressExempted(_address, _exempt);
    }
    
    /**
     * @dev Batch set exempt addresses
     * @param _addresses Array of addresses
     * @param _exempt Array of exemption statuses
     */
    function batchSetExemptAddresses(
        address[] calldata _addresses,
        bool[] calldata _exempt
    ) external onlyOwner {
        require(_addresses.length == _exempt.length, "MaxBalanceModule: length mismatch");
        
        for (uint256 i = 0; i < _addresses.length; i++) {
            exemptAddresses[_addresses[i]] = _exempt[i];
            emit AddressExempted(_addresses[i], _exempt[i]);
        }
    }
    
    /**
     * @dev Enables or disables the module
     * @param _enabled Whether the module should be enabled
     */
    function setModuleEnabled(bool _enabled) external onlyOwner {
        moduleEnabled = _enabled;
        emit ModuleEnabledSet(_enabled);
    }
    
    // ============ Module Functions ============
    
    /**
     * @dev Called on token transfer
     */
    function moduleTransferAction(
        address _from,
        address _to,
        uint256 _value
    ) external override onlyBoundCompliance {
        // No action needed, check happens in moduleCheck
    }
    
    /**
     * @dev Called on token mint
     */
    function moduleMintAction(
        address _to,
        uint256 _value
    ) external override onlyBoundCompliance {
        // No action needed, check happens in moduleCheck
    }
    
    /**
     * @dev Called on token burn
     */
    function moduleBurnAction(
        address _from,
        uint256 _value
    ) external override onlyBoundCompliance {
        // No action needed
    }
    
    /**
     * @dev Checks if transfer is compliant based on max balance rules
     * @param _from Sender address
     * @param _to Recipient address
     * @param _value Transfer amount
     * @param _compliance Compliance contract address
     * @return bool True if transfer is compliant
     */
    function moduleCheck(
        address _from,
        address _to,
        uint256 _value,
        address _compliance
    ) external view override returns (bool) {
        // If module is disabled, allow all transfers
        if (!moduleEnabled) {
            return true;
        }
        
        // Skip check for burning (to zero address)
        if (_to == address(0)) {
            return true;
        }
        
        // Skip check for exempt addresses
        if (exemptAddresses[_to]) {
            return true;
        }
        
        // Get max balance for recipient
        uint256 maxBalance = _getMaxBalance(_to);
        
        // If no limit (0), allow transfer
        if (maxBalance == 0) {
            return true;
        }
        
        // Get current balance of recipient
        uint256 currentBalance = _getBalance(_to);
        
        // Check if new balance would exceed max
        return (currentBalance + _value) <= maxBalance;
    }
    
    /**
     * @dev Returns the module name
     */
    function name() external pure override returns (string memory) {
        return "MaxBalanceModule";
    }
    
    // ============ Internal Functions ============
    
    /**
     * @dev Gets the maximum balance for an address
     * @param _address Address to check
     * @return uint256 Maximum balance
     */
    function _getMaxBalance(address _address) internal view returns (uint256) {
        uint256 custom = customMaxBalance[_address];
        if (custom > 0) {
            return custom;
        }
        return defaultMaxBalance;
    }
    
    /**
     * @dev Gets the current token balance of an address
     * @param _address Address to check
     * @return uint256 Current balance
     */
    function _getBalance(address _address) internal view returns (uint256) {
        if (tokenAddress == address(0)) {
            return 0;
        }
        
        // Call balanceOf on the token contract
        (bool success, bytes memory data) = tokenAddress.staticcall(
            abi.encodeWithSignature("balanceOf(address)", _address)
        );
        
        if (success && data.length >= 32) {
            return abi.decode(data, (uint256));
        }
        
        return 0;
    }
    
    /**
     * @dev Authorizes upgrade (only owner)
     */
    function _authorizeUpgrade(address newImplementation) internal override onlyOwner {}
    
    // ============ View Functions ============
    
    /**
     * @dev Gets the effective max balance for an address
     * @param _address Address to check
     * @return uint256 Effective maximum balance
     */
    function getEffectiveMaxBalance(address _address) external view returns (uint256) {
        return _getMaxBalance(_address);
    }
    
    /**
     * @dev Checks if an address can receive a specific amount
     * @param _address Address to check
     * @param _amount Amount to receive
     * @return bool True if address can receive the amount
     */
    function canReceive(address _address, uint256 _amount) external view returns (bool) {
        if (!moduleEnabled || exemptAddresses[_address]) {
            return true;
        }
        
        uint256 maxBalance = _getMaxBalance(_address);
        if (maxBalance == 0) {
            return true;
        }
        
        uint256 currentBalance = _getBalance(_address);
        return (currentBalance + _amount) <= maxBalance;
    }
}

contracts/compliance/modules/TransferFee.content:
// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.20;

import "./AbstractModule.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";

/**
 * @title TransferFeesModule
 * @dev Compliance module that tracks and enforces transfer fees
 * Note: Actual fee collection happens at the token level, this module tracks fee requirements
 */
contract TransferFeesModule is 
    Initializable, 
    AbstractModule, 
    UUPSUpgradeable,
    OwnableUpgradeable 
{
    // ============ Constants ============
    
    uint256 public constant BPS_DENOMINATOR = 10000;
    uint256 public constant MAX_FEE_BPS = 1000; // 10% max fee
    
    // ============ State Variables ============
    
    // Default transfer fee in basis points
    uint256 public defaultFeeBps;
    
    // Fee recipient address
    address public feeRecipient;
    
    // Custom fee rates per address (0 = use default, max uint256 = exempt)
    mapping(address => uint256) public customFeeBps;
    
    // Addresses exempt from fees
    mapping(address => bool) public exemptAddresses;
    
    // Whether the module is enabled
    bool public moduleEnabled;
    
    // Total fees collected (for tracking)
    uint256 public totalFeesCollected;
    
    // ============ Events ============
    
    event DefaultFeeSet(uint256 feeBps);
    event FeeRecipientSet(address indexed recipient);
    event CustomFeeSet(address indexed account, uint256 feeBps);
    event AddressExempted(address indexed account, bool exempt);
    event ModuleEnabledSet(bool enabled);
    event FeeCollected(address indexed from, address indexed to, uint256 amount, uint256 fee);
    
    // ============ Initializer ============
    
    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }
    
    /**
     * @dev Initializes the module
     * @param _owner Owner of the module
     * @param _defaultFeeBps Default fee in basis points
     * @param _feeRecipient Address to receive fees
     */
    function initialize(
        address _owner,
        uint256 _defaultFeeBps,
        address _feeRecipient
    ) external initializer {
        require(_owner != address(0), "TransferFeesModule: zero owner");
        require(_defaultFeeBps <= MAX_FEE_BPS, "TransferFeesModule: fee too high");
        require(_feeRecipient != address(0), "TransferFeesModule: zero recipient");
        
        __Ownable_init();
_transferOwnership(_owner);
        __UUPSUpgradeable_init();
        
        defaultFeeBps = _defaultFeeBps;
        feeRecipient = _feeRecipient;
        moduleEnabled = true;
        
        emit DefaultFeeSet(_defaultFeeBps);
        emit FeeRecipientSet(_feeRecipient);
    }
    
    // ============ Admin Functions ============
    
    /**
     * @dev Sets the default fee
     * @param _feeBps New default fee in basis points
     */
    function setDefaultFee(uint256 _feeBps) external onlyOwner {
        require(_feeBps <= MAX_FEE_BPS, "TransferFeesModule: fee too high");
        defaultFeeBps = _feeBps;
        emit DefaultFeeSet(_feeBps);
    }
    
    /**
     * @dev Sets the fee recipient
     * @param _recipient New fee recipient address
     */
    function setFeeRecipient(address _recipient) external onlyOwner {
        require(_recipient != address(0), "TransferFeesModule: zero recipient");
        feeRecipient = _recipient;
        emit FeeRecipientSet(_recipient);
    }
    
    /**
     * @dev Sets custom fee for an address
     * @param _address Address to set custom fee for
     * @param _feeBps Custom fee in basis points
     */
    function setCustomFee(address _address, uint256 _feeBps) external onlyOwner {
        require(_feeBps <= MAX_FEE_BPS, "TransferFeesModule: fee too high");
        customFeeBps[_address] = _feeBps;
        emit CustomFeeSet(_address, _feeBps);
    }
    
    /**
     * @dev Batch set custom fees
     * @param _addresses Array of addresses
     * @param _feeBps Array of fees in basis points
     */
    function batchSetCustomFees(
        address[] calldata _addresses,
        uint256[] calldata _feeBps
    ) external onlyOwner {
        require(_addresses.length == _feeBps.length, "TransferFeesModule: length mismatch");
        
        for (uint256 i = 0; i < _addresses.length; i++) {
            require(_feeBps[i] <= MAX_FEE_BPS, "TransferFeesModule: fee too high");
            customFeeBps[_addresses[i]] = _feeBps[i];
            emit CustomFeeSet(_addresses[i], _feeBps[i]);
        }
    }
    
    /**
     * @dev Sets address exemption status
     * @param _address Address to set exemption for
     * @param _exempt Whether the address is exempt
     */
    function setExemptAddress(address _address, bool _exempt) external onlyOwner {
        exemptAddresses[_address] = _exempt;
        emit AddressExempted(_address, _exempt);
    }
    
    /**
     * @dev Batch set exempt addresses
     * @param _addresses Array of addresses
     * @param _exempt Array of exemption statuses
     */
    function batchSetExemptAddresses(
        address[] calldata _addresses,
        bool[] calldata _exempt
    ) external onlyOwner {
        require(_addresses.length == _exempt.length, "TransferFeesModule: length mismatch");
        
        for (uint256 i = 0; i < _addresses.length; i++) {
            exemptAddresses[_addresses[i]] = _exempt[i];
            emit AddressExempted(_addresses[i], _exempt[i]);
        }
    }
    
    /**
     * @dev Enables or disables the module
     * @param _enabled Whether the module should be enabled
     */
    function setModuleEnabled(bool _enabled) external onlyOwner {
        moduleEnabled = _enabled;
        emit ModuleEnabledSet(_enabled);
    }
    
    // ============ Module Functions ============
    
    /**
     * @dev Called on token transfer - tracks fee collection
     */
    function moduleTransferAction(
        address _from,
        address _to,
        uint256 _value
    ) external override onlyBoundCompliance {
        // Calculate and track fee
        if (moduleEnabled && !exemptAddresses[_from] && !exemptAddresses[_to]) {
            uint256 fee = calculateFee(_from, _value);
            if (fee > 0) {
                totalFeesCollected += fee;
                emit FeeCollected(_from, _to, _value, fee);
            }
        }
    }
    
    /**
     * @dev Called on token mint - no fee on minting
     */
    function moduleMintAction(
        address _to,
        uint256 _value
    ) external override onlyBoundCompliance {
        // No fee on minting
    }
    
    /**
     * @dev Called on token burn - no fee on burning
     */
    function moduleBurnAction(
        address _from,
        uint256 _value
    ) external override onlyBoundCompliance {
        // No fee on burning
    }
    
    /**
     * @dev Checks if transfer is compliant - always returns true
     * Fee module doesn't block transfers, just tracks fees
     * @return bool Always true
     */
    function moduleCheck(
        address _from,
        address _to,
        uint256 _value,
        address _compliance
    ) external view override returns (bool) {
        // Fee module doesn't block transfers
        return true;
    }
    
    /**
     * @dev Returns the module name
     */
    function name() external pure override returns (string memory) {
        return "TransferFeesModule";
    }
    
    // ============ Internal Functions ============
    
    /**
     * @dev Authorizes upgrade (only owner)
     */
    function _authorizeUpgrade(address newImplementation) internal override onlyOwner {}
    
    // ============ View Functions ============
    
    /**
     * @dev Calculates the fee for a transfer
     * @param _from Sender address
     * @param _amount Transfer amount
     * @return uint256 Fee amount
     */
    function calculateFee(address _from, uint256 _amount) public view returns (uint256) {
        if (!moduleEnabled) {
            return 0;
        }
        
        if (exemptAddresses[_from]) {
            return 0;
        }
        
        uint256 feeBps = _getFeeBps(_from);
        if (feeBps == 0) {
            return 0;
        }
        
        return (_amount * feeBps) / BPS_DENOMINATOR;
    }
    
    /**
     * @dev Gets the fee rate for an address
     * @param _address Address to check
     * @return uint256 Fee in basis points
     */
    function _getFeeBps(address _address) internal view returns (uint256) {
        uint256 custom = customFeeBps[_address];
        if (custom > 0) {
            return custom;
        }
        return defaultFeeBps;
    }
    
    /**
     * @dev Gets the effective fee rate for an address
     * @param _address Address to check
     * @return uint256 Effective fee in basis points
     */
    function getEffectiveFeeBps(address _address) external view returns (uint256) {
        if (exemptAddresses[_address]) {
            return 0;
        }
        return _getFeeBps(_address);
    }
    
    /**
     * @dev Calculates amount after fee deduction
     * @param _from Sender address
     * @param _amount Gross amount
     * @return uint256 Net amount after fee
     */
    function getAmountAfterFee(address _from, uint256 _amount) external view returns (uint256) {
        uint256 fee = calculateFee(_from, _amount);
        return _amount - fee;
    }
}

contracts/core/DividendDistributor.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/PausableUpgradeable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "./RWASecurityToken.sol";
import "../interfaces/IDividendDistributor.sol";

/**
 * @title DividendDistributor
 * @dev Distributes dividends to security token holders based on snapshots
 */
contract DividendDistributor is
    Initializable,
    UUPSUpgradeable,
    AccessControlUpgradeable,
    ReentrancyGuardUpgradeable,
    PausableUpgradeable,
    IDividendDistributor
{
    using SafeERC20 for IERC20;

    // ============ Constants ============

    bytes32 public constant DISTRIBUTOR_ROLE = keccak256("DISTRIBUTOR_ROLE");
    bytes32 public constant UPGRADER_ROLE = keccak256("UPGRADER_ROLE");

    uint256 public constant DIVIDEND_FEE_BPS = 100; // 1% fee
    uint256 public constant BPS_DENOMINATOR = 10000;
    uint256 public constant DIVIDEND_EXPIRATION = 365 days;

    // ============ Structs ============

    struct DividendDistribution {
        uint256 projectId;
        address token;              // Payment token (address(0) for ETH)
        uint256 totalAmount;        // Total amount for distribution
        uint256 claimedAmount;      // Amount already claimed
        uint256 snapshotId;         // Snapshot ID for balance calculation
        uint256 totalSupplyAtSnapshot; // Total supply at snapshot
        uint256 createdAt;
        uint256 expiresAt;
        bool isActive;
        address securityToken;      // The security token contract
    }

    // ============ State Variables ============

    // Distribution ID => Distribution data
    mapping(uint256 => DividendDistribution) private _distributions;

    // Distribution ID => holder address => claimed
    mapping(uint256 => mapping(address => bool)) private _claimed;

    // Project ID => distribution IDs
    mapping(uint256 => uint256[]) private _projectDistributions;

    // Distribution counter
    uint256 private _distributionCounter;

    // Fee recipient
    address public feeRecipient;

    // Project ID => Security Token address
    mapping(uint256 => address) public projectSecurityTokens;

    // ============ Events ============

    event DividendDistributed(
        uint256 indexed distributionId,
        uint256 indexed projectId,
        address indexed token,
        uint256 totalAmount,
        uint256 snapshotId
    );

    event DividendClaimed(
        uint256 indexed distributionId,
        address indexed holder,
        uint256 amount
    );

    event DividendExpired(uint256 indexed distributionId, uint256 unclaimedAmount);

    event ExpiredDividendsReclaimed(
        uint256 indexed distributionId,
        uint256 amount,
        address recipient
    );

    event SecurityTokenRegistered(uint256 indexed projectId, address indexed securityToken);
    event FeeRecipientUpdated(address oldRecipient, address newRecipient);

    // ============ Initializer ============

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    /**
     * @dev Initializes the dividend distributor
     * @param _admin Admin address
     * @param _feeRecipient Fee recipient address
     */
    function initialize(
        address _admin,
        address _feeRecipient
    ) external initializer {
        require(_admin != address(0), "DividendDistributor: zero admin");
        require(_feeRecipient != address(0), "DividendDistributor: zero fee recipient");

        __UUPSUpgradeable_init();
        __AccessControl_init();
        __ReentrancyGuard_init();
        __Pausable_init();

        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(DISTRIBUTOR_ROLE, _admin);
        _grantRole(UPGRADER_ROLE, _admin);

        feeRecipient = _feeRecipient;
    }

    // ============ Admin Functions ============

    /**
     * @dev Registers a security token for a project
     * @param _projectId Project ID
     * @param _securityToken Security token address
     */
    function registerSecurityToken(
        uint256 _projectId,
        address _securityToken
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_securityToken != address(0), "DividendDistributor: zero address");
        projectSecurityTokens[_projectId] = _securityToken;
        emit SecurityTokenRegistered(_projectId, _securityToken);
    }

    /**
     * @dev Updates fee recipient
     * @param _newRecipient New fee recipient address
     */
    function setFeeRecipient(address _newRecipient) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_newRecipient != address(0), "DividendDistributor: zero address");
        address oldRecipient = feeRecipient;
        feeRecipient = _newRecipient;
        emit FeeRecipientUpdated(oldRecipient, _newRecipient);
    }

    /**
     * @dev Pauses the contract
     */
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    /**
     * @dev Unpauses the contract
     */
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    // ============ Distribution Functions ============

    /**
     * @dev Creates a new dividend distribution
     * @param _projectId Project ID
     * @param _token Payment token (address(0) for ETH)
     * @param _amount Amount to distribute (for ERC20, must be approved first)
     * @return distributionId The ID of the created distribution
     */
    function createDistribution(
        uint256 _projectId,
        address _token,
        uint256 _amount
    ) external payable override nonReentrant whenNotPaused returns (uint256 distributionId) {
        require(_amount > 0, "DividendDistributor: zero amount");

        address securityToken = projectSecurityTokens[_projectId];
        require(securityToken != address(0), "DividendDistributor: project not registered");

        RWASecurityToken tokenContract = RWASecurityToken(securityToken);

        // Calculate fee
        uint256 fee = (_amount * DIVIDEND_FEE_BPS) / BPS_DENOMINATOR;
        uint256 distributionAmount = _amount - fee;

        // Handle payment
        if (_token == address(0)) {
            // ETH payment
            require(msg.value == _amount, "DividendDistributor: incorrect ETH amount");

            // Transfer fee
            if (fee > 0) {
                (bool feeSuccess, ) = feeRecipient.call{value: fee}("");
                require(feeSuccess, "DividendDistributor: fee transfer failed");
            }
        } else {
            // ERC20 payment
            require(msg.value == 0, "DividendDistributor: ETH not accepted for token distribution");

            IERC20(_token).safeTransferFrom(msg.sender, address(this), _amount);

            // Transfer fee
            if (fee > 0) {
                IERC20(_token).safeTransfer(feeRecipient, fee);
            }
        }

        // Create snapshot
        uint256 snapshotId = tokenContract.snapshot();
        uint256 totalSupply = tokenContract.totalSupplyAt(snapshotId);
        require(totalSupply > 0, "DividendDistributor: no token supply");

        // Create distribution
        distributionId = ++_distributionCounter;

        _distributions[distributionId] = DividendDistribution({
            projectId: _projectId,
            token: _token,
            totalAmount: distributionAmount,
            claimedAmount: 0,
            snapshotId: snapshotId,
            totalSupplyAtSnapshot: totalSupply,
            createdAt: block.timestamp,
            expiresAt: block.timestamp + DIVIDEND_EXPIRATION,
            isActive: true,
            securityToken: securityToken
        });

        _projectDistributions[_projectId].push(distributionId);

        emit DividendDistributed(
            distributionId,
            _projectId,
            _token,
            distributionAmount,
            snapshotId
        );

        return distributionId;
    }

    /**
     * @dev Claims dividend for a distribution
     * @param _distributionId Distribution ID
     */
    function claimDividend(uint256 _distributionId) external override nonReentrant whenNotPaused {
        _claimDividend(_distributionId, msg.sender);
    }

    /**
     * @dev Claims dividends for multiple distributions
     * @param _distributionIds Array of distribution IDs
     */
    function batchClaimDividends(uint256[] calldata _distributionIds) external override nonReentrant whenNotPaused {
        for (uint256 i = 0; i < _distributionIds.length; i++) {
            _claimDividend(_distributionIds[i], msg.sender);
        }
    }

    /**
     * @dev Internal claim function
     */
    function _claimDividend(uint256 _distributionId, address _holder) internal {
        DividendDistribution storage dist = _distributions[_distributionId];

        require(dist.isActive, "DividendDistributor: distribution not active");
        require(block.timestamp < dist.expiresAt, "DividendDistributor: distribution expired");
        require(!_claimed[_distributionId][_holder], "DividendDistributor: already claimed");

        uint256 claimableAmount = getClaimableAmount(_distributionId, _holder);
        require(claimableAmount > 0, "DividendDistributor: nothing to claim");

        _claimed[_distributionId][_holder] = true;
        dist.claimedAmount += claimableAmount;

        // Transfer dividend
        if (dist.token == address(0)) {
            (bool success, ) = _holder.call{value: claimableAmount}("");
            require(success, "DividendDistributor: ETH transfer failed");
        } else {
            IERC20(dist.token).safeTransfer(_holder, claimableAmount);
        }

        emit DividendClaimed(_distributionId, _holder, claimableAmount);
    }

    /**
     * @dev Reclaims expired dividends
     * @param _distributionId Distribution ID
     */
    function reclaimExpiredDividends(uint256 _distributionId) external override nonReentrant {
        DividendDistribution storage dist = _distributions[_distributionId];

        require(dist.isActive, "DividendDistributor: distribution not active");
        require(block.timestamp >= dist.expiresAt, "DividendDistributor: not expired");

        uint256 unclaimedAmount = dist.totalAmount - dist.claimedAmount;
        require(unclaimedAmount > 0, "DividendDistributor: nothing to reclaim");

        dist.isActive = false;

        // Transfer unclaimed amount to fee recipient
        if (dist.token == address(0)) {
            (bool success, ) = feeRecipient.call{value: unclaimedAmount}("");
            require(success, "DividendDistributor: ETH transfer failed");
        } else {
            IERC20(dist.token).safeTransfer(feeRecipient, unclaimedAmount);
        }

        emit DividendExpired(_distributionId, unclaimedAmount);
        emit ExpiredDividendsReclaimed(_distributionId, unclaimedAmount, feeRecipient);
    }

    // ============ View Functions ============

    /**
     * @dev Gets claimable amount for a holder
     * @param _distributionId Distribution ID
     * @param _holder Holder address
     * @return uint256 Claimable amount
     */
    function getClaimableAmount(
        uint256 _distributionId,
        address _holder
    ) public view override returns (uint256) {
        DividendDistribution storage dist = _distributions[_distributionId];

        if (!dist.isActive || _claimed[_distributionId][_holder]) {
            return 0;
        }

        if (block.timestamp >= dist.expiresAt) {
            return 0;
        }

        RWASecurityToken tokenContract = RWASecurityToken(dist.securityToken);
        uint256 holderBalance = tokenContract.balanceOfAt(_holder, dist.snapshotId);

        if (holderBalance == 0 || dist.totalSupplyAtSnapshot == 0) {
            return 0;
        }

        return (dist.totalAmount * holderBalance) / dist.totalSupplyAtSnapshot;
    }

    /**
     * @dev Checks if holder has claimed
     * @param _distributionId Distribution ID
     * @param _holder Holder address
     * @return bool True if claimed
     */
    function hasClaimed(
        uint256 _distributionId,
        address _holder
    ) external view override returns (bool) {
        return _claimed[_distributionId][_holder];
    }

    /**
     * @dev Gets distribution details
     * @param _distributionId Distribution ID
     * @return Distribution struct
     */
    function getDistribution(
        uint256 _distributionId
    ) external view override returns (Distribution memory) {
        DividendDistribution storage dist = _distributions[_distributionId];
        return Distribution({
            projectId: dist.projectId,
            token: dist.token,
            totalAmount: dist.totalAmount,
            claimedAmount: dist.claimedAmount,
            snapshotId: dist.snapshotId,
            createdAt: dist.createdAt,
            expiresAt: dist.expiresAt,
            isActive: dist.isActive
        });
    }

    /**
     * @dev Gets all distribution IDs for a project
     * @param _projectId Project ID
     * @return uint256[] Array of distribution IDs
     */
    function getDistributionsByProject(
        uint256 _projectId
    ) external view override returns (uint256[] memory) {
        return _projectDistributions[_projectId];
    }

    /**
     * @dev Gets total distribution count
     * @return uint256 Total distributions
     */
    function totalDistributions() external view returns (uint256) {
        return _distributionCounter;
    }

    // ============ Internal Functions ============

    /**
     * @dev Authorizes upgrade
     */
    function _authorizeUpgrade(
        address newImplementation
    ) internal override onlyRole(UPGRADER_ROLE) {}
}

contracts/core/ProjectBadgeManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";

contract ProjectBadgeManager is AccessControlUpgradeable, UUPSUpgradeable {
    bytes32 public constant BADGE_ADMIN_ROLE = keccak256("BADGE_ADMIN_ROLE");
    
    enum BadgeType { Wildcard, Verified, Sponsored }
    enum BadgeColor { Bronze, Silver, Gold }
    
    struct Badge {
        BadgeType badgeType;
        BadgeColor color;
        uint256 grantedAt;
    }
    
    mapping(uint256 => Badge) public projectBadges;
    
    event BadgeUpdated(uint256 indexed projectId, BadgeType badgeType, BadgeColor color);
    
    function initialize(address admin) public initializer {
        __AccessControl_init();
        __UUPSUpgradeable_init();
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(BADGE_ADMIN_ROLE, admin);
    }
    
    function setBadge(
        uint256 projectId,
        BadgeType badgeType,
        BadgeColor color
    ) external onlyRole(BADGE_ADMIN_ROLE) {
        projectBadges[projectId] = Badge({
            badgeType: badgeType,
            color: color,
            grantedAt: block.timestamp
        });
        emit BadgeUpdated(projectId, badgeType, color);
    }
    
    function getBadge(uint256 projectId) external view returns (Badge memory) {
        Badge memory badge = projectBadges[projectId];
        if (badge.grantedAt == 0) {
            return Badge(BadgeType.Wildcard, BadgeColor.Bronze, 0);
        }
        return badge;
    }
    
    function _authorizeUpgrade(address) internal override onlyRole(DEFAULT_ADMIN_ROLE) {}
}

contracts/core/RWAEscrowVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/PausableUpgradeable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/IERC20Metadata.sol";

import "../interfaces/IRWAProjectNFT.sol";
import "./RWASecurityToken.sol";

/**
 * @title Chainlink Price Feed Interface
 */
interface AggregatorV3Interface {
    function decimals() external view returns (uint8);
    function description() external view returns (string memory);
    function version() external view returns (uint256);
    function latestRoundData() external view returns (
        uint80 roundId,
        int256 answer,
        uint256 startedAt,
        uint256 updatedAt,
        uint80 answeredInRound
    );
}

/**
 * @title RWAEscrowVault
 * @notice Upgradeable escrow vault for RWA project investments with milestone-based fund release
 * @dev Uses Chainlink Price Feeds for accurate real-time pricing - NO HARDCODED PRICES
 * 
 * Key Features:
 * - Native token (POL/ETH) and ERC20 (USDC/USDT) investment support
 * - Chainlink oracle integration for accurate USD conversion
 * - Proper decimal handling: USD limits stored with 6 decimals
 * - Milestone-based fund release with dispute resolution
 * - ERC-3643 compliant token minting to verified investors
 * - Platform fee collection (2.5% default)
 * - Emergency refund mechanism
 * - Stale price protection (configurable max age)
 */
contract RWAEscrowVault is 
    Initializable, 
    UUPSUpgradeable, 
    AccessControlUpgradeable, 
    ReentrancyGuardUpgradeable, 
    PausableUpgradeable 
{
    using SafeERC20 for IERC20;

    // ============================================
    // CONSTANTS
    // ============================================
    
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
    bytes32 public constant UPGRADER_ROLE = keccak256("UPGRADER_ROLE");
    bytes32 public constant DISPUTE_RESOLVER_ROLE = keccak256("DISPUTE_RESOLVER_ROLE");
    
    uint256 public constant PLATFORM_FEE_BPS = 250; // 2.5%
    uint256 public constant BPS_DENOMINATOR = 10000;
    uint256 public constant RELEASE_GRACE_PERIOD = 3 days;
    uint256 public constant DISPUTE_GRACE_PERIOD = 7 days;
    uint256 public constant MAX_MILESTONES = 20;
    
    // Decimal constants
    uint256 public constant USD_DECIMALS = 6;      // USDC/USDT use 6 decimals
    uint256 public constant NATIVE_DECIMALS = 18;  // POL/ETH use 18 decimals
    
    // ============================================
    // ENUMS
    // ============================================
    
    enum MilestoneStatus { 
        Pending, 
        Submitted, 
        Approved, 
        Rejected, 
        Disputed, 
        Released 
    }

    // ============================================
    // STRUCTS
    // ============================================
    
    struct Investment {
        uint256 amount;           // Amount in payment token decimals
        uint256 amountUSD;        // Amount in USD (6 decimals)
        uint256 tokensMinted;     // Security tokens minted (18 decimals)
        bool refunded;
    }
    
    struct MilestoneData {
        string description;
        uint256 percentage;       // Basis points (100 = 1%)
        MilestoneStatus status;
        string proofURI;
        uint256 submittedAt;
        uint256 approvedAt;
        uint256 releasedAmount;
        string rejectionReason;
        address disputeRaiser;
        string disputeReason;
    }
    
    struct ProjectFundingData {
        uint256 projectId;
        uint256 fundingGoal;      // In USD (6 decimals)
        uint256 totalRaised;      // In USD (6 decimals)
        uint256 totalReleased;    // In payment token decimals
        uint256 deadline;
        address paymentToken;     // address(0) = native token
        bool fundingComplete;
        bool refundsEnabled;
        uint256 currentMilestone;
        uint256 minInvestment;    // In USD (6 decimals)
        uint256 maxInvestment;    // In USD (6 decimals)
        address projectOwner;
        address securityToken;
    }
    
    struct PriceFeedConfig {
        AggregatorV3Interface feed;
        uint8 decimals;
        bool isStablecoin;        // If true, assume 1:1 USD peg (skip oracle)
    }

    // ============================================
    // STATE VARIABLES
    // ============================================
    
    /// @notice Project NFT contract reference
    IRWAProjectNFT public projectNFT;
    
    /// @notice Platform fee recipient
    address public feeRecipient;
    
    /// @notice Native token (POL/ETH) price feed
    AggregatorV3Interface public nativePriceFeed;
    
    /// @notice Maximum age for price data (stale price protection)
    uint256 public maxPriceAge;
    
    /// @notice Project ID => Funding data
    mapping(uint256 => ProjectFundingData) private _projectFunding;
    
    /// @notice Project ID => Milestone index => Milestone data
    mapping(uint256 => mapping(uint256 => MilestoneData)) private _milestones;
    
    /// @notice Project ID => Milestone count
    mapping(uint256 => uint256) private _milestoneCount;
    
    /// @notice Project ID => Investor => Investment data
    mapping(uint256 => mapping(address => Investment)) private _investments;
    
    /// @notice Project ID => List of investors
    mapping(uint256 => address[]) private _projectInvestors;
    
    /// @notice Project ID => Investor => Has invested
    mapping(uint256 => mapping(address => bool)) private _hasInvested;
    
    /// @notice Token address => Price feed config
    mapping(address => PriceFeedConfig) public tokenPriceFeeds;
    
    /// @notice Accepted ERC20 payment tokens
    mapping(address => bool) public acceptedTokens;
    
    /// @notice Gap for future upgrades
    uint256[40] private __gap;

    // ============================================
    // EVENTS
    // ============================================
    
    event ProjectInitialized(
        uint256 indexed projectId, 
        uint256 fundingGoal, 
        uint256 deadline, 
        address paymentToken,
        address securityToken
    );
    
    event InvestmentReceived(
        uint256 indexed projectId, 
        address indexed investor, 
        uint256 amount,
        uint256 amountUSD,
        uint256 tokensMinted,
        address paymentToken,
        uint256 priceUsed
    );
    
    event FundingCompleted(uint256 indexed projectId, uint256 totalRaised);
    
    event MilestoneAdded(
        uint256 indexed projectId, 
        uint256 indexed milestoneIndex, 
        string description, 
        uint256 percentage
    );
    
    event MilestoneSubmitted(
        uint256 indexed projectId, 
        uint256 indexed milestoneIndex, 
        string proofURI
    );
    
    event MilestoneApproved(uint256 indexed projectId, uint256 indexed milestoneIndex);
    event MilestoneRejected(uint256 indexed projectId, uint256 indexed milestoneIndex, string reason);
    event MilestoneFundsReleased(uint256 indexed projectId, uint256 indexed milestoneIndex, uint256 amount);
    event DisputeRaised(uint256 indexed projectId, uint256 indexed milestoneIndex, address indexed raiser, string reason);
    event DisputeResolved(uint256 indexed projectId, uint256 indexed milestoneIndex, bool approved);
    event RefundsEnabled(uint256 indexed projectId);
    event RefundClaimed(uint256 indexed projectId, address indexed investor, uint256 amount);
    event PlatformFeeCollected(uint256 indexed projectId, uint256 amount);
    event FeeRecipientUpdated(address indexed newRecipient);
    event NativePriceFeedUpdated(address indexed feed);
    event TokenPriceFeedUpdated(address indexed token, address indexed feed, bool isStablecoin);
    event MaxPriceAgeUpdated(uint256 newMaxAge);

    // ============================================
    // ERRORS
    // ============================================
    
    error ProjectNotInitialized();
    error ProjectAlreadyInitialized();
    error InvalidProjectId();
    error InvalidAmount();
    error BelowMinimumInvestment();
    error ExceedsMaximumInvestment();
    error FundingDeadlinePassed();
    error FundingNotComplete();
    error FundingAlreadyComplete();
    error RefundsNotEnabled();
    error AlreadyRefunded();
    error NoInvestmentToRefund();
    error InvalidMilestone();
    error MilestoneNotPending();
    error MilestoneNotSubmitted();
    error MilestoneNotApproved();
    error MaxMilestonesReached();
    error InvalidPercentage();
    error NotProjectOwner();
    error DisputeInProgress();
    error NoDisputeToResolve();
    error TokenNotAccepted();
    error PriceFeedNotSet();
    error StalePrice();
    error InvalidPrice();
    error TransferFailed();

    // ============================================
    // MODIFIERS
    // ============================================
    
    modifier onlyProjectOwner(uint256 _projectId) {
        if (_projectFunding[_projectId].projectOwner != msg.sender) {
            revert NotProjectOwner();
        }
        _;
    }
    
    modifier projectExists(uint256 _projectId) {
        if (_projectFunding[_projectId].projectId == 0) {
            revert ProjectNotInitialized();
        }
        _;
    }

    // ============================================
    // INITIALIZER
    // ============================================
    
    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }
    
    /**
     * @notice Initialize the escrow vault
     * @param _projectNFT Address of the RWA Project NFT contract
     * @param _feeRecipient Address to receive platform fees
     * @param _nativePriceFeed Chainlink price feed for native token (POL/USD or ETH/USD)
     * @param _maxPriceAge Maximum age for price data in seconds (e.g., 3600 = 1 hour)
     */
    function initialize(
        address _projectNFT,
        address _feeRecipient,
        address _nativePriceFeed,
        uint256 _maxPriceAge
    ) external initializer {
        require(_projectNFT != address(0), "Invalid project NFT");
        require(_feeRecipient != address(0), "Invalid fee recipient");
        require(_nativePriceFeed != address(0), "Invalid price feed");
        require(_maxPriceAge > 0, "Invalid max price age");
        
        __AccessControl_init();
        __ReentrancyGuard_init();
        __Pausable_init();
        __UUPSUpgradeable_init();
        
        projectNFT = IRWAProjectNFT(_projectNFT);
        feeRecipient = _feeRecipient;
        nativePriceFeed = AggregatorV3Interface(_nativePriceFeed);
        maxPriceAge = _maxPriceAge;
        
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(OPERATOR_ROLE, msg.sender);
        _grantRole(UPGRADER_ROLE, msg.sender);
        _grantRole(DISPUTE_RESOLVER_ROLE, msg.sender);
    }

    // ============================================
    // PRICE FEED FUNCTIONS
    // ============================================
    
    /**
     * @notice Get the current native token price in USD
     * @return price Price with 8 decimals (Chainlink standard)
     * @return decimals Number of decimals in the price
     */
    function getNativeTokenPrice() public view returns (uint256 price, uint8 decimals) {
        if (address(nativePriceFeed) == address(0)) revert PriceFeedNotSet();
        
        (
            uint80 roundId,
            int256 answer,
            ,
            uint256 updatedAt,
            uint80 answeredInRound
        ) = nativePriceFeed.latestRoundData();
        
        // Validate price data
        if (answer <= 0) revert InvalidPrice();
        if (updatedAt == 0) revert InvalidPrice();
        if (block.timestamp - updatedAt > maxPriceAge) revert StalePrice();
        if (answeredInRound < roundId) revert StalePrice();
        
        return (uint256(answer), nativePriceFeed.decimals());
    }
    
    /**
     * @notice Get the current price for an ERC20 token in USD
     * @param _token Token address
     * @return price Price with feed decimals
     * @return decimals Number of decimals in the price
     */
    function getTokenPrice(address _token) public view returns (uint256 price, uint8 decimals) {
        PriceFeedConfig storage config = tokenPriceFeeds[_token];
        
        // If it's a stablecoin, return 1:1 USD peg
        if (config.isStablecoin) {
            return (1e8, 8); // $1.00 with 8 decimals
        }
        
        if (address(config.feed) == address(0)) revert PriceFeedNotSet();
        
        (
            uint80 roundId,
            int256 answer,
            ,
            uint256 updatedAt,
            uint80 answeredInRound
        ) = config.feed.latestRoundData();
        
        // Validate price data
        if (answer <= 0) revert InvalidPrice();
        if (updatedAt == 0) revert InvalidPrice();
        if (block.timestamp - updatedAt > maxPriceAge) revert StalePrice();
        if (answeredInRound < roundId) revert StalePrice();
        
        return (uint256(answer), config.decimals);
    }
    
    /**
     * @notice Convert native token amount to USD
     * @param _amountNative Amount in native token (18 decimals)
     * @return amountUSD Amount in USD (6 decimals)
     */
    function convertNativeToUSD(uint256 _amountNative) public view returns (uint256 amountUSD) {
        (uint256 price, uint8 priceDecimals) = getNativeTokenPrice();
        
        // Formula: (nativeAmount * price) / 10^(18 + priceDecimals - 6)
        // Example: (1e18 * 0.35e8) / 10^(18+8-6) = 0.35e6 = 350000 ($0.35)
        uint256 divisor = 10 ** (NATIVE_DECIMALS + priceDecimals - USD_DECIMALS);
        amountUSD = (_amountNative * price) / divisor;
    }
    
    /**
     * @notice Convert USD to native token amount
     * @param _amountUSD Amount in USD (6 decimals)
     * @return amountNative Amount in native token (18 decimals)
     */
    function convertUSDToNative(uint256 _amountUSD) public view returns (uint256 amountNative) {
        (uint256 price, uint8 priceDecimals) = getNativeTokenPrice();
        
        // Formula: (usdAmount * 10^(18 + priceDecimals - 6)) / price
        uint256 multiplier = 10 ** (NATIVE_DECIMALS + priceDecimals - USD_DECIMALS);
        amountNative = (_amountUSD * multiplier) / price;
    }
    
    /**
     * @notice Convert ERC20 token amount to USD
     * @param _token Token address
     * @param _amount Amount in token decimals
     * @return amountUSD Amount in USD (6 decimals)
     */
    function convertTokenToUSD(address _token, uint256 _amount) public view returns (uint256 amountUSD) {
        uint8 tokenDecimals = IERC20Metadata(_token).decimals();
        (uint256 price, uint8 priceDecimals) = getTokenPrice(_token);
        
        // Formula: (amount * price) / 10^(tokenDecimals + priceDecimals - 6)
        uint256 divisor = 10 ** (tokenDecimals + priceDecimals - USD_DECIMALS);
        amountUSD = (_amount * price) / divisor;
    }

    // ============================================
    // PROJECT INITIALIZATION
    // ============================================
    
    /**
     * @notice Initialize funding for a new project
     * @dev Called by Factory when creating a new project
     * @param _projectId Project ID from NFT contract
     * @param _fundingGoal Funding goal in USD (6 decimals) e.g., 1000000000 = $1000
     * @param _minInvestment Minimum investment in USD (6 decimals) e.g., 100000000 = $100
     * @param _maxInvestment Maximum investment in USD (6 decimals)
     * @param _deadline Unix timestamp deadline
     * @param _paymentToken Payment token address (address(0) for native)
     * @param _projectOwner Project owner address
     * @param _securityToken Security token address for minting
     */
    function initializeProject(
        uint256 _projectId,
        uint256 _fundingGoal,
        uint256 _minInvestment,
        uint256 _maxInvestment,
        uint256 _deadline,
        address _paymentToken,
        address _projectOwner,
        address _securityToken
    ) external onlyRole(OPERATOR_ROLE) {
        if (_projectId == 0) revert InvalidProjectId();
        if (_projectFunding[_projectId].projectId != 0) revert ProjectAlreadyInitialized();
        if (_fundingGoal == 0) revert InvalidAmount();
        if (_deadline <= block.timestamp) revert FundingDeadlinePassed();
        
        _projectFunding[_projectId] = ProjectFundingData({
            projectId: _projectId,
            fundingGoal: _fundingGoal,
            totalRaised: 0,
            totalReleased: 0,
            deadline: _deadline,
            paymentToken: _paymentToken,
            fundingComplete: false,
            refundsEnabled: false,
            currentMilestone: 0,
            minInvestment: _minInvestment,
            maxInvestment: _maxInvestment,
            projectOwner: _projectOwner,
            securityToken: _securityToken
        });
        
        emit ProjectInitialized(
            _projectId, 
            _fundingGoal, 
            _deadline, 
            _paymentToken,
            _securityToken
        );
    }

    // ============================================
    // INVESTMENT FUNCTIONS
    // ============================================
    
    /**
     * @notice Invest with native token (POL/ETH)
     * @dev Uses Chainlink price feed for accurate USD conversion
     * @param _projectId Project to invest in
     */
    function invest(uint256 _projectId) 
        external 
        payable 
        nonReentrant 
        whenNotPaused 
        projectExists(_projectId) 
    {
        if (msg.value == 0) revert InvalidAmount();
        
        ProjectFundingData storage funding = _projectFunding[_projectId];
        
        if (funding.fundingComplete) revert FundingAlreadyComplete();
        if (block.timestamp > funding.deadline) revert FundingDeadlinePassed();
        
        // Get real-time price and convert to USD
        uint256 amountUSD = convertNativeToUSD(msg.value);
        (uint256 priceUsed, ) = getNativeTokenPrice();
        
        _processInvestment(_projectId, msg.sender, msg.value, amountUSD, address(0), priceUsed);
    }
    
    /**
     * @notice Invest with ERC20 token (USDC/USDT or other accepted tokens)
     * @dev For stablecoins, assumes 1:1 USD peg. For others, uses Chainlink price feed
     * @param _projectId Project to invest in
     * @param _token ERC20 token address
     * @param _amount Amount in token decimals
     */
    function investWithToken(
        uint256 _projectId, 
        address _token, 
        uint256 _amount
    ) 
        external 
        nonReentrant 
        whenNotPaused 
        projectExists(_projectId) 
    {
        if (_amount == 0) revert InvalidAmount();
        if (!acceptedTokens[_token]) revert TokenNotAccepted();
        
        ProjectFundingData storage funding = _projectFunding[_projectId];
        
        if (funding.fundingComplete) revert FundingAlreadyComplete();
        if (block.timestamp > funding.deadline) revert FundingDeadlinePassed();
        
        // Convert to USD using price feed or 1:1 for stablecoins
        uint256 amountUSD = convertTokenToUSD(_token, _amount);
        (uint256 priceUsed, ) = getTokenPrice(_token);
        
        // Transfer tokens from investor
        IERC20(_token).safeTransferFrom(msg.sender, address(this), _amount);
        
        _processInvestment(_projectId, msg.sender, _amount, amountUSD, _token, priceUsed);
    }
    
    /**
     * @dev Internal function to process investment
     */
    function _processInvestment(
        uint256 _projectId,
        address _investor,
        uint256 _amount,
        uint256 _amountUSD,
        address _paymentToken,
        uint256 _priceUsed
    ) internal {
        ProjectFundingData storage funding = _projectFunding[_projectId];
        Investment storage investment = _investments[_projectId][_investor];
        
        // Calculate total investment for this investor (in USD)
        uint256 totalInvestmentUSD = investment.amountUSD + _amountUSD;
        
        // Validate against limits (both in USD with 6 decimals)
        if (_amountUSD < funding.minInvestment && investment.amountUSD == 0) {
            revert BelowMinimumInvestment();
        }
        if (totalInvestmentUSD > funding.maxInvestment) {
            revert ExceedsMaximumInvestment();
        }
        
        // Track investor if first investment
        if (!_hasInvested[_projectId][_investor]) {
            _projectInvestors[_projectId].push(_investor);
            _hasInvested[_projectId][_investor] = true;
        }
        
        // Calculate tokens to mint (1 token per 1 USD, with 18 decimals for security token)
        // amountUSD is 6 decimals, security token is 18 decimals
        // So multiply by 10^12 to get 18 decimals
        uint256 tokensToMint = _amountUSD * (10 ** 12);
        
        // Update investment tracking
        investment.amount += _amount;
        investment.amountUSD += _amountUSD;
        investment.tokensMinted += tokensToMint;
        
        // Update project totals
        funding.totalRaised += _amountUSD;
        
        // Mint security tokens to investor
        if (funding.securityToken != address(0)) {
            RWASecurityToken(funding.securityToken).mint(_investor, tokensToMint);
        }
        
        // Update project NFT
        projectNFT.updateTotalRaised(_projectId, funding.totalRaised);
        
        emit InvestmentReceived(
            _projectId, 
            _investor, 
            _amount,
            _amountUSD, 
            tokensToMint,
            _paymentToken,
            _priceUsed
        );
        
        // Check if funding goal reached
        if (funding.totalRaised >= funding.fundingGoal) {
            _completeFunding(_projectId);
        }
    }
    
    /**
     * @dev Mark funding as complete
     */
    function _completeFunding(uint256 _projectId) internal {
        ProjectFundingData storage funding = _projectFunding[_projectId];
        
        funding.fundingComplete = true;
        projectNFT.updateProjectStatus(_projectId, IRWAProjectNFT.ProjectStatus.Funded);
        
        emit FundingCompleted(_projectId, funding.totalRaised);
    }

    // ============================================
    // MILESTONE MANAGEMENT
    // ============================================
    
    /**
     * @notice Add a milestone to a project
     */
    function addMilestone(
        uint256 _projectId,
        string calldata _description,
        uint256 _percentage
    ) 
        external 
        onlyProjectOwner(_projectId) 
        projectExists(_projectId) 
    {
        uint256 milestoneIndex = _milestoneCount[_projectId];
        if (milestoneIndex >= MAX_MILESTONES) revert MaxMilestonesReached();
        if (_percentage == 0 || _percentage > BPS_DENOMINATOR) revert InvalidPercentage();
        
        _milestones[_projectId][milestoneIndex] = MilestoneData({
            description: _description,
            percentage: _percentage,
            status: MilestoneStatus.Pending,
            proofURI: "",
            submittedAt: 0,
            approvedAt: 0,
            releasedAmount: 0,
            rejectionReason: "",
            disputeRaiser: address(0),
            disputeReason: ""
        });
        
        _milestoneCount[_projectId]++;
        
        emit MilestoneAdded(_projectId, milestoneIndex, _description, _percentage);
    }
    
    /**
     * @notice Submit milestone proof for review
     */
    function submitMilestone(
        uint256 _projectId,
        uint256 _milestoneIndex,
        string calldata _proofURI
    ) 
        external 
        onlyProjectOwner(_projectId) 
        projectExists(_projectId) 
    {
        MilestoneData storage milestone = _milestones[_projectId][_milestoneIndex];
        
        if (milestone.status != MilestoneStatus.Pending && 
            milestone.status != MilestoneStatus.Rejected) {
            revert MilestoneNotPending();
        }
        
        milestone.status = MilestoneStatus.Submitted;
        milestone.proofURI = _proofURI;
        milestone.submittedAt = block.timestamp;
        
        emit MilestoneSubmitted(_projectId, _milestoneIndex, _proofURI);
    }
    
    /**
     * @notice Approve a submitted milestone
     */
    function approveMilestone(
        uint256 _projectId,
        uint256 _milestoneIndex
    ) 
        external 
        onlyRole(OPERATOR_ROLE) 
        projectExists(_projectId) 
    {
        MilestoneData storage milestone = _milestones[_projectId][_milestoneIndex];
        
        if (milestone.status != MilestoneStatus.Submitted) {
            revert MilestoneNotSubmitted();
        }
        
        milestone.status = MilestoneStatus.Approved;
        milestone.approvedAt = block.timestamp;
        
        emit MilestoneApproved(_projectId, _milestoneIndex);
    }
    
    /**
     * @notice Reject a submitted milestone
     */
    function rejectMilestone(
        uint256 _projectId,
        uint256 _milestoneIndex,
        string calldata _reason
    ) 
        external 
        onlyRole(OPERATOR_ROLE) 
        projectExists(_projectId) 
    {
        MilestoneData storage milestone = _milestones[_projectId][_milestoneIndex];
        
        if (milestone.status != MilestoneStatus.Submitted) {
            revert MilestoneNotSubmitted();
        }
        
        milestone.status = MilestoneStatus.Rejected;
        milestone.rejectionReason = _reason;
        
        emit MilestoneRejected(_projectId, _milestoneIndex, _reason);
    }
    
    /**
     * @notice Release funds for an approved milestone
     */
    function releaseMilestoneFunds(
        uint256 _projectId,
        uint256 _milestoneIndex
    ) 
        external 
        nonReentrant 
        projectExists(_projectId) 
    {
        ProjectFundingData storage funding = _projectFunding[_projectId];
        MilestoneData storage milestone = _milestones[_projectId][_milestoneIndex];
        
        if (milestone.status != MilestoneStatus.Approved) {
            revert MilestoneNotApproved();
        }
        
        // Calculate release amount based on payment token
        uint256 releaseAmount;
        if (funding.paymentToken == address(0)) {
            releaseAmount = (address(this).balance * milestone.percentage) / BPS_DENOMINATOR;
        } else {
            uint256 tokenBalance = IERC20(funding.paymentToken).balanceOf(address(this));
            releaseAmount = (tokenBalance * milestone.percentage) / BPS_DENOMINATOR;
        }
        
        // Calculate platform fee
        uint256 platformFee = (releaseAmount * PLATFORM_FEE_BPS) / BPS_DENOMINATOR;
        uint256 ownerAmount = releaseAmount - platformFee;
        
        // Update milestone
        milestone.status = MilestoneStatus.Released;
        milestone.releasedAmount = releaseAmount;
        funding.totalReleased += releaseAmount;
        funding.currentMilestone = _milestoneIndex + 1;
        
        // Transfer funds
        if (funding.paymentToken == address(0)) {
            (bool successOwner, ) = funding.projectOwner.call{value: ownerAmount}("");
            if (!successOwner) revert TransferFailed();
            
            (bool successFee, ) = feeRecipient.call{value: platformFee}("");
            if (!successFee) revert TransferFailed();
        } else {
            IERC20(funding.paymentToken).safeTransfer(funding.projectOwner, ownerAmount);
            IERC20(funding.paymentToken).safeTransfer(feeRecipient, platformFee);
        }
        
        emit MilestoneFundsReleased(_projectId, _milestoneIndex, releaseAmount);
        emit PlatformFeeCollected(_projectId, platformFee);
        
        _checkProjectCompletion(_projectId);
    }
    
    function _checkProjectCompletion(uint256 _projectId) internal {
        uint256 count = _milestoneCount[_projectId];
        bool allComplete = true;
        
        for (uint256 i = 0; i < count; i++) {
            if (_milestones[_projectId][i].status != MilestoneStatus.Released) {
                allComplete = false;
                break;
            }
        }
        
        if (allComplete && count > 0) {
            projectNFT.completeProject(_projectId);
        }
    }

    // ============================================
    // DISPUTE RESOLUTION
    // ============================================
    
    function raiseDispute(
        uint256 _projectId,
        uint256 _milestoneIndex,
        string calldata _reason
    ) 
        external 
        projectExists(_projectId) 
    {
        require(_hasInvested[_projectId][msg.sender], "Not an investor");
        
        MilestoneData storage milestone = _milestones[_projectId][_milestoneIndex];
        
        if (milestone.status == MilestoneStatus.Disputed) {
            revert DisputeInProgress();
        }
        
        milestone.status = MilestoneStatus.Disputed;
        milestone.disputeRaiser = msg.sender;
        milestone.disputeReason = _reason;
        
        emit DisputeRaised(_projectId, _milestoneIndex, msg.sender, _reason);
    }
    
    function resolveDispute(
        uint256 _projectId,
        uint256 _milestoneIndex,
        bool _approved
    ) 
        external 
        onlyRole(DISPUTE_RESOLVER_ROLE) 
        projectExists(_projectId) 
    {
        MilestoneData storage milestone = _milestones[_projectId][_milestoneIndex];
        
        if (milestone.status != MilestoneStatus.Disputed) {
            revert NoDisputeToResolve();
        }
        
        if (_approved) {
            milestone.status = MilestoneStatus.Approved;
            milestone.approvedAt = block.timestamp;
        } else {
            milestone.status = MilestoneStatus.Rejected;
            milestone.rejectionReason = "Rejected after dispute resolution";
        }
        
        emit DisputeResolved(_projectId, _milestoneIndex, _approved);
    }

    // ============================================
    // REFUNDS
    // ============================================
    
    function enableRefunds(uint256 _projectId) 
        external 
        onlyRole(OPERATOR_ROLE) 
        projectExists(_projectId) 
    {
        ProjectFundingData storage funding = _projectFunding[_projectId];
        
        funding.refundsEnabled = true;
        projectNFT.updateProjectStatus(_projectId, IRWAProjectNFT.ProjectStatus.Failed);
        
        emit RefundsEnabled(_projectId);
    }
    
    function claimRefund(uint256 _projectId) 
        external 
        nonReentrant 
        projectExists(_projectId) 
    {
        ProjectFundingData storage funding = _projectFunding[_projectId];
        Investment storage investment = _investments[_projectId][msg.sender];
        
        if (!funding.refundsEnabled) revert RefundsNotEnabled();
        if (investment.refunded) revert AlreadyRefunded();
        if (investment.amount == 0) revert NoInvestmentToRefund();
        
        investment.refunded = true;
        uint256 refundAmount = investment.amount;
        
        // Calculate proportional refund
        if (funding.paymentToken == address(0)) {
            uint256 balance = address(this).balance;
            uint256 proportionalAmount = (balance * investment.amountUSD) / funding.totalRaised;
            refundAmount = proportionalAmount < refundAmount ? proportionalAmount : refundAmount;
            
            (bool success, ) = msg.sender.call{value: refundAmount}("");
            if (!success) revert TransferFailed();
        } else {
            uint256 balance = IERC20(funding.paymentToken).balanceOf(address(this));
            uint256 proportionalAmount = (balance * investment.amountUSD) / funding.totalRaised;
            refundAmount = proportionalAmount < refundAmount ? proportionalAmount : refundAmount;
            
            IERC20(funding.paymentToken).safeTransfer(msg.sender, refundAmount);
        }
        
        emit RefundClaimed(_projectId, msg.sender, refundAmount);
    }

    // ============================================
    // ADMIN FUNCTIONS
    // ============================================
    
    /**
     * @notice Set the native token price feed (Chainlink)
     * @param _priceFeed Chainlink price feed address (e.g., POL/USD)
     */
    function setNativePriceFeed(address _priceFeed) external onlyRole(OPERATOR_ROLE) {
        require(_priceFeed != address(0), "Invalid price feed");
        nativePriceFeed = AggregatorV3Interface(_priceFeed);
        emit NativePriceFeedUpdated(_priceFeed);
    }
    
    /**
     * @notice Set price feed for an ERC20 token
     * @param _token Token address
     * @param _priceFeed Chainlink price feed address (address(0) if stablecoin)
     * @param _isStablecoin If true, assumes 1:1 USD peg without oracle
     */
    function setTokenPriceFeed(
        address _token, 
        address _priceFeed, 
        bool _isStablecoin
    ) external onlyRole(OPERATOR_ROLE) {
        if (_isStablecoin) {
            tokenPriceFeeds[_token] = PriceFeedConfig({
                feed: AggregatorV3Interface(address(0)),
                decimals: 8,
                isStablecoin: true
            });
        } else {
            require(_priceFeed != address(0), "Invalid price feed");
            AggregatorV3Interface feed = AggregatorV3Interface(_priceFeed);
            tokenPriceFeeds[_token] = PriceFeedConfig({
                feed: feed,
                decimals: feed.decimals(),
                isStablecoin: false
            });
        }
        emit TokenPriceFeedUpdated(_token, _priceFeed, _isStablecoin);
    }
    
    /**
     * @notice Set whether an ERC20 token is accepted for investment
     */
    function setAcceptedToken(address _token, bool _accepted) external onlyRole(OPERATOR_ROLE) {
        acceptedTokens[_token] = _accepted;
    }
    
    /**
     * @notice Update maximum price age for stale price protection
     */
    function setMaxPriceAge(uint256 _maxAge) external onlyRole(OPERATOR_ROLE) {
        require(_maxAge > 0, "Invalid max age");
        maxPriceAge = _maxAge;
        emit MaxPriceAgeUpdated(_maxAge);
    }
    
    function setFeeRecipient(address _newRecipient) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_newRecipient != address(0), "Invalid address");
        feeRecipient = _newRecipient;
        emit FeeRecipientUpdated(_newRecipient);
    }
    
    function pause() external onlyRole(OPERATOR_ROLE) {
        _pause();
    }
    
    function unpause() external onlyRole(OPERATOR_ROLE) {
        _unpause();
    }

    // ============================================
    // VIEW FUNCTIONS
    // ============================================
    
    function getProjectFunding(uint256 _projectId) 
        external 
        view 
        returns (ProjectFundingData memory) 
    {
        return _projectFunding[_projectId];
    }
    
    function getMilestones(uint256 _projectId) 
        external 
        view 
        returns (MilestoneData[] memory) 
    {
        uint256 count = _milestoneCount[_projectId];
        MilestoneData[] memory milestones = new MilestoneData[](count);
        
        for (uint256 i = 0; i < count; i++) {
            milestones[i] = _milestones[_projectId][i];
        }
        
        return milestones;
    }
    
    function getMilestone(uint256 _projectId, uint256 _milestoneIndex) 
        external 
        view 
        returns (MilestoneData memory) 
    {
        return _milestones[_projectId][_milestoneIndex];
    }
    
    function getMilestoneCount(uint256 _projectId) external view returns (uint256) {
        return _milestoneCount[_projectId];
    }
    
    function getInvestorAmount(uint256 _projectId, address _investor) 
        external 
        view 
        returns (uint256) 
    {
        return _investments[_projectId][_investor].amountUSD;
    }
    
    function getInvestorDetails(uint256 _projectId, address _investor) 
        external 
        view 
        returns (
            uint256 amount,
            uint256 amountUSD,
            uint256 tokensMinted,
            bool refunded
        ) 
    {
        Investment storage inv = _investments[_projectId][_investor];
        return (inv.amount, inv.amountUSD, inv.tokensMinted, inv.refunded);
    }
    
    function getProjectInvestors(uint256 _projectId) 
        external 
        view 
        returns (address[] memory) 
    {
        return _projectInvestors[_projectId];
    }
    
    function getInvestorCount(uint256 _projectId) external view returns (uint256) {
        return _projectInvestors[_projectId].length;
    }
    
    function getReleasableAmount(uint256 _projectId) external view returns (uint256) {
        ProjectFundingData storage funding = _projectFunding[_projectId];
        uint256 milestoneIndex = funding.currentMilestone;
        
        if (milestoneIndex >= _milestoneCount[_projectId]) {
            return 0;
        }
        
        MilestoneData storage milestone = _milestones[_projectId][milestoneIndex];
        
        if (milestone.status != MilestoneStatus.Approved) {
            return 0;
        }
        
        if (funding.paymentToken == address(0)) {
            return (address(this).balance * milestone.percentage) / BPS_DENOMINATOR;
        } else {
            uint256 balance = IERC20(funding.paymentToken).balanceOf(address(this));
            return (balance * milestone.percentage) / BPS_DENOMINATOR;
        }
    }

    // ============================================
    // UPGRADE AUTHORIZATION
    // ============================================
    
    function _authorizeUpgrade(address newImplementation) 
        internal 
        override 
        onlyRole(UPGRADER_ROLE) 
    {}

    receive() external payable {}
}

contracts/core/RWALaunchpadFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/PausableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";
import "../interfaces/IRWALaunchpadFactory.sol";
import "../interfaces/IRWAProjectNFT.sol";
import "../libraries/DeploymentLib.sol";

interface IRWASecurityExchange {
    function createPairForToken(address _securityToken) external returns (bytes32);
}

/**
 * @title RWALaunchpadFactory
 * @dev Factory contract for deploying RWA project contracts (optimized)
 */
contract RWALaunchpadFactory is
    Initializable,
    UUPSUpgradeable,
    AccessControlUpgradeable,
    PausableUpgradeable,
    ReentrancyGuardUpgradeable,
    IRWALaunchpadFactory
{
    // ============ Custom Errors ============
    error ZeroAddress();
    error FeeTooHigh();
    error InvalidInput();
    error DeadlineTooSoon();
    error InsufficientFee();
    error TransferFailed();

    // ============ Constants ============
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
    bytes32 public constant UPGRADER_ROLE = keccak256("UPGRADER_ROLE");
    uint256 public constant MAX_FEE_BPS = 1000;
    uint256 public constant BPS_DENOMINATOR = 10000;

    // ============ Structs ============
    struct DeployedContracts {
        uint256 projectId;
        address securityToken;
        address escrowVault;
        address compliance;
        uint256 deployedAt;
        address owner;
    }

    struct Implementations {
        address securityToken;
        address escrowVault;
        address compliance;
    }

    // ============ State Variables ============
    mapping(uint256 => DeployedContracts) private _deployedContracts;
    mapping(address => uint256[]) private _ownerDeployments;
    
    uint256 private _platformFeeBps;
    uint256 private _creationFeeBps;
    address private _feeRecipient;
    
    IRWAProjectNFT private _projectNFT;
    address private _identityRegistry;
    Implementations private _implementations;
    address private _defaultPaymentToken;
    address private _dividendDistributor;
    
    // NEW: Exchange integration
    address private _securityExchange;
    bool private _autoCreateTradingPairs;

    // ============ Events ============
    event ProjectContractsDeployed(
        uint256 indexed projectId,
        address indexed owner,
        address securityToken,
        address escrowVault,
        address compliance
    );
    event PlatformFeeUpdated(uint256 oldFee, uint256 newFee);
    event CreationFeeUpdated(uint256 oldFee, uint256 newFee);
    event FeeRecipientUpdated(address oldRecipient, address newRecipient);
    event ImplementationsUpdated(address securityToken, address escrowVault, address compliance);
    event SecurityExchangeUpdated(address indexed oldExchange, address indexed newExchange);
    event TradingPairCreated(uint256 indexed projectId, address indexed securityToken, bytes32 pairId);
    event TradingPairCreationFailed(uint256 indexed projectId, address indexed securityToken, string reason);

    // ============ Initializer ============
    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(
        address admin_,
        address feeRecipient_,
        address projectNFT_,
        address identityRegistry_,
        uint256 platformFee_,
        uint256 creationFee_
    ) external initializer {
        if (admin_ == address(0) || feeRecipient_ == address(0) || 
            projectNFT_ == address(0) || identityRegistry_ == address(0)) revert ZeroAddress();
        if (platformFee_ > MAX_FEE_BPS || creationFee_ > MAX_FEE_BPS) revert FeeTooHigh();

        __UUPSUpgradeable_init();
        __AccessControl_init();
        __Pausable_init();
        __ReentrancyGuard_init();

        _grantRole(DEFAULT_ADMIN_ROLE, admin_);
        _grantRole(OPERATOR_ROLE, admin_);
        _grantRole(UPGRADER_ROLE, admin_);

        _feeRecipient = feeRecipient_;
        _projectNFT = IRWAProjectNFT(projectNFT_);
        _identityRegistry = identityRegistry_;
        _platformFeeBps = platformFee_;
        _creationFeeBps = creationFee_;
        _autoCreateTradingPairs = true; // Enable by default
    }

    // ============ Implementation Management ============
    function setImplementations(
        address securityToken_,
        address escrowVault_,
        address compliance_
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        if (securityToken_ == address(0) || escrowVault_ == address(0) || 
            compliance_ == address(0)) revert ZeroAddress();
        
        _implementations = Implementations({
            securityToken: securityToken_,
            escrowVault: escrowVault_,
            compliance: compliance_
        });
        
        emit ImplementationsUpdated(securityToken_, escrowVault_, compliance_);
    }

    // ============ Deployment Functions ============
    function deployProjectContracts(
        string calldata name_,
        string calldata symbol_,
        string calldata metadataURI_,
        uint256 fundingGoal_,
        uint256 minInvestment_,
        uint256 maxInvestment_,
        uint256 deadline_,
        uint256 maxSupply_,
        address paymentToken_
    ) external payable override nonReentrant whenNotPaused returns (uint256 projectId) {
        _validateInputs(name_, symbol_, metadataURI_, fundingGoal_, minInvestment_, maxInvestment_, deadline_);
        _collectCreationFee(fundingGoal_, paymentToken_);

        // Create project NFT
        projectId = _createProject(metadataURI_, fundingGoal_, minInvestment_, maxInvestment_, deadline_);

        // Deploy contracts
        address compliance = _deployCompliance();
        address securityToken = _deploySecurityToken(name_, symbol_, projectId, compliance, maxSupply_);
        address escrowVault = _deployEscrowVault(projectId, fundingGoal_, minInvestment_, maxInvestment_, deadline_, paymentToken_, securityToken);

        // Link contracts
        _projectNFT.linkSecurityToken(projectId, securityToken);
        _projectNFT.linkEscrowVault(projectId, escrowVault);

        // Store deployment
        _deployedContracts[projectId] = DeployedContracts({
            projectId: projectId,
            securityToken: securityToken,
            escrowVault: escrowVault,
            compliance: compliance,
            deployedAt: block.timestamp,
            owner: msg.sender
        });
        _ownerDeployments[msg.sender].push(projectId);

        emit ProjectContractsDeployed(projectId, msg.sender, securityToken, escrowVault, compliance);

        // Auto-create trading pair on exchange
        _createTradingPairIfEnabled(projectId, securityToken);
    }

    function _validateInputs(
        string calldata name_,
        string calldata symbol_,
        string calldata metadataURI_,
        uint256 fundingGoal_,
        uint256 minInvestment_,
        uint256 maxInvestment_,
        uint256 deadline_
    ) internal view {
        if (bytes(name_).length == 0 || bytes(symbol_).length == 0 || 
            bytes(metadataURI_).length == 0) revert InvalidInput();
        if (fundingGoal_ < 10000 || minInvestment_ < 100 || 
            maxInvestment_ < minInvestment_) revert InvalidInput();
        if (deadline_ < block.timestamp + 7 days) revert DeadlineTooSoon();
    }

    function _collectCreationFee(uint256 fundingGoal_, address paymentToken_) internal {
        uint256 creationFee = (fundingGoal_ * _creationFeeBps) / BPS_DENOMINATOR;
        if (creationFee > 0) {
            if (paymentToken_ == address(0)) {
                if (msg.value < creationFee) revert InsufficientFee();
                (bool success, ) = _feeRecipient.call{value: creationFee}("");
                if (!success) revert TransferFailed();
                if (msg.value > creationFee) {
                    (bool refundSuccess, ) = msg.sender.call{value: msg.value - creationFee}("");
                    if (!refundSuccess) revert TransferFailed();
                }
            }
        }
    }

    function _createProject(
        string calldata metadataURI_,
        uint256 fundingGoal_,
        uint256 minInvestment_,
        uint256 maxInvestment_,
        uint256 deadline_
    ) internal returns (uint256) {
        // Call createProjectFor on ProjectNFT
        (bool success, bytes memory data) = address(_projectNFT).call(
            abi.encodeWithSignature(
                "createProjectFor(address,string,uint256,uint256,uint256,uint256)",
                msg.sender, metadataURI_, fundingGoal_, minInvestment_, maxInvestment_, deadline_
            )
        );
        if (!success) revert TransferFailed();
        return abi.decode(data, (uint256));
    }

    function _deployCompliance() internal returns (address) {
        bytes memory initData = abi.encodeWithSignature("initialize(address)", msg.sender);
        return DeploymentLib.deployProxy(_implementations.compliance, initData);
    }

    function _deploySecurityToken(
        string calldata name_,
        string calldata symbol_,
        uint256 projectId_,
        address compliance_,
        uint256 maxSupply_
    ) internal returns (address) {
        bytes memory initData = abi.encodeWithSignature(
            "initialize(string,string,uint8,uint256,address,address,address,uint256,address,address)",
            name_, symbol_, 18, projectId_, address(_projectNFT), _identityRegistry, 
            compliance_, maxSupply_, msg.sender, address(0)
        );
        address token = DeploymentLib.deployProxy(_implementations.securityToken, initData);        
        return token;
    }

    function _deployEscrowVault(
        uint256 projectId_,
        uint256 fundingGoal_,
        uint256 minInvestment_,
        uint256 maxInvestment_,
        uint256 deadline_,
        address paymentToken_,
        address securityToken_
    ) internal returns (address) {
        bytes memory initData = abi.encodeWithSignature(
            "initialize(address,address,address)",
            address(this), _feeRecipient, address(_projectNFT)
        );
        address vault = DeploymentLib.deployProxy(_implementations.escrowVault, initData);
        
        // Initialize project in escrow
        (bool success, ) = vault.call(
            abi.encodeWithSignature(
                "initializeProject(uint256,uint256,uint256,uint256,uint256,address,address,address)",
                projectId_, fundingGoal_, minInvestment_, maxInvestment_, deadline_,
                paymentToken_, msg.sender, securityToken_
            )
        );
        if (!success) revert TransferFailed();
        
        return vault;
    }

    /**
     * @dev Create trading pair on exchange if enabled
     */
    function _createTradingPairIfEnabled(uint256 projectId_, address securityToken_) internal {
        if (_securityExchange != address(0) && _autoCreateTradingPairs) {
            try IRWASecurityExchange(_securityExchange).createPairForToken(securityToken_) returns (bytes32 pairId) {
                emit TradingPairCreated(projectId_, securityToken_, pairId);
            } catch Error(string memory reason) {
                emit TradingPairCreationFailed(projectId_, securityToken_, reason);
            } catch {
                emit TradingPairCreationFailed(projectId_, securityToken_, "Unknown error");
            }
        }
    }

    // ============ Exchange Integration ============
    
    /**
     * @notice Set the security exchange address for auto-creating trading pairs
     * @param exchange_ Address of the RWASecurityExchange contract
     */
    function setSecurityExchange(address exchange_) external onlyRole(DEFAULT_ADMIN_ROLE) {
        address oldExchange = _securityExchange;
        _securityExchange = exchange_;
        emit SecurityExchangeUpdated(oldExchange, exchange_);
    }

    /**
     * @notice Enable or disable auto-creation of trading pairs
     * @param enabled_ Whether to auto-create trading pairs
     */
    function setAutoCreateTradingPairs(bool enabled_) external onlyRole(DEFAULT_ADMIN_ROLE) {
        _autoCreateTradingPairs = enabled_;
    }

    /**
     * @notice Manually create trading pair for an existing project
     * @param projectId_ The project ID
     */
    function createTradingPairForProject(uint256 projectId_) external onlyRole(OPERATOR_ROLE) {
        if (_securityExchange == address(0)) revert ZeroAddress();
        
        DeployedContracts storage d = _deployedContracts[projectId_];
        if (d.securityToken == address(0)) revert InvalidInput();
        
        bytes32 pairId = IRWASecurityExchange(_securityExchange).createPairForToken(d.securityToken);
        emit TradingPairCreated(projectId_, d.securityToken, pairId);
    }

    // ============ Admin Functions ============
    function setPlatformFee(uint256 newFee_) external onlyRole(DEFAULT_ADMIN_ROLE) {
        if (newFee_ > MAX_FEE_BPS) revert FeeTooHigh();
        uint256 oldFee = _platformFeeBps;
        _platformFeeBps = newFee_;
        emit PlatformFeeUpdated(oldFee, newFee_);
    }

    function setCreationFee(uint256 newFee_) external onlyRole(DEFAULT_ADMIN_ROLE) {
        if (newFee_ > MAX_FEE_BPS) revert FeeTooHigh();
        uint256 oldFee = _creationFeeBps;
        _creationFeeBps = newFee_;
        emit CreationFeeUpdated(oldFee, newFee_);
    }

    function setFeeRecipient(address newRecipient_) external onlyRole(DEFAULT_ADMIN_ROLE) {
        if (newRecipient_ == address(0)) revert ZeroAddress();
        address oldRecipient = _feeRecipient;
        _feeRecipient = newRecipient_;
        emit FeeRecipientUpdated(oldRecipient, newRecipient_);
    }

    function setIdentityRegistry(address newRegistry_) external onlyRole(DEFAULT_ADMIN_ROLE) {
        if (newRegistry_ == address(0)) revert ZeroAddress();
        _identityRegistry = newRegistry_;
    }

    function setDividendDistributor(address distributor_) external onlyRole(DEFAULT_ADMIN_ROLE) {
        _dividendDistributor = distributor_;
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    // ============ View Functions ============
    function getProjectDeployment(uint256 projectId_) external view override returns (ProjectDeployment memory) {
        DeployedContracts storage d = _deployedContracts[projectId_];
        return ProjectDeployment({
            projectId: d.projectId,
            securityToken: d.securityToken,
            escrowVault: d.escrowVault,
            compliance: d.compliance,
            deployedAt: d.deployedAt
        });
    }

    function getDeploymentsByOwner(address owner_) external view override returns (uint256[] memory) {
        return _ownerDeployments[owner_];
    }

    function platformFeeBps() external view override returns (uint256) {
        return _platformFeeBps;
    }

    function creationFeeBps() external view returns (uint256) {
        return _creationFeeBps;
    }

    function feeRecipient() external view override returns (address) {
        return _feeRecipient;
    }

    function projectNFT() external view override returns (address) {
        return address(_projectNFT);
    }

    function identityRegistry() external view override returns (address) {
        return _identityRegistry;
    }

    function implementations() external view returns (Implementations memory) {
        return _implementations;
    }

    function dividendDistributor() external view returns (address) {
        return _dividendDistributor;
    }

    function securityExchange() external view returns (address) {
        return _securityExchange;
    }

    function autoCreateTradingPairs() external view returns (bool) {
        return _autoCreateTradingPairs;
    }

    // ============ Internal Functions ============
    function _authorizeUpgrade(address) internal override onlyRole(UPGRADER_ROLE) {}

    receive() external payable {}
}

contracts/core/RWAProjectNFT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/token/ERC721/ERC721Upgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC721/extensions/ERC721URIStorageUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC721/extensions/ERC721EnumerableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/PausableUpgradeable.sol";
import "../interfaces/IRWAProjectNFT.sol";

/**
 * @title RWAProjectNFT
 * @dev NFT contract representing RWA projects - one NFT per project, soulbound until completion
 */
contract RWAProjectNFT is
    Initializable,
    ERC721Upgradeable,
    ERC721URIStorageUpgradeable,
    ERC721EnumerableUpgradeable,
    AccessControlUpgradeable,
    PausableUpgradeable,
    UUPSUpgradeable,
    IRWAProjectNFT
{
    // ============ Constants ============

    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
    bytes32 public constant UPGRADER_ROLE = keccak256("UPGRADER_ROLE");
    bytes32 public constant FACTORY_ROLE = keccak256("FACTORY_ROLE");

    uint256 public constant MIN_FUNDING_GOAL = 10000;
    uint256 public constant MIN_INVESTMENT = 100;
    uint256 public constant MIN_DEADLINE_DAYS = 7;

    // ============ Structs ============

    struct ProjectData {
        uint256 id;
        address owner;
        string metadataURI;
        uint256 fundingGoal;
        uint256 totalRaised;
        uint256 minInvestment;
        uint256 maxInvestment;
        uint256 deadline;
        ProjectStatus status;
        address securityToken;
        address escrowVault;
        uint256 createdAt;
        uint256 completedAt;
        bool transferable;
    }

    // ============ State Variables ============

    // Project ID counter
    uint256 private _projectCounter;

    // Project ID => Project data
    mapping(uint256 => ProjectData) private _projects;

    // Owner => Project IDs
    mapping(address => uint256[]) private _ownerProjects;

    // ============ Events ============

    event ProjectCreated(
        uint256 indexed projectId,
        address indexed owner,
        string metadataURI,
        uint256 fundingGoal,
        uint256 deadline
    );

    event ProjectStatusUpdated(
        uint256 indexed projectId,
        ProjectStatus oldStatus,
        ProjectStatus newStatus
    );

    event ProjectCompleted(uint256 indexed projectId, uint256 timestamp);

    event ProjectCancelled(uint256 indexed projectId, string reason);

    event MetadataUpdated(uint256 indexed projectId, string newMetadataURI);

    event SecurityTokenLinked(uint256 indexed projectId, address indexed securityToken);

    event EscrowVaultLinked(uint256 indexed projectId, address indexed escrowVault);

    event TotalRaisedUpdated(uint256 indexed projectId, uint256 totalRaised);

    // ============ Initializer ============

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    /**
     * @dev Initializes the contract
     * @param _admin Admin address
     * @param _name NFT name
     * @param _symbol NFT symbol
     */
    function initialize(
        address _admin,
        string memory _name,
        string memory _symbol
    ) external initializer {
        require(_admin != address(0), "RWAProjectNFT: zero admin");

        __ERC721_init(_name, _symbol);
        __ERC721URIStorage_init();
        __ERC721Enumerable_init();
        __AccessControl_init();
        __Pausable_init();
        __UUPSUpgradeable_init();

        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(OPERATOR_ROLE, _admin);
        _grantRole(UPGRADER_ROLE, _admin);
    }

    // ============ Project Creation ============

    /**
     * @dev Creates a new project NFT
     * @param _metadataURI Project metadata URI
     * @param _fundingGoal Funding goal amount
     * @param _minInvestment Minimum investment amount
     * @param _maxInvestment Maximum investment amount
     * @param _deadline Funding deadline timestamp
     * @return projectId The ID of the created project
     */
    function createProject(
        string calldata _metadataURI,
        uint256 _fundingGoal,
        uint256 _minInvestment,
        uint256 _maxInvestment,
        uint256 _deadline
    ) external override whenNotPaused returns (uint256 projectId) {
        require(bytes(_metadataURI).length > 0, "RWAProjectNFT: empty metadata");
        require(_fundingGoal >= MIN_FUNDING_GOAL, "RWAProjectNFT: goal too low");
        require(_minInvestment >= MIN_INVESTMENT, "RWAProjectNFT: min investment too low");
        require(_maxInvestment >= _minInvestment, "RWAProjectNFT: invalid max investment");
        require(
            _deadline >= block.timestamp + (MIN_DEADLINE_DAYS * 1 days),
            "RWAProjectNFT: deadline too soon"
        );

        projectId = ++_projectCounter;

        _projects[projectId] = ProjectData({
            id: projectId,
            owner: msg.sender,
            metadataURI: _metadataURI,
            fundingGoal: _fundingGoal,
            totalRaised: 0,
            minInvestment: _minInvestment,
            maxInvestment: _maxInvestment,
            deadline: _deadline,
            status: ProjectStatus.Pending,
            securityToken: address(0),
            escrowVault: address(0),
            createdAt: block.timestamp,
            completedAt: 0,
            transferable: false
        });

        _ownerProjects[msg.sender].push(projectId);

        // Mint NFT to project creator
        _safeMint(msg.sender, projectId);
        _setTokenURI(projectId, _metadataURI);

        emit ProjectCreated(projectId, msg.sender, _metadataURI, _fundingGoal, _deadline);

        return projectId;
    }

    /**
     * @dev Creates a project (called by factory)
     */
    function createProjectFor(
        address _owner,
        string calldata _metadataURI,
        uint256 _fundingGoal,
        uint256 _minInvestment,
        uint256 _maxInvestment,
        uint256 _deadline
    ) external onlyRole(FACTORY_ROLE) returns (uint256 projectId) {
        require(_owner != address(0), "RWAProjectNFT: zero owner");
        require(bytes(_metadataURI).length > 0, "RWAProjectNFT: empty metadata");
        require(_fundingGoal >= MIN_FUNDING_GOAL, "RWAProjectNFT: goal too low");
        require(_minInvestment >= MIN_INVESTMENT, "RWAProjectNFT: min investment too low");
        require(_maxInvestment >= _minInvestment, "RWAProjectNFT: invalid max investment");
        require(
            _deadline >= block.timestamp + (MIN_DEADLINE_DAYS * 1 days),
            "RWAProjectNFT: deadline too soon"
        );

        projectId = ++_projectCounter;

        _projects[projectId] = ProjectData({
            id: projectId,
            owner: _owner,
            metadataURI: _metadataURI,
            fundingGoal: _fundingGoal,
            totalRaised: 0,
            minInvestment: _minInvestment,
            maxInvestment: _maxInvestment,
            deadline: _deadline,
            status: ProjectStatus.Pending,
            securityToken: address(0),
            escrowVault: address(0),
            createdAt: block.timestamp,
            completedAt: 0,
            transferable: false
        });

        _ownerProjects[_owner].push(projectId);

        // Mint NFT to project owner
        _safeMint(_owner, projectId);
        _setTokenURI(projectId, _metadataURI);

        emit ProjectCreated(projectId, _owner, _metadataURI, _fundingGoal, _deadline);

        return projectId;
    }

    // ============ Project Management ============

    /**
     * @dev Updates project status
     * @param _projectId Project ID
     * @param _newStatus New status
     */
    function updateProjectStatus(
        uint256 _projectId,
        ProjectStatus _newStatus
    ) external override {
        require(_projectId > 0 && _projectId <= _projectCounter, "RWAProjectNFT: invalid project");
        
        ProjectData storage project = _projects[_projectId];
        
        require(
            msg.sender == project.owner ||
            msg.sender == project.escrowVault ||
            hasRole(OPERATOR_ROLE, msg.sender),
            "RWAProjectNFT: not authorized"
        );

        ProjectStatus oldStatus = project.status;
        project.status = _newStatus;

        emit ProjectStatusUpdated(_projectId, oldStatus, _newStatus);
    }

    /**
     * @dev Marks project as completed
     * @param _projectId Project ID
     */
    function completeProject(uint256 _projectId) external override {
        require(_projectId > 0 && _projectId <= _projectCounter, "RWAProjectNFT: invalid project");
        
        ProjectData storage project = _projects[_projectId];
        
        require(
            msg.sender == project.escrowVault ||
            hasRole(OPERATOR_ROLE, msg.sender),
            "RWAProjectNFT: not authorized"
        );
        require(
            project.status != ProjectStatus.Completed &&
            project.status != ProjectStatus.Cancelled,
            "RWAProjectNFT: invalid status"
        );

        ProjectStatus oldStatus = project.status;
        project.status = ProjectStatus.Completed;
        project.completedAt = block.timestamp;
        project.transferable = true; // NFT becomes transferable after completion

        emit ProjectStatusUpdated(_projectId, oldStatus, ProjectStatus.Completed);
        emit ProjectCompleted(_projectId, block.timestamp);
    }

    /**
     * @dev Cancels a project
     * @param _projectId Project ID
     * @param _reason Cancellation reason
     */
    function cancelProject(
        uint256 _projectId,
        string calldata _reason
    ) external override {
        require(_projectId > 0 && _projectId <= _projectCounter, "RWAProjectNFT: invalid project");
        
        ProjectData storage project = _projects[_projectId];
        
        require(
            msg.sender == project.owner ||
            hasRole(OPERATOR_ROLE, msg.sender),
            "RWAProjectNFT: not authorized"
        );
        require(
            project.status != ProjectStatus.Completed &&
            project.status != ProjectStatus.Cancelled,
            "RWAProjectNFT: invalid status"
        );

        ProjectStatus oldStatus = project.status;
        project.status = ProjectStatus.Cancelled;

        emit ProjectStatusUpdated(_projectId, oldStatus, ProjectStatus.Cancelled);
        emit ProjectCancelled(_projectId, _reason);
    }

    /**
     * @dev Links security token to project
     * @param _projectId Project ID
     * @param _securityToken Security token address
     */
    function linkSecurityToken(
        uint256 _projectId,
        address _securityToken
    ) external override {
        require(_projectId > 0 && _projectId <= _projectCounter, "RWAProjectNFT: invalid project");
        require(_securityToken != address(0), "RWAProjectNFT: zero address");
        
        ProjectData storage project = _projects[_projectId];
        
        require(
            hasRole(OPERATOR_ROLE, msg.sender) || hasRole(FACTORY_ROLE, msg.sender),
            "RWAProjectNFT: not authorized"
        );
        require(project.securityToken == address(0), "RWAProjectNFT: already linked");

        project.securityToken = _securityToken;

        emit SecurityTokenLinked(_projectId, _securityToken);
    }

    /**
     * @dev Links escrow vault to project
     * @param _projectId Project ID
     * @param _escrowVault Escrow vault address
     */
    function linkEscrowVault(
        uint256 _projectId,
        address _escrowVault
    ) external override {
        require(_projectId > 0 && _projectId <= _projectCounter, "RWAProjectNFT: invalid project");
        require(_escrowVault != address(0), "RWAProjectNFT: zero address");
        
        ProjectData storage project = _projects[_projectId];
        
        require(
            hasRole(OPERATOR_ROLE, msg.sender) || hasRole(FACTORY_ROLE, msg.sender),
            "RWAProjectNFT: not authorized"
        );
        require(project.escrowVault == address(0), "RWAProjectNFT: already linked");

        project.escrowVault = _escrowVault;

        emit EscrowVaultLinked(_projectId, _escrowVault);
    }

    /**
     * @dev Updates project metadata
     * @param _projectId Project ID
     * @param _newMetadataURI New metadata URI
     */
    function updateMetadata(
        uint256 _projectId,
        string calldata _newMetadataURI
    ) external override {
        require(_projectId > 0 && _projectId <= _projectCounter, "RWAProjectNFT: invalid project");
        require(bytes(_newMetadataURI).length > 0, "RWAProjectNFT: empty metadata");
        
        ProjectData storage project = _projects[_projectId];
        
        require(
            msg.sender == project.owner ||
            hasRole(OPERATOR_ROLE, msg.sender),
            "RWAProjectNFT: not authorized"
        );

        project.metadataURI = _newMetadataURI;
        _setTokenURI(_projectId, _newMetadataURI);

        emit MetadataUpdated(_projectId, _newMetadataURI);
    }

    /**
     * @dev Updates total raised amount for a project
     * @param _projectId Project ID
     * @param _totalRaised New total raised amount
     */
    function updateTotalRaised(
        uint256 _projectId,
        uint256 _totalRaised
    ) external override {
        require(_projectId > 0 && _projectId <= _projectCounter, "RWAProjectNFT: invalid project");
        
        ProjectData storage project = _projects[_projectId];
        
        require(
            msg.sender == project.escrowVault ||
            hasRole(OPERATOR_ROLE, msg.sender),
            "RWAProjectNFT: not authorized"
        );

        project.totalRaised = _totalRaised;

        emit TotalRaisedUpdated(_projectId, _totalRaised);
    }

    // ============ View Functions ============

    /**
     * @dev Gets project details
     * @param _projectId Project ID
     * @return Project struct
     */
    function getProject(
        uint256 _projectId
    ) external view override returns (Project memory) {
        require(_projectId > 0 && _projectId <= _projectCounter, "RWAProjectNFT: invalid project");
        
        ProjectData storage data = _projects[_projectId];
        
        return Project({
            id: data.id,
            owner: data.owner,
            metadataURI: data.metadataURI,
            fundingGoal: data.fundingGoal,
            totalRaised: data.totalRaised,
            minInvestment: data.minInvestment,
            maxInvestment: data.maxInvestment,
            deadline: data.deadline,
            status: data.status,
            securityToken: data.securityToken,
            escrowVault: data.escrowVault,
            createdAt: data.createdAt,
            completedAt: data.completedAt,
            transferable: data.transferable
        });
    }

    /**
     * @dev Gets project owner
     * @param _projectId Project ID
     * @return address Owner address
     */
    function getProjectOwner(
        uint256 _projectId
    ) external view override returns (address) {
        require(_projectId > 0 && _projectId <= _projectCounter, "RWAProjectNFT: invalid project");
        return _projects[_projectId].owner;
    }

    /**
     * @dev Gets project status
     * @param _projectId Project ID
     * @return ProjectStatus Current status
     */
    function getProjectStatus(
        uint256 _projectId
    ) external view override returns (ProjectStatus) {
        require(_projectId > 0 && _projectId <= _projectCounter, "RWAProjectNFT: invalid project");
        return _projects[_projectId].status;
    }

    /**
     * @dev Checks if project NFT is transferable
     * @param _projectId Project ID
     * @return bool True if transferable
     */
    function isTransferable(
        uint256 _projectId
    ) external view override returns (bool) {
        require(_projectId > 0 && _projectId <= _projectCounter, "RWAProjectNFT: invalid project");
        return _projects[_projectId].transferable;
    }

    /**
     * @dev Checks if project exists
     * @param _projectId Project ID
     * @return bool True if exists
     */
    function projectExists(
        uint256 _projectId
    ) external view override returns (bool) {
        return _projectId > 0 && _projectId <= _projectCounter;
    }

    /**
     * @dev Gets total number of projects
     * @return uint256 Total projects
     */
    function totalProjects() external view override returns (uint256) {
        return _projectCounter;
    }

    /**
     * @dev Gets projects owned by an address
     * @param _owner Owner address
     * @return uint256[] Array of project IDs
     */
    function getProjectsByOwner(address _owner) external view returns (uint256[] memory) {
        return _ownerProjects[_owner];
    }

    // ============ Admin Functions ============

    /**
     * @dev Pauses the contract
     */
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    /**
     * @dev Unpauses the contract
     */
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    // ============ Override Functions ============

    /**
     * @dev Hook called before token transfer - enforces soulbound until completion
     */
    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 tokenId,
        uint256 batchSize
    ) internal override(ERC721Upgradeable, ERC721EnumerableUpgradeable) {
        // Allow minting (from == address(0))
        if (from != address(0)) {
            // Check if transferable (only after project completion)
            require(
                _projects[tokenId].transferable ||
                hasRole(OPERATOR_ROLE, msg.sender),
                "RWAProjectNFT: soulbound until completion"
            );
        }

        super._beforeTokenTransfer(from, to, tokenId, batchSize);
    }

    /**
     * @dev Updates owner mapping on transfer
     */
    function _afterTokenTransfer(
        address from,
        address to,
        uint256 tokenId,
        uint256 batchSize
    ) internal override(ERC721Upgradeable) {
        super._afterTokenTransfer(from, to, tokenId, batchSize);

        // Update project owner
        if (from != address(0) && to != address(0)) {
            _projects[tokenId].owner = to;
        }
    }

    /**
     * @dev Burns token
     */
    function _burn(
        uint256 tokenId
    ) internal override(ERC721Upgradeable, ERC721URIStorageUpgradeable) {
        super._burn(tokenId);
    }

    /**
     * @dev Returns token URI
     */
    function tokenURI(
        uint256 tokenId
    ) public view override(ERC721Upgradeable, ERC721URIStorageUpgradeable) returns (string memory) {
        return super.tokenURI(tokenId);
    }

    /**
     * @dev Supports interface
     */
    function supportsInterface(
        bytes4 interfaceId
    ) public view override(
        ERC721Upgradeable,
        ERC721EnumerableUpgradeable,
        ERC721URIStorageUpgradeable,
        AccessControlUpgradeable
    ) returns (bool) {
        return super.supportsInterface(interfaceId);
    }

    /**
     * @dev Authorizes upgrade
     */
    function _authorizeUpgrade(
        address newImplementation
    ) internal override onlyRole(UPGRADER_ROLE) {}
}

contracts/core/RWASecurityToken.sol.content:
// contracts/RWASecurityToken.sol
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/token/ERC20/ERC20Upgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/extensions/ERC20BurnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/extensions/ERC20PausableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/extensions/ERC20SnapshotUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";

interface IIdentityRegistry {
    function isVerified(address _userAddress) external view returns (bool);
}

interface IModularCompliance {
    function canTransfer(address _from, address _to, uint256 _amount) external view returns (bool);
    function transferred(address _from, address _to, uint256 _amount) external;
    function created(address _to, uint256 _amount) external;
    function destroyed(address _from, uint256 _amount) external;
}

contract RWASecurityToken is 
    Initializable, 
    ERC20Upgradeable, 
    ERC20BurnableUpgradeable,
    ERC20PausableUpgradeable,
    ERC20SnapshotUpgradeable,
    AccessControlUpgradeable, 
    UUPSUpgradeable,
    ReentrancyGuardUpgradeable 
{
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant BURNER_ROLE = keccak256("BURNER_ROLE");
    bytes32 public constant FREEZER_ROLE = keccak256("FREEZER_ROLE");
    bytes32 public constant COMPLIANCE_ROLE = keccak256("COMPLIANCE_ROLE");
    bytes32 public constant UPGRADER_ROLE = keccak256("UPGRADER_ROLE");
    bytes32 public constant SNAPSHOT_ROLE = keccak256("SNAPSHOT_ROLE");

    IIdentityRegistry public identityRegistry;
    IModularCompliance public compliance;

    uint256 public maxSupply;
    uint256 public projectId;
    
    // Lockup tracking
    uint256 public defaultLockupPeriod;
    mapping(address => uint256) public lockupExpiry;
    mapping(address => bool) public frozen;

    // Off-chain payment tracking
    struct OffChainPayment {
        address investor;
        uint256 tokenAmount;
        string paymentMethod;
        string paymentReference;
        uint256 timestamp;
    }
    
    mapping(string => OffChainPayment) public offChainPayments;
    mapping(string => bool) public processedReferences;
    uint256 public totalOffChainInvestments;

    // Events
    event TokensFrozen(address indexed account, bool frozen);
    event LockupSet(address indexed account, uint256 expiry);
    event ComplianceUpdated(address indexed newCompliance);
    event IdentityRegistryUpdated(address indexed newRegistry);
    event OffChainInvestment(
        address indexed investor,
        uint256 tokenAmount,
        string paymentMethod,
        string paymentReference,
        uint256 timestamp
    );

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(
        string memory _name,
        string memory _symbol,
        address _admin,
        address _identityRegistry,
        address _compliance,
        uint256 _maxSupply,
        uint256 _projectId
    ) public initializer {
        __ERC20_init(_name, _symbol);
        __ERC20Burnable_init();
        __ERC20Pausable_init();
        __ERC20Snapshot_init();
        __AccessControl_init();
        __UUPSUpgradeable_init();
        __ReentrancyGuard_init();

        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(MINTER_ROLE, _admin);
        _grantRole(BURNER_ROLE, _admin);
        _grantRole(FREEZER_ROLE, _admin);
        _grantRole(COMPLIANCE_ROLE, _admin);
        _grantRole(UPGRADER_ROLE, _admin);
        _grantRole(SNAPSHOT_ROLE, _admin);

        identityRegistry = IIdentityRegistry(_identityRegistry);
        if (_compliance != address(0)) {
            compliance = IModularCompliance(_compliance);
        }
        
        maxSupply = _maxSupply;
        projectId = _projectId;
        defaultLockupPeriod = 365 days;
    }

    // ============================================================================
    // SNAPSHOT FUNCTIONS
    // ============================================================================

    /**
     * @notice Create a snapshot for dividend distribution
     * @return snapshotId The ID of the created snapshot
     */
    function snapshot() external onlyRole(SNAPSHOT_ROLE) returns (uint256) {
        return _snapshot();
    }

    /**
     * @notice Get balance at a specific snapshot
     */
    function balanceOfAt(address account, uint256 snapshotId) public view override returns (uint256) {
        return super.balanceOfAt(account, snapshotId);
    }

    /**
     * @notice Get total supply at a specific snapshot
     */
    function totalSupplyAt(uint256 snapshotId) public view override returns (uint256) {
        return super.totalSupplyAt(snapshotId);
    }

    // ============================================================================
    // MINTING FUNCTIONS
    // ============================================================================

    function mint(address _to, uint256 _amount) external onlyRole(MINTER_ROLE) {
        require(_to != address(0), "Cannot mint to zero address");
        require(totalSupply() + _amount <= maxSupply, "Exceeds max supply");
        require(identityRegistry.isVerified(_to), "Recipient not verified");

        _mint(_to, _amount);
        _setLockupIfNew(_to);

        if (address(compliance) != address(0)) {
            compliance.created(_to, _amount);
        }
    }

    /**
     * @notice Mint tokens for off-chain payments (Stripe, bank transfer, etc.)
     */
    function mintForOffChainPayment(
        address _to,
        uint256 _tokenAmount,
        string calldata _paymentMethod,
        string calldata _paymentReference
    ) external onlyRole(MINTER_ROLE) nonReentrant {
        require(_to != address(0), "Cannot mint to zero address");
        require(_tokenAmount > 0, "Amount must be greater than 0");
        require(bytes(_paymentReference).length > 0, "Payment reference required");
        require(!processedReferences[_paymentReference], "Payment already processed");
        require(totalSupply() + _tokenAmount <= maxSupply, "Exceeds max supply");
        require(identityRegistry.isVerified(_to), "Recipient not verified");

        processedReferences[_paymentReference] = true;

        offChainPayments[_paymentReference] = OffChainPayment({
            investor: _to,
            tokenAmount: _tokenAmount,
            paymentMethod: _paymentMethod,
            paymentReference: _paymentReference,
            timestamp: block.timestamp
        });

        totalOffChainInvestments++;

        _mint(_to, _tokenAmount);
        _setLockupIfNew(_to);

        if (address(compliance) != address(0)) {
            compliance.created(_to, _tokenAmount);
        }

        emit OffChainInvestment(_to, _tokenAmount, _paymentMethod, _paymentReference, block.timestamp);
    }

    /**
     * @notice Batch mint for multiple off-chain payments
     */
    function batchMintForOffChainPayment(
        address[] calldata _investors,
        uint256[] calldata _amounts,
        string calldata _paymentMethod,
        string[] calldata _paymentReferences
    ) external onlyRole(MINTER_ROLE) nonReentrant {
        require(_investors.length == _amounts.length, "Arrays length mismatch");
        require(_investors.length == _paymentReferences.length, "Arrays length mismatch");
        require(_investors.length <= 50, "Batch too large");

        uint256 totalAmount = 0;
        for (uint256 i = 0; i < _amounts.length; i++) {
            totalAmount += _amounts[i];
        }
        require(totalSupply() + totalAmount <= maxSupply, "Exceeds max supply");

        for (uint256 i = 0; i < _investors.length; i++) {
            address investor = _investors[i];
            uint256 amount = _amounts[i];
            string calldata ref = _paymentReferences[i];

            require(investor != address(0), "Cannot mint to zero address");
            require(amount > 0, "Amount must be greater than 0");
            require(!processedReferences[ref], "Payment already processed");
            require(identityRegistry.isVerified(investor), "Recipient not verified");

            processedReferences[ref] = true;

            offChainPayments[ref] = OffChainPayment({
                investor: investor,
                tokenAmount: amount,
                paymentMethod: _paymentMethod,
                paymentReference: ref,
                timestamp: block.timestamp
            });

            totalOffChainInvestments++;

            _mint(investor, amount);
            _setLockupIfNew(investor);

            if (address(compliance) != address(0)) {
                compliance.created(investor, amount);
            }

            emit OffChainInvestment(investor, amount, _paymentMethod, ref, block.timestamp);
        }
    }

    // ============================================================================
    // LOCKUP FUNCTIONS
    // ============================================================================

    function _setLockupIfNew(address _account) internal {
        if (lockupExpiry[_account] == 0 && defaultLockupPeriod > 0) {
            lockupExpiry[_account] = block.timestamp + defaultLockupPeriod;
            emit LockupSet(_account, lockupExpiry[_account]);
        }
    }

    function setLockup(address _account, uint256 _expiry) external onlyRole(COMPLIANCE_ROLE) {
        lockupExpiry[_account] = _expiry;
        emit LockupSet(_account, _expiry);
    }

    function setDefaultLockupPeriod(uint256 _period) external onlyRole(COMPLIANCE_ROLE) {
        defaultLockupPeriod = _period;
    }

    function isLocked(address _account) public view returns (bool) {
        return lockupExpiry[_account] > block.timestamp;
    }

    // ============================================================================
    // FREEZE FUNCTIONS
    // ============================================================================

    function setFrozen(address _account, bool _frozen) external onlyRole(FREEZER_ROLE) {
        frozen[_account] = _frozen;
        emit TokensFrozen(_account, _frozen);
    }

    function batchSetFrozen(address[] calldata _accounts, bool _frozen) external onlyRole(FREEZER_ROLE) {
        for (uint256 i = 0; i < _accounts.length; i++) {
            frozen[_accounts[i]] = _frozen;
            emit TokensFrozen(_accounts[i], _frozen);
        }
    }

    // ============================================================================
    // TRANSFER OVERRIDES
    // ============================================================================

    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 amount
    ) internal virtual override(ERC20Upgradeable, ERC20PausableUpgradeable, ERC20SnapshotUpgradeable) {
        super._beforeTokenTransfer(from, to, amount);

        // Skip checks for minting
        if (from != address(0)) {
            require(!frozen[from], "Sender account is frozen");
            require(!isLocked(from), "Sender tokens are locked");
            
            // Skip verification for burning
            if (to != address(0)) {
                require(!frozen[to], "Recipient account is frozen");
                require(identityRegistry.isVerified(to), "Recipient not verified");
                
                if (address(compliance) != address(0)) {
                    require(compliance.canTransfer(from, to, amount), "Transfer not compliant");
                }
            }
        }
    }

    function _afterTokenTransfer(
        address from,
        address to,
        uint256 amount
    ) internal virtual override {
        super._afterTokenTransfer(from, to, amount);

        // Notify compliance of transfer
        if (from != address(0) && to != address(0) && address(compliance) != address(0)) {
            compliance.transferred(from, to, amount);
        }
    }

    // ============================================================================
    // ADMIN FUNCTIONS
    // ============================================================================

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    function setCompliance(address _compliance) external onlyRole(COMPLIANCE_ROLE) {
        compliance = IModularCompliance(_compliance);
        emit ComplianceUpdated(_compliance);
    }

    function setIdentityRegistry(address _identityRegistry) external onlyRole(COMPLIANCE_ROLE) {
        identityRegistry = IIdentityRegistry(_identityRegistry);
        emit IdentityRegistryUpdated(_identityRegistry);
    }

    function setMaxSupply(uint256 _maxSupply) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_maxSupply >= totalSupply(), "Cannot set below current supply");
        maxSupply = _maxSupply;
    }

    // ============================================================================
    // VIEW FUNCTIONS
    // ============================================================================

    function getOffChainPayment(string calldata _reference) external view returns (OffChainPayment memory) {
        return offChainPayments[_reference];
    }

    function isPaymentProcessed(string calldata _reference) external view returns (bool) {
        return processedReferences[_reference];
    }

    /**
     * @notice Get current snapshot ID
     */
    function getCurrentSnapshotId() external view returns (uint256) {
        return _getCurrentSnapshotId();
    }

    // ============================================================================
    // UPGRADE
    // ============================================================================

    function _authorizeUpgrade(address newImplementation) internal override onlyRole(UPGRADER_ROLE) {}
}

contracts/identity/KYCManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/PausableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";

interface IIdentityRegistry {
    function registerIdentity(address _userAddress, address _identity, uint16 _country) external;
    function isVerified(address _userAddress) external view returns (bool);
    function deleteIdentity(address _userAddress) external;
}

/// @title KYCManager - Automated KYC with manual fallback
/// @notice Handles automated KYC verification with human review for edge cases
/// @dev Integrates with IdentityRegistry for on-chain identity management
contract KYCManager is 
    Initializable, 
    AccessControlUpgradeable, 
    UUPSUpgradeable,
    PausableUpgradeable,
    ReentrancyGuardUpgradeable
{
    // ============================================
    // ROLES
    // ============================================
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant KYC_REVIEWER_ROLE = keccak256("KYC_REVIEWER_ROLE");
    bytes32 public constant AUTO_VERIFIER_ROLE = keccak256("AUTO_VERIFIER_ROLE");
    bytes32 public constant UPGRADER_ROLE = keccak256("UPGRADER_ROLE");
    bytes32 public constant ESCROW_ROLE = keccak256("ESCROW_ROLE");

    // ============================================
    // ENUMS
    // ============================================
    enum KYCStatus {
        None,               // 0 - No submission
        Pending,            // 1 - Awaiting auto-verification
        AutoVerifying,      // 2 - Auto-verification in progress
        ManualReview,       // 3 - Sent to manual review (auto failed)
        Approved,           // 4 - KYC approved
        Rejected,           // 5 - KYC rejected
        Expired,            // 6 - KYC expired
        Revoked             // 7 - KYC revoked
    }

    enum KYCLevel {
        None,               // 0 - Not verified
        Basic,              // 1 - Email + country only
        Standard,           // 2 - ID verified
        Enhanced,           // 3 - ID + address verified
        Accredited          // 4 - Accredited investor
    }

    enum RejectionReason {
        None,               // 0
        BlockedCountry,     // 1
        Underage,           // 2
        DocumentExpired,    // 3
        DocumentUnreadable, // 4
        FaceMismatch,       // 5
        LivenessCheckFailed,// 6
        SanctionsList,      // 7
        DuplicateIdentity,  // 8
        SuspiciousActivity, // 9
        Other               // 10
    }

    // ============================================
    // STRUCTS
    // ============================================
    struct KYCSubmission {
        address user;
        KYCStatus status;
        KYCLevel level;
        KYCLevel requestedLevel;
        uint16 countryCode;
        bytes32 documentHash;       // Hash of document data
        bytes32 dataHash;           // Hash of all KYC data
        uint256 submittedAt;
        uint256 verifiedAt;
        uint256 expiresAt;
        address verifiedBy;         // address(0) if auto-verified
        bool autoVerified;
        RejectionReason rejectionReason;
        string rejectionDetails;
        uint8 verificationScore;
        uint256 totalInvested;
    }

    // ============================================
    // STATE VARIABLES
    // ============================================
    IIdentityRegistry public identityRegistry;
    
    uint256 public kycValidityPeriod;
    uint8 public autoApprovalThreshold;     // Minimum score for auto-approval (0-100)
    uint8 public manualReviewThreshold;     // Below this gets rejected, above goes to manual
    
    mapping(address => KYCSubmission) private _submissions;
    mapping(bytes32 => address) private _documentToUser;  // Prevent duplicate documents
    mapping(uint16 => bool) public blockedCountries;
    mapping(KYCLevel => uint256) public investmentLimits;
    
    
    address[] private _allUsers;
    mapping(address => bool) private _isRegistered;
    
    // Statistics
    uint256 public totalSubmissions;
    uint256 public totalAutoApproved;
    uint256 public totalManualApproved;
    uint256 public totalRejected;
    uint256 public pendingManualReview;

    mapping(uint8 => uint256) public tierLimits;

    // ============================================
    // EVENTS
    // ============================================
    event KYCSubmitted(
        address indexed user, 
        KYCLevel requestedLevel, 
        bytes32 indexed dataHash, 
        uint256 timestamp
    );
    event KYCAutoVerificationStarted(address indexed user);
    event KYCAutoApproved(
        address indexed user, 
        KYCLevel level, 
        uint8 confidenceScore, 
        uint256 expiresAt
    );
    event KYCSentToManualReview(
        address indexed user, 
        string reason, 
        uint8 confidenceScore
    );
    event KYCManualApproved(
        address indexed user, 
        KYCLevel level, 
        address indexed reviewer
    );
    event KYCRejected(
        address indexed user, 
        RejectionReason reason, 
        string details, 
        bool wasAutomatic
    );
    event KYCRevoked(address indexed user, address indexed admin, string reason);
    event KYCExpired(address indexed user);
    event ThresholdsUpdated(uint8 autoApproval, uint8 manualReview);
    event CountryBlocked(uint16 indexed countryCode);
    event CountryUnblocked(uint16 indexed countryCode);
    event InvestmentLimitUpdated(KYCLevel indexed level, uint256 limit);
    event InvestmentRecorded(address indexed user,  uint256 amount,  uint256 newTotal, uint256 remainingLimit);
    event EscrowAuthorized(address indexed escrow);
    event EscrowRevoked(address indexed escrow);
    event TierLimitUpdated(uint8 indexed level, uint256 limit);
    event AllTierLimitsUpdated(uint256 bronze, uint256 silver, uint256 gold, uint256 diamond);

    // ============================================
    // CUSTOM ERRORS (Solidity 0.8.4+)
    // ============================================
    error CountryIsBlocked();
    error AlreadyPending();
    error AlreadyApproved();
    error NotPending();
    error NotInManualReview();
    error InvalidThreshold();
    error DuplicateDocument();
    error ZeroAddress();
    error InvalidScore();
    error InvalidDocumentHash();
    error NotApproved();
    error ExceedsInvestmentLimit();
    error KYCNotApproved();
    error KYCHasExpired();

    // ============================================
    // MODIFIERS
    // ============================================
    modifier validAddress(address _addr) {
        if (_addr == address(0)) revert ZeroAddress();
        _;
    }

    // ============================================
    // INITIALIZER
    // ============================================
    
    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    /// @notice Initialize the KYC Manager
    /// @param _identityRegistry Address of the IdentityRegistry contract
    /// @param _admin Address of the admin
    function initialize(
        address _identityRegistry,
        address _admin
    ) public initializer validAddress(_identityRegistry) validAddress(_admin) {
        __AccessControl_init();
        __UUPSUpgradeable_init();
        __Pausable_init();
        __ReentrancyGuard_init();

        identityRegistry = IIdentityRegistry(_identityRegistry);
        
        kycValidityPeriod = 365 days;
        autoApprovalThreshold = 80;     // 80% confidence for auto-approval
        manualReviewThreshold = 50;     // Below 50% rejected, 50-80% manual review

        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(ADMIN_ROLE, _admin);
        _grantRole(KYC_REVIEWER_ROLE, _admin);
        _grantRole(AUTO_VERIFIER_ROLE, _admin);
        _grantRole(UPGRADER_ROLE, _admin);

        // Default investment limits (USD with 6 decimals)
        investmentLimits[KYCLevel.None] = 0;
        investmentLimits[KYCLevel.Basic] = 1_000 * 1e6;        // $1,000
        investmentLimits[KYCLevel.Standard] = 10_000 * 1e6;    // $10,000
        investmentLimits[KYCLevel.Enhanced] = 100_000 * 1e6;   // $100,000
        investmentLimits[KYCLevel.Accredited] = type(uint256).max; // Unlimited
    }

    // ============================================
    // USER FUNCTIONS
    // ============================================

    /// @notice Submit KYC for verification
    /// @param _countryCode ISO 3166-1 numeric country code
    /// @param _documentHash Hash of the uploaded documents
    /// @param _dataHash Hash of all KYC data (for integrity verification)
    /// @param _requestedLevel Requested verification level
    function submitKYC(
        uint16 _countryCode,
        bytes32 _documentHash,
        bytes32 _dataHash,
        KYCLevel _requestedLevel
    ) external whenNotPaused nonReentrant {
        if (blockedCountries[_countryCode]) revert CountryIsBlocked();
        if (_documentHash == bytes32(0)) revert InvalidDocumentHash();
        
        // Check for duplicate documents
        if (_documentToUser[_documentHash] != address(0) && 
            _documentToUser[_documentHash] != msg.sender) {
            revert DuplicateDocument();
        }

        KYCSubmission storage submission = _submissions[msg.sender];
        
        // Allow resubmission if rejected, expired, or none
        if (submission.status == KYCStatus.Pending || 
            submission.status == KYCStatus.AutoVerifying ||
            submission.status == KYCStatus.ManualReview) {
            revert AlreadyPending();
        }
        
        if (submission.status == KYCStatus.Approved && 
            block.timestamp < submission.expiresAt) {
            revert AlreadyApproved();
        }

        // Register user if first submission
        if (!_isRegistered[msg.sender]) {
            _allUsers.push(msg.sender);
            _isRegistered[msg.sender] = true;
        }

        // Map document to user
        _documentToUser[_documentHash] = msg.sender;

        // Create submission
        _submissions[msg.sender] = KYCSubmission({
            user: msg.sender,
            status: KYCStatus.Pending,
            level: KYCLevel.None,
            requestedLevel: _requestedLevel,
            countryCode: _countryCode,
            documentHash: _documentHash,
            dataHash: _dataHash,
            submittedAt: block.timestamp,
            verifiedAt: 0,
            expiresAt: 0,
            verifiedBy: address(0),
            autoVerified: false,
            rejectionReason: RejectionReason.None,
            rejectionDetails: "",
            verificationScore: 0,
            totalInvested: 0
        });

        totalSubmissions++;

        emit KYCSubmitted(msg.sender, _requestedLevel, _dataHash, block.timestamp);
    }

    // Batch update function
    function setAllTierLimits(
        uint256 _bronze,
        uint256 _silver,
        uint256 _gold,
        uint256 _diamond
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        tierLimits[1] = _bronze;   // 10,000 USDC = 10_000_000_000 (6 decimals)
        tierLimits[2] = _silver;   // 100,000 USDC = 100_000_000_000
        tierLimits[3] = _gold;     // 1,000,000 USDC = 1_000_000_000_000
        tierLimits[4] = _diamond;  // 0 = unlimited
        
        emit AllTierLimitsUpdated(_bronze, _silver, _gold, _diamond);
    }


    function requestUpgrade(
        bytes32 _documentHash,
        bytes32 _dataHash,
        KYCLevel _requestedLevel
    ) external whenNotPaused nonReentrant {
        KYCSubmission storage submission = _submissions[msg.sender];
        
        // Must have approved KYC
        if (submission.status != KYCStatus.Approved) revert NotApproved();
        
        // Must not be expired
        if (block.timestamp >= submission.expiresAt) revert KYCHasExpired();
        
        // Requested level must be higher than current
        if (uint8(_requestedLevel) <= uint8(submission.level)) {
            revert InvalidThreshold(); // Reusing error - could create a new one
        }
        
        // Check for duplicate documents (if new document provided)
        if (_documentHash != bytes32(0) && 
            _documentHash != submission.documentHash &&
            _documentToUser[_documentHash] != address(0) && 
            _documentToUser[_documentHash] != msg.sender) {
            revert DuplicateDocument();
        }

        // Store old level for reference
        KYCLevel oldLevel = submission.level;
        
        // Update submission for upgrade review
        submission.status = KYCStatus.Pending;
        submission.requestedLevel = _requestedLevel;
        if (_documentHash != bytes32(0)) {
            _documentToUser[_documentHash] = msg.sender;
            submission.documentHash = _documentHash;
        }
        if (_dataHash != bytes32(0)) {
            submission.dataHash = _dataHash;
        }
        submission.submittedAt = block.timestamp;
        submission.verificationScore = 0;
        
        // Keep the old level active during upgrade process
        // (user retains current privileges until upgrade completes)
        submission.level = oldLevel;

        totalSubmissions++;

        emit KYCSubmitted(msg.sender, _requestedLevel, _dataHash, block.timestamp);
    }

    /// @notice Get own KYC status
    function getMyKYC() external view returns (KYCSubmission memory) {
        return _submissions[msg.sender];
    }

    // ============================================
    // AUTO-VERIFIER FUNCTIONS (Backend calls these)
    // ============================================

    /// @notice Start auto-verification process
    /// @param _user User address to verify
    function startAutoVerification(address _user) 
        external 
        onlyRole(AUTO_VERIFIER_ROLE) 
        whenNotPaused 
    {
        KYCSubmission storage submission = _submissions[_user];
        if (submission.status != KYCStatus.Pending) revert NotPending();
        
        submission.status = KYCStatus.AutoVerifying;
        emit KYCAutoVerificationStarted(_user);
    }

    /// @notice Submit auto-verification result
    /// @param _user User address
    /// @param _passed Whether all checks passed
    /// @param _confidenceScore Confidence score 0-100
    /// @param _rejectionReason Reason if failed
    /// @param _failureDetails Details about the failure
    function submitAutoVerificationResult(
        address _user,
        bool _passed,
        uint8 _confidenceScore,
        RejectionReason _rejectionReason,
        string calldata _failureDetails
    ) external onlyRole(AUTO_VERIFIER_ROLE) whenNotPaused nonReentrant {
        if (_confidenceScore > 100) revert InvalidScore();
        
        KYCSubmission storage submission = _submissions[_user];
        if (submission.status != KYCStatus.AutoVerifying && 
            submission.status != KYCStatus.Pending) {
            revert NotPending();
        }

        submission.verificationScore = _confidenceScore;

        if (_passed && _confidenceScore >= autoApprovalThreshold) {
            // AUTO-APPROVE
            _approveKYC(_user, submission.requestedLevel, true);
            totalAutoApproved++;
            
            emit KYCAutoApproved(
                _user, 
                submission.requestedLevel, 
                _confidenceScore, 
                submission.expiresAt
            );
        } else if (_confidenceScore >= manualReviewThreshold) {
            // SEND TO MANUAL REVIEW
            submission.status = KYCStatus.ManualReview;
            submission.rejectionDetails = _failureDetails;
            pendingManualReview++;
            
            emit KYCSentToManualReview(_user, _failureDetails, _confidenceScore);
        } else {
            // AUTO-REJECT
            submission.status = KYCStatus.Rejected;
            submission.rejectionReason = _rejectionReason;
            submission.rejectionDetails = _failureDetails;
            submission.verifiedAt = block.timestamp;
            totalRejected++;
            
            emit KYCRejected(_user, _rejectionReason, _failureDetails, true);
        }
    }

    // ============================================
    // MANUAL REVIEWER FUNCTIONS
    // ============================================

    /// @notice Manually approve a KYC submission
    /// @param _user User address
    /// @param _level Approved KYC level
    function manualApprove(
        address _user,
        KYCLevel _level
    ) external onlyRole(KYC_REVIEWER_ROLE) whenNotPaused nonReentrant {
        KYCSubmission storage submission = _submissions[_user];
        if (submission.status != KYCStatus.ManualReview) revert NotInManualReview();

        _approveKYC(_user, _level, false);
        pendingManualReview--;
        totalManualApproved++;

        emit KYCManualApproved(_user, _level, msg.sender);
    }

    /// @notice Manually reject a KYC submission
    /// @param _user User address
    /// @param _reason Rejection reason
    /// @param _details Additional details
    function manualReject(
        address _user,
        RejectionReason _reason,
        string calldata _details
    ) external onlyRole(KYC_REVIEWER_ROLE) whenNotPaused {
        KYCSubmission storage submission = _submissions[_user];
        if (submission.status != KYCStatus.ManualReview) revert NotInManualReview();

        submission.status = KYCStatus.Rejected;
        submission.rejectionReason = _reason;
        submission.rejectionDetails = _details;
        submission.verifiedAt = block.timestamp;
        submission.verifiedBy = msg.sender;
        
        pendingManualReview--;
        totalRejected++;

        emit KYCRejected(_user, _reason, _details, false);
    }

    /// @notice Revoke an approved KYC
    /// @param _user User address
    /// @param _reason Reason for revocation
    function revokeKYC(
        address _user,
        string calldata _reason
    ) external onlyRole(ADMIN_ROLE) {
        KYCSubmission storage submission = _submissions[_user];
        if (submission.status != KYCStatus.Approved) revert NotApproved();

        submission.status = KYCStatus.Revoked;
        submission.rejectionDetails = _reason;
        submission.level = KYCLevel.None;

        // Remove from IdentityRegistry
        try identityRegistry.deleteIdentity(_user) {} catch {}

        emit KYCRevoked(_user, msg.sender, _reason);
    }

    // ============================================
    // INTERNAL FUNCTIONS
    // ============================================

    function _approveKYC(
        address _user, 
        KYCLevel _level,
        bool _isAuto
    ) internal {
        KYCSubmission storage submission = _submissions[_user];
        
        uint256 expiresAt = block.timestamp + kycValidityPeriod;

        submission.status = KYCStatus.Approved;
        submission.level = _level;
        submission.verifiedAt = block.timestamp;
        submission.expiresAt = expiresAt;
        submission.autoVerified = _isAuto;
        submission.verifiedBy = _isAuto ? address(0) : msg.sender;
        submission.rejectionReason = RejectionReason.None;
        submission.rejectionDetails = "";

        // Register in IdentityRegistry
        try identityRegistry.registerIdentity(_user, _user, submission.countryCode) {
        } catch {
            // Already registered is fine
        }
    }

    // ============================================
    // VIEW FUNCTIONS
    // ============================================

    /// @notice Get KYC submission for any user (admin view)
    function getKYCSubmission(address _user) external view returns (KYCSubmission memory) {
        return _submissions[_user];
    }

    /// @notice Check if user has approved KYC
    function isKYCApproved(address _user) external view returns (bool) {
        KYCSubmission storage s = _submissions[_user];
        return s.status == KYCStatus.Approved && block.timestamp < s.expiresAt;
    }

    /// @notice Get user's KYC level
    function getKYCLevel(address _user) external view returns (KYCLevel) {
        KYCSubmission storage s = _submissions[_user];
        if (s.status != KYCStatus.Approved || block.timestamp >= s.expiresAt) {
            return KYCLevel.None;
        }
        return s.level;
    }

    /// @notice Get user's investment limit based on KYC level
    function getInvestmentLimit(address _user) external view returns (uint256) {
        KYCSubmission storage s = _submissions[_user];
        if (s.status != KYCStatus.Approved || block.timestamp >= s.expiresAt) {
            return 0;
        }
        return investmentLimits[s.level];
    }

    /// @notice Get list of addresses pending manual review
    function getPendingManualReviewList() external view returns (address[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < _allUsers.length; i++) {
            if (_submissions[_allUsers[i]].status == KYCStatus.ManualReview) {
                count++;
            }
        }
        
        address[] memory pending = new address[](count);
        uint256 idx = 0;
        for (uint256 i = 0; i < _allUsers.length; i++) {
            if (_submissions[_allUsers[i]].status == KYCStatus.ManualReview) {
                pending[idx++] = _allUsers[i];
            }
        }
        return pending;
    }

    /// @notice Get all pending submissions (for auto-verifier)
    function getPendingSubmissions() external view returns (address[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < _allUsers.length; i++) {
            if (_submissions[_allUsers[i]].status == KYCStatus.Pending) {
                count++;
            }
        }
        
        address[] memory pending = new address[](count);
        uint256 idx = 0;
        for (uint256 i = 0; i < _allUsers.length; i++) {
            if (_submissions[_allUsers[i]].status == KYCStatus.Pending) {
                pending[idx++] = _allUsers[i];
            }
        }
        return pending;
    }

    /// @notice Get KYC statistics
    function getStatistics() external view returns (
        uint256 _totalSubmissions,
        uint256 _totalAutoApproved,
        uint256 _totalManualApproved,
        uint256 _totalRejected,
        uint256 _pendingManualReview,
        uint256 _totalUsers
    ) {
        return (
            totalSubmissions,
            totalAutoApproved,
            totalManualApproved,
            totalRejected,
            pendingManualReview,
            _allUsers.length
        );
    }

    /// @notice Get submissions with pagination
    function getSubmissionsPaginated(
        uint256 _offset, 
        uint256 _limit
    ) external view returns (KYCSubmission[] memory) {
        uint256 total = _allUsers.length;
        if (_offset >= total) {
            return new KYCSubmission[](0);
        }
        
        uint256 end = _offset + _limit;
        if (end > total) {
            end = total;
        }
        
        KYCSubmission[] memory submissions = new KYCSubmission[](end - _offset);
        for (uint256 i = _offset; i < end; i++) {
            submissions[i - _offset] = _submissions[_allUsers[i]];
        }
        
        return submissions;
    }

    // ============================================
    // INVESTMENT LIMIT FUNCTIONS
    // ============================================

    /// @notice Get user's remaining investment limit
    /// @param _user User address
    /// @return Remaining limit in USDC (6 decimals)
    function getRemainingLimit(address _user) external view returns (uint256) {
        KYCSubmission storage s = _submissions[_user];
        
        // Not approved or expired = no limit
        if (s.status != KYCStatus.Approved || block.timestamp >= s.expiresAt) {
            return 0;
        }
        
        uint256 limit = investmentLimits[s.level];
        
        // Unlimited tier
        if (limit == type(uint256).max) {
            return type(uint256).max;
        }
        
        // Calculate remaining
        if (s.totalInvested >= limit) {
            return 0;
        }
        
        return limit - s.totalInvested;
    }

    /// @notice Check if user can invest a specific amount
    /// @param _user User address
    /// @param _amount Amount to invest (in USDC, 6 decimals)
    /// @return allowed Whether the investment is allowed
    /// @return reason Reason if not allowed
    function canInvest(
        address _user, 
        uint256 _amount
    ) external view returns (bool allowed, string memory reason) {
        KYCSubmission storage s = _submissions[_user];
        
        // Check KYC status
        if (s.status != KYCStatus.Approved) {
            return (false, "KYC not approved");
        }
        
        // Check expiration
        if (block.timestamp >= s.expiresAt) {
            return (false, "KYC expired");
        }
        
        // Check limit
        uint256 limit = investmentLimits[s.level];
        
        // Unlimited tier always allowed
        if (limit == type(uint256).max) {
            return (true, "");
        }
        
        // Check remaining capacity
        if (s.totalInvested + _amount > limit) {
            return (false, "Exceeds investment limit");
        }
        
        return (true, "");
    }

    /// @notice Get user's total invested amount
    /// @param _user User address
    /// @return Total invested in USDC (6 decimals)
    function getTotalInvested(address _user) external view returns (uint256) {
        return _submissions[_user].totalInvested;
    }

    // ============================================
    // ESCROW FUNCTIONS (called when user invests)
    // ============================================

    /// @notice Record an investment (called by authorized escrow contracts)
    /// @param _user User address
    /// @param _amount Investment amount in USDC (6 decimals)
    function recordInvestment(
        address _user,
        uint256 _amount
    ) external onlyRole(ESCROW_ROLE) nonReentrant {
        KYCSubmission storage s = _submissions[_user];
        
        // Validate KYC status
        if (s.status != KYCStatus.Approved) revert KYCNotApproved();
        if (block.timestamp >= s.expiresAt) revert KYCHasExpired();
        
        // Check limit (skip for unlimited tier)
        uint256 limit = investmentLimits[s.level];
        if (limit != type(uint256).max) {
            if (s.totalInvested + _amount > limit) revert ExceedsInvestmentLimit();
        }
        
        // Record investment
        s.totalInvested += _amount;
        
        // Calculate remaining for event
        uint256 remaining = limit == type(uint256).max 
            ? type(uint256).max 
            : limit - s.totalInvested;
        
        emit InvestmentRecorded(_user, _amount, s.totalInvested, remaining);
    }

    /// @notice Reverse an investment (for refunds)
    /// @param _user User address
    /// @param _amount Amount to reverse
    function reverseInvestment(
        address _user,
        uint256 _amount
    ) external onlyRole(ESCROW_ROLE) nonReentrant {
        KYCSubmission storage s = _submissions[_user];
        
        // Allow reversal even if KYC expired (for refunds)
        if (s.totalInvested < _amount) {
            s.totalInvested = 0;
        } else {
            s.totalInvested -= _amount;
        }
    }

    // ============================================
    // ADMIN FUNCTIONS
    // ============================================

    /// @notice Set auto-approval and manual review thresholds
    function setThresholds(
        uint8 _autoApproval,
        uint8 _manualReview
    ) external onlyRole(ADMIN_ROLE) {
        if (_autoApproval > 100 || _manualReview > 100) revert InvalidThreshold();
        if (_manualReview >= _autoApproval) revert InvalidThreshold();
        
        autoApprovalThreshold = _autoApproval;
        manualReviewThreshold = _manualReview;
        
        emit ThresholdsUpdated(_autoApproval, _manualReview);
    }

    /// @notice Block a country
    function blockCountry(uint16 _countryCode) external onlyRole(ADMIN_ROLE) {
        blockedCountries[_countryCode] = true;
        emit CountryBlocked(_countryCode);
    }

    /// @notice Unblock a country
    function unblockCountry(uint16 _countryCode) external onlyRole(ADMIN_ROLE) {
        blockedCountries[_countryCode] = false;
        emit CountryUnblocked(_countryCode);
    }

    /// @notice Set investment limit for a KYC level
    function setInvestmentLimit(KYCLevel _level, uint256 _limit) external onlyRole(ADMIN_ROLE) {
        investmentLimits[_level] = _limit;
        emit InvestmentLimitUpdated(_level, _limit);
    }

    /// @notice Set KYC validity period
    function setKYCValidityPeriod(uint256 _period) external onlyRole(ADMIN_ROLE) {
        kycValidityPeriod = _period;
    }

    /// @notice Update IdentityRegistry address
    function setIdentityRegistry(address _registry) external onlyRole(ADMIN_ROLE) validAddress(_registry) {
        identityRegistry = IIdentityRegistry(_registry);
    }

    /// @notice Grant AUTO_VERIFIER_ROLE to backend service
    function addAutoVerifier(address _verifier) external onlyRole(ADMIN_ROLE) validAddress(_verifier) {
        _grantRole(AUTO_VERIFIER_ROLE, _verifier);
    }

    /// @notice Remove AUTO_VERIFIER_ROLE
    function removeAutoVerifier(address _verifier) external onlyRole(ADMIN_ROLE) {
        _revokeRole(AUTO_VERIFIER_ROLE, _verifier);
    }

    /// @notice Add KYC reviewer
    function addReviewer(address _reviewer) external onlyRole(ADMIN_ROLE) validAddress(_reviewer) {
        _grantRole(KYC_REVIEWER_ROLE, _reviewer);
    }

    /// @notice Remove KYC reviewer
    function removeReviewer(address _reviewer) external onlyRole(ADMIN_ROLE) {
        _revokeRole(KYC_REVIEWER_ROLE, _reviewer);
    }

    /// @notice Pause the contract
    function pause() external onlyRole(ADMIN_ROLE) {
        _pause();
    }

    /// @notice Unpause the contract
    function unpause() external onlyRole(ADMIN_ROLE) {
        _unpause();
    }

    /// @notice Authorize an escrow contract to record investments
    /// @param _escrow Escrow contract address
    function authorizeEscrow(address _escrow) external onlyRole(ADMIN_ROLE) validAddress(_escrow) {
        _grantRole(ESCROW_ROLE, _escrow);
        emit EscrowAuthorized(_escrow);
    }

    /// @notice Revoke escrow authorization
    /// @param _escrow Escrow contract address
    function revokeEscrow(address _escrow) external onlyRole(ADMIN_ROLE) {
        _revokeRole(ESCROW_ROLE, _escrow);
        emit EscrowRevoked(_escrow);
    }

    // ============================================
    // UPGRADE
    // ============================================

    function _authorizeUpgrade(address) internal override onlyRole(UPGRADER_ROLE) {}
}

