pragma solidity ^0.8.20;

import "../interfaces/IClaimIssuer.sol";
import "./MockIdentity.sol";

/**
 * @title MockClaimIssuer
 * @dev Mock implementation of IClaimIssuer for testing
 */
contract MockClaimIssuer is MockIdentity, IClaimIssuer {
    // ============ State Variables ============
    
    mapping(bytes => bool) internal _revokedSignatures;
    mapping(bytes32 => bool) internal _revokedClaimIds;
    
    // ============ Constructor ============
    
    constructor(address _owner) MockIdentity(_owner) {}
    
    // ============ IClaimIssuer Functions ============
    
    function revokeClaim(bytes32 _claimId, address /* _identity */) external override onlyOwner returns (bool) {
        _revokedClaimIds[_claimId] = true;
        emit ClaimRevoked(_claimId);
        return true;
    }
    
    function revokeClaimBySignature(bytes calldata _signature) external override onlyOwner {
        _revokedSignatures[_signature] = true;
    }
    
    function isClaimRevoked(bytes calldata _signature) external view override returns (bool) {
        return _revokedSignatures[_signature];
    }
    
    function isClaimValid(
        IIdentity _identity,
        uint256 _topic,
        bytes calldata _sig,
        bytes calldata _data
    ) external view override(IClaimIssuer, MockIdentity) returns (bool) {
        // Check if signature is revoked
        if (_revokedSignatures[_sig]) {
            return false;
        }
        
        // For testing purposes, always return true
        return true;
    }
    
    function getRecoveredAddress(
        bytes calldata _sig,
        bytes32 _dataHash
    ) external pure override returns (address) {
        // Simple signature recovery (for testing)
        if (_sig.length != 65) {
            return address(0);
        }
        
        bytes32 r;
        bytes32 s;
        uint8 v;
        
        assembly {
            r := calldataload(_sig.offset)
            s := calldataload(add(_sig.offset, 32))
            v := byte(0, calldataload(add(_sig.offset, 64)))
        }
        
        if (v < 27) {
            v += 27;
        }
        
        return ecrecover(_dataHash, v, r, s);
    }
}

