// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "../interfaces/IIdentity.sol";

/**
 * @title MockIdentity
 * @dev Mock implementation of IIdentity for testing
 */
contract MockIdentity is IIdentity {
    // ============ State Variables ============
    
    address public owner;
    
    // Key management
    mapping(bytes32 => uint256[]) internal _keyPurposes;
    mapping(bytes32 => uint256) internal _keyTypes;
    mapping(uint256 => bytes32[]) internal _keysByPurpose;
    
    // Claim management
    struct ClaimData {
        uint256 topic;
        uint256 scheme;
        address issuer;
        bytes signature;
        bytes data;
        string uri;
    }
    
    mapping(bytes32 => ClaimData) internal _claims;
    mapping(uint256 => bytes32[]) internal _claimsByTopic;
    
    uint256 internal _executionNonce;
    
    // ============ Constructor ============
    
    constructor(address _owner) {
        owner = _owner;
        
        // Add owner as management key (purpose = 1)
        bytes32 ownerKey = keccak256(abi.encodePacked(_owner));
        _keyPurposes[ownerKey].push(1); // MANAGEMENT_KEY
        _keyTypes[ownerKey] = 1; // ECDSA_TYPE
        _keysByPurpose[1].push(ownerKey);
    }
    
    // ============ Modifiers ============
    
    modifier onlyOwner() {
        require(msg.sender == owner, "MockIdentity: not owner");
        _;
    }
    
    // ============ IERC734 Functions ============
    
    function addKey(bytes32 _key, uint256 _purpose, uint256 _keyType) external override onlyOwner returns (bool) {
        _keyPurposes[_key].push(_purpose);
        _keyTypes[_key] = _keyType;
        _keysByPurpose[_purpose].push(_key);
        emit KeyAdded(_key, _purpose, _keyType);
        return true;
    }
    
    function removeKey(bytes32 _key, uint256 _purpose) external override onlyOwner returns (bool) {
        uint256[] storage purposes = _keyPurposes[_key];
        for (uint256 i = 0; i < purposes.length; i++) {
            if (purposes[i] == _purpose) {
                purposes[i] = purposes[purposes.length - 1];
                purposes.pop();
                break;
            }
        }
        emit KeyRemoved(_key, _purpose, _keyTypes[_key]);
        return true;
    }
    
    function execute(address _to, uint256 _value, bytes calldata _data) external payable override returns (uint256) {
        uint256 executionId = _executionNonce++;
        emit ExecutionRequested(executionId, _to, _value, _data);
        
        (bool success,) = _to.call{value: _value}(_data);
        emit Executed(executionId, _to, _value, _data);
        
        return executionId;
    }
    
    function approve(uint256 _id, bool _approve) external override returns (bool) {
        emit Approved(_id, _approve);
        return true;
    }
    
    function getKey(bytes32 _key) external view override returns (uint256[] memory purposes, uint256 keyType, bytes32 key) {
        return (_keyPurposes[_key], _keyTypes[_key], _key);
    }
    
    function getKeyPurposes(bytes32 _key) external view override returns (uint256[] memory) {
        return _keyPurposes[_key];
    }
    
    function getKeysByPurpose(uint256 _purpose) external view override returns (bytes32[] memory) {
        return _keysByPurpose[_purpose];
    }
    
    function keyHasPurpose(bytes32 _key, uint256 _purpose) external view override returns (bool) {
        uint256[] memory purposes = _keyPurposes[_key];
        for (uint256 i = 0; i < purposes.length; i++) {
            if (purposes[i] == _purpose) {
                return true;
            }
        }
        return false;
    }
    
    // ============ IERC735 Functions ============
    
    function addClaim(
        uint256 _topic,
        uint256 _scheme,
        address _issuer,
        bytes calldata _signature,
        bytes calldata _data,
        string calldata _uri
    ) external override returns (bytes32) {
        bytes32 claimId = keccak256(abi.encodePacked(_issuer, _topic));
        
        _claims[claimId] = ClaimData({
            topic: _topic,
            scheme: _scheme,
            issuer: _issuer,
            signature: _signature,
            data: _data,
            uri: _uri
        });
        
        _claimsByTopic[_topic].push(claimId);
        
        emit ClaimAdded(claimId, _topic, _scheme, _issuer, _signature, _data, _uri);
        return claimId;
    }
    
    function removeClaim(bytes32 _claimId) external override returns (bool) {
        ClaimData memory claim = _claims[_claimId];
        require(claim.issuer != address(0), "MockIdentity: claim does not exist");
        
        delete _claims[_claimId];
        
        emit ClaimRemoved(_claimId, claim.topic, claim.scheme, claim.issuer, claim.signature, claim.data, claim.uri);
        return true;
    }
    
    function getClaim(bytes32 _claimId) external view override returns (
        uint256 topic,
        uint256 scheme,
        address issuer,
        bytes memory signature,
        bytes memory data,
        string memory uri
    ) {
        ClaimData memory claim = _claims[_claimId];
        return (claim.topic, claim.scheme, claim.issuer, claim.signature, claim.data, claim.uri);
    }
    
    function getClaimIdsByTopic(uint256 _topic) external view override returns (bytes32[] memory) {
        return _claimsByTopic[_topic];
    }
    
    // ============ IIdentity Functions ============
    
    function isClaimValid(
        IIdentity /* _identity */,
        uint256 _topic,
        bytes calldata /* _sig */,
        bytes calldata /* _data */
    ) external view virtual override returns (bool) {
        // For testing, just check if a claim exists for this topic
        bytes32[] memory claimIds = _claimsByTopic[_topic];
        return claimIds.length > 0;
    }
}

contracts/OffChainInvestmentManager.sol.content:
// contracts/OffChainInvestmentManager.sol
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/PausableUpgradeable.sol";

interface IRWAProjectNFT {
    struct Project {
        uint256 id;
        address owner;
        string metadataURI;
        uint256 fundingGoal;
        uint256 totalRaised;
        uint256 minInvestment;
        uint256 maxInvestment;
        uint256 deadline;
        uint8 status;
        address securityToken;
        address escrowVault;
        uint256 createdAt;
        uint256 completedAt;
        bool transferable;
    }
    
    function getProject(uint256 projectId) external view returns (Project memory);
    function projectExists(uint256 projectId) external view returns (bool);
}

interface IRWASecurityToken {
    function mintForOffChainPayment(
        address _to,
        uint256 _tokenAmount,
        string calldata _paymentMethod,
        string calldata _paymentReference
    ) external;
    function isPaymentProcessed(string calldata _reference) external view returns (bool);
}

interface IIdentityRegistry {
    function isVerified(address _userAddress) external view returns (bool);
}

contract OffChainInvestmentManager is
    Initializable,
    AccessControlUpgradeable,
    UUPSUpgradeable,
    ReentrancyGuardUpgradeable,
    PausableUpgradeable
{
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
    bytes32 public constant PROCESSOR_ROLE = keccak256("PROCESSOR_ROLE");
    bytes32 public constant UPGRADER_ROLE = keccak256("UPGRADER_ROLE");

    enum PaymentStatus { Pending, Confirmed, Minted, Failed, Refunded }
    enum PaymentMethod { Stripe, BankTransfer, Wire, Check, Crypto, Other }

    struct Investment {
        uint256 id;
        uint256 projectId;
        address investor;
        uint256 amountUSD;
        uint256 tokenAmount;
        PaymentMethod paymentMethod;
        string paymentReference;
        PaymentStatus status;
        uint256 createdAt;
        uint256 processedAt;
        address processor;
        string notes;
    }

    IRWAProjectNFT public projectNFT;
    IIdentityRegistry public identityRegistry;

    uint256 private _investmentCounter;
    
    mapping(uint256 => Investment) public investments;
    mapping(string => uint256) public paymentReferenceToId;
    mapping(address => uint256[]) public investorInvestments;
    mapping(uint256 => uint256[]) public projectInvestments;
    
    mapping(uint256 => uint256) public projectOffChainRaised;
    mapping(uint256 => uint256) public projectTokenPrice;
    uint256 public defaultTokenPrice;

    event InvestmentCreated(
        uint256 indexed investmentId,
        uint256 indexed projectId,
        address indexed investor,
        uint256 amountUSD,
        PaymentMethod paymentMethod,
        string paymentReference
    );
    event InvestmentConfirmed(uint256 indexed investmentId, address processor);
    event TokensMinted(uint256 indexed investmentId, address indexed investor, uint256 tokenAmount);
    event InvestmentFailed(uint256 indexed investmentId, string reason);
    event InvestmentRefunded(uint256 indexed investmentId);
    event TokenPriceSet(uint256 indexed projectId, uint256 priceInCents);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(
        address _admin,
        address _projectNFT,
        address _identityRegistry
    ) public initializer {
        __AccessControl_init();
        __UUPSUpgradeable_init();
        __ReentrancyGuard_init();
        __Pausable_init();

        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(OPERATOR_ROLE, _admin);
        _grantRole(PROCESSOR_ROLE, _admin);
        _grantRole(UPGRADER_ROLE, _admin);

        projectNFT = IRWAProjectNFT(_projectNFT);
        identityRegistry = IIdentityRegistry(_identityRegistry);
        defaultTokenPrice = 100;
    }

    function createInvestment(
        uint256 _projectId,
        address _investor,
        uint256 _amountUSD,
        PaymentMethod _paymentMethod,
        string calldata _paymentReference
    ) external onlyRole(PROCESSOR_ROLE) whenNotPaused returns (uint256 investmentId) {
        require(projectNFT.projectExists(_projectId), "Project does not exist");
        require(_investor != address(0), "Invalid investor address");
        require(_amountUSD > 0, "Amount must be greater than 0");
        require(bytes(_paymentReference).length > 0, "Payment reference required");
        require(paymentReferenceToId[_paymentReference] == 0, "Payment reference already used");

        IRWAProjectNFT.Project memory project = projectNFT.getProject(_projectId);
        require(project.status == 2, "Project not active");

        require(identityRegistry.isVerified(_investor), "Investor not verified");

        uint256 tokenPrice = projectTokenPrice[_projectId];
        if (tokenPrice == 0) {
            tokenPrice = defaultTokenPrice;
        }
        uint256 tokenAmount = (_amountUSD * 1e18) / tokenPrice;

        _investmentCounter++;
        investmentId = _investmentCounter;

        investments[investmentId] = Investment({
            id: investmentId,
            projectId: _projectId,
            investor: _investor,
            amountUSD: _amountUSD,
            tokenAmount: tokenAmount,
            paymentMethod: _paymentMethod,
            paymentReference: _paymentReference,
            status: PaymentStatus.Pending,
            createdAt: block.timestamp,
            processedAt: 0,
            processor: address(0),
            notes: ""
        });

        paymentReferenceToId[_paymentReference] = investmentId;
        investorInvestments[_investor].push(investmentId);
        projectInvestments[_projectId].push(investmentId);

        emit InvestmentCreated(
            investmentId,
            _projectId,
            _investor,
            _amountUSD,
            _paymentMethod,
            _paymentReference
        );

        return investmentId;
    }

    function confirmAndMint(uint256 _investmentId) external onlyRole(PROCESSOR_ROLE) nonReentrant whenNotPaused {
        Investment storage investment = investments[_investmentId];
        require(investment.id != 0, "Investment does not exist");
        require(investment.status == PaymentStatus.Pending, "Investment not pending");

        IRWAProjectNFT.Project memory project = projectNFT.getProject(investment.projectId);
        require(project.securityToken != address(0), "Security token not deployed");

        investment.status = PaymentStatus.Confirmed;
        investment.processedAt = block.timestamp;
        investment.processor = msg.sender;

        emit InvestmentConfirmed(_investmentId, msg.sender);

        IRWASecurityToken securityToken = IRWASecurityToken(project.securityToken);
        
        string memory methodStr = _paymentMethodToString(investment.paymentMethod);
        
        securityToken.mintForOffChainPayment(
            investment.investor,
            investment.tokenAmount,
            methodStr,
            investment.paymentReference
        );

        investment.status = PaymentStatus.Minted;
        projectOffChainRaised[investment.projectId] += investment.amountUSD;

        emit TokensMinted(_investmentId, investment.investor, investment.tokenAmount);
    }

    function batchConfirmAndMint(uint256[] calldata _investmentIds) external onlyRole(PROCESSOR_ROLE) nonReentrant whenNotPaused {
        require(_investmentIds.length <= 20, "Batch too large");
        
        for (uint256 i = 0; i < _investmentIds.length; i++) {
            Investment storage investment = investments[_investmentIds[i]];
            
            if (investment.id == 0 || investment.status != PaymentStatus.Pending) {
                continue;
            }

            IRWAProjectNFT.Project memory project = projectNFT.getProject(investment.projectId);
            if (project.securityToken == address(0)) {
                continue;
            }

            investment.status = PaymentStatus.Confirmed;
            investment.processedAt = block.timestamp;
            investment.processor = msg.sender;

            emit InvestmentConfirmed(_investmentIds[i], msg.sender);

            IRWASecurityToken securityToken = IRWASecurityToken(project.securityToken);
            string memory methodStr = _paymentMethodToString(investment.paymentMethod);

            try securityToken.mintForOffChainPayment(
                investment.investor,
                investment.tokenAmount,
                methodStr,
                investment.paymentReference
            ) {
                investment.status = PaymentStatus.Minted;
                projectOffChainRaised[investment.projectId] += investment.amountUSD;
                emit TokensMinted(_investmentIds[i], investment.investor, investment.tokenAmount);
            } catch {
                investment.status = PaymentStatus.Failed;
                investment.notes = "Minting failed";
                emit InvestmentFailed(_investmentIds[i], "Minting failed");
            }
        }
    }

    function markFailed(uint256 _investmentId, string calldata _reason) external onlyRole(PROCESSOR_ROLE) {
        Investment storage investment = investments[_investmentId];
        require(investment.id != 0, "Investment does not exist");
        require(investment.status == PaymentStatus.Pending, "Investment not pending");

        investment.status = PaymentStatus.Failed;
        investment.processedAt = block.timestamp;
        investment.processor = msg.sender;
        investment.notes = _reason;

        emit InvestmentFailed(_investmentId, _reason);
    }

    function markRefunded(uint256 _investmentId) external onlyRole(PROCESSOR_ROLE) {
        Investment storage investment = investments[_investmentId];
        require(investment.id != 0, "Investment does not exist");
        require(
            investment.status == PaymentStatus.Pending || investment.status == PaymentStatus.Failed,
            "Cannot refund"
        );

        investment.status = PaymentStatus.Refunded;
        investment.processedAt = block.timestamp;
        investment.processor = msg.sender;

        emit InvestmentRefunded(_investmentId);
    }

    function setTokenPrice(uint256 _projectId, uint256 _priceInCents) external onlyRole(OPERATOR_ROLE) {
        require(_priceInCents > 0, "Price must be greater than 0");
        projectTokenPrice[_projectId] = _priceInCents;
        emit TokenPriceSet(_projectId, _priceInCents);
    }

    function setDefaultTokenPrice(uint256 _priceInCents) external onlyRole(OPERATOR_ROLE) {
        require(_priceInCents > 0, "Price must be greater than 0");
        defaultTokenPrice = _priceInCents;
    }

    function setProjectNFT(address _projectNFT) external onlyRole(DEFAULT_ADMIN_ROLE) {
        projectNFT = IRWAProjectNFT(_projectNFT);
    }

    function setIdentityRegistry(address _identityRegistry) external onlyRole(DEFAULT_ADMIN_ROLE) {
        identityRegistry = IIdentityRegistry(_identityRegistry);
    }

    // View functions
    function getInvestment(uint256 _investmentId) external view returns (Investment memory) {
        return investments[_investmentId];
    }

    function getInvestorInvestments(address _investor) external view returns (uint256[] memory) {
        return investorInvestments[_investor];
    }

    function getProjectInvestments(uint256 _projectId) external view returns (uint256[] memory) {
        return projectInvestments[_projectId];
    }

    function getProjectOffChainTotal(uint256 _projectId) external view returns (uint256) {
        return projectOffChainRaised[_projectId];
    }

    function calculateTokenAmount(uint256 _projectId, uint256 _amountUSD) external view returns (uint256) {
        uint256 tokenPrice = projectTokenPrice[_projectId];
        if (tokenPrice == 0) {
            tokenPrice = defaultTokenPrice;
        }
        return (_amountUSD * 1e18) / tokenPrice;
    }

    function getTotalInvestments() external view returns (uint256) {
        return _investmentCounter;
    }

    function _paymentMethodToString(PaymentMethod _method) internal pure returns (string memory) {
        if (_method == PaymentMethod.Stripe) return "Stripe";
        if (_method == PaymentMethod.BankTransfer) return "BankTransfer";
        if (_method == PaymentMethod.Wire) return "Wire";
        if (_method == PaymentMethod.Check) return "Check";
        if (_method == PaymentMethod.Crypto) return "Crypto";
        return "Other";
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    function _authorizeUpgrade(address newImplementation) internal override onlyRole(UPGRADER_ROLE) {}
}

