// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "../interfaces/IIdentityRegistry.sol";
import "../interfaces/IIdentityRegistryStorage.sol";
import "../interfaces/IClaimTopicsRegistry.sol";
import "../interfaces/ITrustedIssuersRegistry.sol";
import "../interfaces/IIdentity.sol";
import "../interfaces/IClaimIssuer.sol";

/**
 * @title IdentityRegistry
 * @dev Registry for managing investor identities and verification
 */
contract IdentityRegistry is
    Initializable,
    UUPSUpgradeable,
    AccessControlUpgradeable,
    IIdentityRegistry
{
    // ============ Constants ============

    bytes32 public constant AGENT_ROLE = keccak256("AGENT_ROLE");
    bytes32 public constant UPGRADER_ROLE = keccak256("UPGRADER_ROLE");

    // ============ State Variables ============

    IIdentityRegistryStorage private _identityStorage;
    IClaimTopicsRegistry private _claimTopicsRegistry;
    ITrustedIssuersRegistry private _trustedIssuersRegistry;

    // ============ Events (only declare events NOT in interface) ============
    
    event IdentityUpdated(address indexed investorAddress, IIdentity indexed oldIdentity, IIdentity indexed newIdentity);

    // ============ Initializer ============

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(
        address _admin,
        address _claimTopics,
        address _trustedIssuers,
        address _storage
    ) external initializer {
        require(_admin != address(0), "IdentityRegistry: zero admin");
        require(_claimTopics != address(0), "IdentityRegistry: zero claim topics");
        require(_trustedIssuers != address(0), "IdentityRegistry: zero trusted issuers");
        require(_storage != address(0), "IdentityRegistry: zero storage");

        __UUPSUpgradeable_init();
        __AccessControl_init();

        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(AGENT_ROLE, _admin);
        _grantRole(UPGRADER_ROLE, _admin);

        _claimTopicsRegistry = IClaimTopicsRegistry(_claimTopics);
        _trustedIssuersRegistry = ITrustedIssuersRegistry(_trustedIssuers);
        _identityStorage = IIdentityRegistryStorage(_storage);
    }

    // ============ Registration Functions ============

    function registerIdentity(
        address _userAddress,
        IIdentity _identity,
        uint16 _country
    ) external override onlyRole(AGENT_ROLE) {
        require(_userAddress != address(0), "IdentityRegistry: zero address");
        require(address(_identity) != address(0), "IdentityRegistry: zero identity");
        require(
            address(_identityStorage.storedIdentity(_userAddress)) == address(0),
            "IdentityRegistry: already registered"
        );

        _identityStorage.addIdentityToStorage(_userAddress, _identity, _country);
    }

    function batchRegisterIdentity(
        address[] calldata _userAddresses,
        IIdentity[] calldata _identities,
        uint16[] calldata _countries
    ) external override onlyRole(AGENT_ROLE) {
        require(
            _userAddresses.length == _identities.length &&
            _userAddresses.length == _countries.length,
            "IdentityRegistry: length mismatch"
        );

        for (uint256 i = 0; i < _userAddresses.length; i++) {
            require(_userAddresses[i] != address(0), "IdentityRegistry: zero address");
            require(address(_identities[i]) != address(0), "IdentityRegistry: zero identity");

            _identityStorage.addIdentityToStorage(
                _userAddresses[i],
                _identities[i],
                _countries[i]
            );
        }
    }

    function deleteIdentity(address _userAddress) external override onlyRole(AGENT_ROLE) {
        require(_userAddress != address(0), "IdentityRegistry: zero address");

        IIdentity userIdentity = _identityStorage.storedIdentity(_userAddress);
        require(address(userIdentity) != address(0), "IdentityRegistry: identity not found");

        _identityStorage.removeIdentityFromStorage(_userAddress);
    }

    function updateIdentity(
        address _userAddress,
        IIdentity _newIdentity
    ) external override onlyRole(AGENT_ROLE) {
        require(_userAddress != address(0), "IdentityRegistry: zero address");
        require(address(_newIdentity) != address(0), "IdentityRegistry: zero identity");

        IIdentity oldIdentity = _identityStorage.storedIdentity(_userAddress);
        require(address(oldIdentity) != address(0), "IdentityRegistry: not registered");

        _identityStorage.modifyStoredIdentity(_userAddress, _newIdentity);

        emit IdentityUpdated(_userAddress, oldIdentity, _newIdentity);
    }

    function updateCountry(
        address _userAddress,
        uint16 _country
    ) external override onlyRole(AGENT_ROLE) {
        require(_userAddress != address(0), "IdentityRegistry: zero address");
        require(
            address(_identityStorage.storedIdentity(_userAddress)) != address(0),
            "IdentityRegistry: not registered"
        );

        _identityStorage.modifyStoredInvestorCountry(_userAddress, _country);
    }

    // ============ Verification Functions ============

    function isVerified(address _userAddress) external view override returns (bool) {
        if (_userAddress == address(0)) {
            return false;
        }

        IIdentity userIdentity = _identityStorage.storedIdentity(_userAddress);
        if (address(userIdentity) == address(0)) {
            return false;
        }

        uint256[] memory requiredClaimTopics = _claimTopicsRegistry.getClaimTopics();

        if (requiredClaimTopics.length == 0) {
            return true;
        }

        for (uint256 i = 0; i < requiredClaimTopics.length; i++) {
            if (!_hasValidClaim(userIdentity, requiredClaimTopics[i])) {
                return false;
            }
        }

        return true;
    }

    function _hasValidClaim(
        IIdentity _identity,
        uint256 _topic
    ) internal view returns (bool) {
        bytes32[] memory claimIds = _identity.getClaimIdsByTopic(_topic);

        if (claimIds.length == 0) {
            return false;
        }

        IClaimIssuer[] memory trustedIssuers = _trustedIssuersRegistry.getTrustedIssuersForClaimTopic(_topic);

        if (trustedIssuers.length == 0) {
            return false;
        }

        for (uint256 i = 0; i < claimIds.length; i++) {
            (
                uint256 topic,
                ,
                address issuer,
                bytes memory signature,
                bytes memory data,
                
            ) = _identity.getClaim(claimIds[i]);

            for (uint256 j = 0; j < trustedIssuers.length; j++) {
                if (address(trustedIssuers[j]) == issuer) {
                    if (trustedIssuers[j].isClaimValid(_identity, topic, signature, data)) {
                        return true;
                    }
                }
            }
        }

        return false;
    }

    // ============ View Functions ============

    function identity(address _userAddress) external view override returns (IIdentity) {
        return _identityStorage.storedIdentity(_userAddress);
    }

    function investorCountry(address _userAddress) external view override returns (uint16) {
        return _identityStorage.storedInvestorCountry(_userAddress);
    }

    function identityStorage() external view override returns (IIdentityRegistryStorage) {
        return _identityStorage;
    }

    function topicsRegistry() external view override returns (IClaimTopicsRegistry) {
        return _claimTopicsRegistry;
    }

    function issuersRegistry() external view override returns (ITrustedIssuersRegistry) {
        return _trustedIssuersRegistry;
    }

    function contains(address _userAddress) external view override returns (bool) {
        return address(_identityStorage.storedIdentity(_userAddress)) != address(0);
    }

    function _authorizeUpgrade(
        address newImplementation
    ) internal override onlyRole(UPGRADER_ROLE) {}
}

contracts/registry/IdentityRegistryStora.content:
// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "../interfaces/IIdentityRegistryStorage.sol";
import "../interfaces/IIdentity.sol";
import "../libraries/Constants.sol";

/**
 * @title IdentityRegistryStorage
 * @dev Storage contract for investor identities
 */
contract IdentityRegistryStorage is 
    Initializable, 
    OwnableUpgradeable, 
    UUPSUpgradeable,
    IIdentityRegistryStorage 
{
    // Investor address => Identity contract
    mapping(address => IIdentity) private _identities;
    
    // Investor address => Country code (ISO 3166-1 numeric)
    mapping(address => uint16) private _countries;
    
    // Linked identity registries
    address[] private _identityRegistries;
    mapping(address => bool) private _isLinkedRegistry;

    modifier onlyLinkedRegistry() {
        require(_isLinkedRegistry[msg.sender], "IdentityRegistryStorage: caller not linked");
        _;
    }

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(address _owner) external initializer {
        __Ownable_init();
        __UUPSUpgradeable_init();
        _transferOwnership(_owner);
    }

    /**
     * @dev Add identity to storage
     */
    function addIdentityToStorage(
        address _userAddress,
        IIdentity _identity,
        uint16 _country
    ) external override onlyLinkedRegistry {
        require(_userAddress != address(0), "IdentityRegistryStorage: invalid user address");
        require(address(_identity) != address(0), "IdentityRegistryStorage: invalid identity");
        require(address(_identities[_userAddress]) == address(0), "IdentityRegistryStorage: identity already exists");

        _identities[_userAddress] = _identity;
        _countries[_userAddress] = _country;

        emit IdentityStored(_userAddress, _identity);
    }

    /**
     * @dev Remove identity from storage
     */
    function removeIdentityFromStorage(address _userAddress) external override onlyLinkedRegistry {
        require(address(_identities[_userAddress]) != address(0), "IdentityRegistryStorage: identity not found");

        IIdentity identity = _identities[_userAddress];
        delete _identities[_userAddress];
        delete _countries[_userAddress];

        emit IdentityUnstored(_userAddress, identity);
    }

    /**
     * @dev Modify stored country
     */
    function modifyStoredInvestorCountry(
        address _userAddress, 
        uint16 _country
    ) external override onlyLinkedRegistry {
        require(address(_identities[_userAddress]) != address(0), "IdentityRegistryStorage: identity not found");

        _countries[_userAddress] = _country;

        emit CountryModified(_userAddress, _country);
    }

    /**
     * @dev Modify stored identity
     */
    function modifyStoredIdentity(
        address _userAddress, 
        IIdentity _identity
    ) external override onlyLinkedRegistry {
        require(address(_identities[_userAddress]) != address(0), "IdentityRegistryStorage: identity not found");
        require(address(_identity) != address(0), "IdentityRegistryStorage: invalid identity");

        IIdentity oldIdentity = _identities[_userAddress];
        _identities[_userAddress] = _identity;

        emit IdentityModified(oldIdentity, _identity);
    }

    /**
     * @dev Bind an identity registry
     */
    function bindIdentityRegistry(address _identityRegistry) external override onlyOwner {
        require(_identityRegistry != address(0), "IdentityRegistryStorage: invalid registry");
        require(!_isLinkedRegistry[_identityRegistry], "IdentityRegistryStorage: already bound");
        require(
            _identityRegistries.length < Constants.MAX_IDENTITY_REGISTRIES, 
            "IdentityRegistryStorage: max registries reached"
        );

        _identityRegistries.push(_identityRegistry);
        _isLinkedRegistry[_identityRegistry] = true;

        emit IdentityRegistryBound(_identityRegistry);
    }

    /**
     * @dev Unbind an identity registry
     */
    function unbindIdentityRegistry(address _identityRegistry) external override onlyOwner {
        require(_isLinkedRegistry[_identityRegistry], "IdentityRegistryStorage: not bound");

        uint256 length = _identityRegistries.length;
        for (uint256 i = 0; i < length; i++) {
            if (_identityRegistries[i] == _identityRegistry) {
                _identityRegistries[i] = _identityRegistries[length - 1];
                _identityRegistries.pop();
                break;
            }
        }

        _isLinkedRegistry[_identityRegistry] = false;

        emit IdentityRegistryUnbound(_identityRegistry);
    }

    /**
     * @dev Get linked identity registries
     */
    function linkedIdentityRegistries() external view override returns (address[] memory) {
        return _identityRegistries;
    }

    /**
     * @dev Get stored identity
     */
    function storedIdentity(address _userAddress) external view override returns (IIdentity) {
        return _identities[_userAddress];
    }

    /**
     * @dev Get stored country
     */
    function storedInvestorCountry(address _userAddress) external view override returns (uint16) {
        return _countries[_userAddress];
    }

    /**
     * @dev Check if registry is linked
     */
    function isLinkedRegistry(address _registry) external view returns (bool) {
        return _isLinkedRegistry[_registry];
    }

    function _authorizeUpgrade(address) internal override onlyOwner {}
}

contracts/registry/TrustedIssuersRegistr.content:
// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "../interfaces/ITrustedIssuersRegistry.sol";
import "../interfaces/IClaimIssuer.sol";
import "../libraries/Constants.sol";

/**
 * @title TrustedIssuersRegistry
 * @dev Registry for trusted claim issuers
 */
contract TrustedIssuersRegistry is 
    Initializable, 
    OwnableUpgradeable, 
    UUPSUpgradeable,
    ITrustedIssuersRegistry 
{
    IClaimIssuer[] private _trustedIssuers;
    mapping(address => bool) private _isTrustedIssuer;
    mapping(address => uint256[]) private _issuerClaimTopics;
    mapping(address => mapping(uint256 => bool)) private _issuerHasClaimTopic;

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(address _owner) external initializer {
        __Ownable_init();
        __UUPSUpgradeable_init();
        _transferOwnership(_owner);
    }

    /**
     * @dev Add a trusted issuer
     */
    function addTrustedIssuer(
        IClaimIssuer _trustedIssuer, 
        uint256[] calldata _claimTopics
    ) external override onlyOwner {
        require(address(_trustedIssuer) != address(0), "TrustedIssuersRegistry: invalid issuer");
        require(!_isTrustedIssuer[address(_trustedIssuer)], "TrustedIssuersRegistry: issuer already exists");
        require(_claimTopics.length > 0, "TrustedIssuersRegistry: no claim topics");
        require(_claimTopics.length <= Constants.MAX_CLAIM_TOPICS, "TrustedIssuersRegistry: too many topics");
        require(_trustedIssuers.length < Constants.MAX_TRUSTED_ISSUERS, "TrustedIssuersRegistry: max issuers reached");

        _trustedIssuers.push(_trustedIssuer);
        _isTrustedIssuer[address(_trustedIssuer)] = true;
        
        for (uint256 i = 0; i < _claimTopics.length; i++) {
            _issuerClaimTopics[address(_trustedIssuer)].push(_claimTopics[i]);
            _issuerHasClaimTopic[address(_trustedIssuer)][_claimTopics[i]] = true;
        }

        emit TrustedIssuerAdded(_trustedIssuer, _claimTopics);
    }

    /**
     * @dev Remove a trusted issuer
     */
    function removeTrustedIssuer(IClaimIssuer _trustedIssuer) external override onlyOwner {
        require(_isTrustedIssuer[address(_trustedIssuer)], "TrustedIssuersRegistry: issuer not found");

        uint256 length = _trustedIssuers.length;
        for (uint256 i = 0; i < length; i++) {
            if (_trustedIssuers[i] == _trustedIssuer) {
                _trustedIssuers[i] = _trustedIssuers[length - 1];
                _trustedIssuers.pop();
                break;
            }
        }

        // Clear claim topics
        uint256[] memory topics = _issuerClaimTopics[address(_trustedIssuer)];
        for (uint256 i = 0; i < topics.length; i++) {
            _issuerHasClaimTopic[address(_trustedIssuer)][topics[i]] = false;
        }
        delete _issuerClaimTopics[address(_trustedIssuer)];
        
        _isTrustedIssuer[address(_trustedIssuer)] = false;

        emit TrustedIssuerRemoved(_trustedIssuer);
    }

    /**
     * @dev Update issuer claim topics
     */
    function updateIssuerClaimTopics(
        IClaimIssuer _trustedIssuer, 
        uint256[] calldata _claimTopics
    ) external override onlyOwner {
        require(_isTrustedIssuer[address(_trustedIssuer)], "TrustedIssuersRegistry: issuer not found");
        require(_claimTopics.length > 0, "TrustedIssuersRegistry: no claim topics");
        require(_claimTopics.length <= Constants.MAX_CLAIM_TOPICS, "TrustedIssuersRegistry: too many topics");

        // Clear old topics
        uint256[] memory oldTopics = _issuerClaimTopics[address(_trustedIssuer)];
        for (uint256 i = 0; i < oldTopics.length; i++) {
            _issuerHasClaimTopic[address(_trustedIssuer)][oldTopics[i]] = false;
        }
        delete _issuerClaimTopics[address(_trustedIssuer)];

        // Set new topics
        for (uint256 i = 0; i < _claimTopics.length; i++) {
            _issuerClaimTopics[address(_trustedIssuer)].push(_claimTopics[i]);
            _issuerHasClaimTopic[address(_trustedIssuer)][_claimTopics[i]] = true;
        }

        emit ClaimTopicsUpdated(_trustedIssuer, _claimTopics);
    }

    /**
     * @dev Get all trusted issuers
     */
    function getTrustedIssuers() external view override returns (IClaimIssuer[] memory) {
        return _trustedIssuers;
    }

    /**
     * @dev Get trusted issuers for a claim topic
     */
    function getTrustedIssuersForClaimTopic(
        uint256 _claimTopic
    ) external view override returns (IClaimIssuer[] memory) {
        uint256 count;
        
        // Count matching issuers
        for (uint256 i = 0; i < _trustedIssuers.length; i++) {
            if (_issuerHasClaimTopic[address(_trustedIssuers[i])][_claimTopic]) {
                count++;
            }
        }

        // Build result array
        IClaimIssuer[] memory result = new IClaimIssuer[](count);
        uint256 index;
        
        for (uint256 i = 0; i < _trustedIssuers.length; i++) {
            if (_issuerHasClaimTopic[address(_trustedIssuers[i])][_claimTopic]) {
                result[index++] = _trustedIssuers[i];
            }
        }

        return result;
    }

    /**
     * @dev Check if address is trusted issuer
     */
    function isTrustedIssuer(address _issuer) external view override returns (bool) {
        return _isTrustedIssuer[_issuer];
    }

    /**
     * @dev Get issuer's claim topics
     */
    function getTrustedIssuerClaimTopics(
        IClaimIssuer _trustedIssuer
    ) external view override returns (uint256[] memory) {
        return _issuerClaimTopics[address(_trustedIssuer)];
    }

    /**
     * @dev Check if issuer has claim topic
     */
    function hasClaimTopic(address _issuer, uint256 _claimTopic) external view override returns (bool) {
        return _issuerHasClaimTopic[_issuer][_claimTopic];
    }

    function _authorizeUpgrade(address) internal override onlyOwner {}
}

contracts/RWASecurityExchange.sol.content:
// contracts/RWASecurityExchange.sol
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/PausableUpgradeable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

interface IIdentityRegistry {
    function isVerified(address _userAddress) external view returns (bool);
}

interface IRWASecurityToken {
    function isLocked(address _account) external view returns (bool);
    function frozen(address _account) external view returns (bool);
}

contract RWASecurityExchange is
    Initializable,
    AccessControlUpgradeable,
    UUPSUpgradeable,
    ReentrancyGuardUpgradeable,
    PausableUpgradeable
{
    using SafeERC20 for IERC20;

    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
    bytes32 public constant FACTORY_ROLE = keccak256("FACTORY_ROLE");
    bytes32 public constant UPGRADER_ROLE = keccak256("UPGRADER_ROLE");

    enum OrderSide { Buy, Sell }
    enum OrderStatus { Active, Filled, PartiallyFilled, Cancelled }

    struct Order {
        uint256 id;
        address trader;
        address securityToken;
        address paymentToken;
        OrderSide side;
        uint256 price;
        uint256 amount;
        uint256 filled;
        uint256 createdAt;
        OrderStatus status;
    }

    struct TradingPair {
        address securityToken;
        address paymentToken;
        bool active;
        uint256 lastPrice;
        uint256 totalVolume;
        uint256 tradesCount;
        uint256 createdAt;
    }

    struct Trade {
        uint256 id;
        uint256 buyOrderId;
        uint256 sellOrderId;
        address buyer;
        address seller;
        address securityToken;
        address paymentToken;
        uint256 price;
        uint256 amount;
        uint256 timestamp;
    }

    // State
    IIdentityRegistry public identityRegistry;
    address public defaultPaymentToken;
    
    uint256 public makerFeeBps;
    uint256 public takerFeeBps;
    address public feeCollector;
    
    uint256 private _orderCounter;
    uint256 private _tradeCounter;
    
    mapping(uint256 => Order) public orders;
    mapping(address => uint256[]) public userOrders;
    
    mapping(bytes32 => TradingPair) public tradingPairs;
    mapping(address => bool) public acceptedPaymentTokens;
    
    mapping(bytes32 => uint256[]) public buyOrderBook;
    mapping(bytes32 => uint256[]) public sellOrderBook;
    
    mapping(uint256 => Trade) public trades;
    mapping(bytes32 => uint256[]) public pairTrades;
    
    bool public autoCreatePairs;

    // Events
    event TradingPairCreated(address indexed securityToken, address indexed paymentToken, bytes32 pairId);
    event TradingPairStatusChanged(bytes32 indexed pairId, bool active);
    event OrderCreated(
        uint256 indexed orderId,
        address indexed trader,
        address securityToken,
        address paymentToken,
        OrderSide side,
        uint256 price,
        uint256 amount
    );
    event OrderCancelled(uint256 indexed orderId);
    event OrderFilled(uint256 indexed orderId, uint256 filledAmount, uint256 remainingAmount);
    event TradeExecuted(
        uint256 indexed tradeId,
        uint256 indexed buyOrderId,
        uint256 indexed sellOrderId,
        address buyer,
        address seller,
        uint256 price,
        uint256 amount,
        uint256 buyerFee,
        uint256 sellerFee
    );
    event FeesUpdated(uint256 makerFeeBps, uint256 takerFeeBps);
    event FeeCollectorUpdated(address indexed newCollector);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(
        address _admin,
        address _identityRegistry,
        address _defaultPaymentToken,
        address _feeCollector
    ) public initializer {
        __AccessControl_init();
        __UUPSUpgradeable_init();
        __ReentrancyGuard_init();
        __Pausable_init();

        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(OPERATOR_ROLE, _admin);
        _grantRole(UPGRADER_ROLE, _admin);

        identityRegistry = IIdentityRegistry(_identityRegistry);
        defaultPaymentToken = _defaultPaymentToken;
        feeCollector = _feeCollector;
        
        makerFeeBps = 10;
        takerFeeBps = 25;
        
        acceptedPaymentTokens[_defaultPaymentToken] = true;
        autoCreatePairs = true;
    }

    // ============================================================================
    // TRADING PAIR MANAGEMENT
    // ============================================================================

    function createTradingPair(
        address _securityToken,
        address _paymentToken
    ) external onlyRole(OPERATOR_ROLE) returns (bytes32 pairId) {
        return _createTradingPair(_securityToken, _paymentToken);
    }

    function _createTradingPair(
        address _securityToken,
        address _paymentToken
    ) internal returns (bytes32 pairId) {
        require(_securityToken != address(0), "Invalid security token");
        require(acceptedPaymentTokens[_paymentToken], "Payment token not accepted");
        
        pairId = keccak256(abi.encodePacked(_securityToken, _paymentToken));
        require(tradingPairs[pairId].securityToken == address(0), "Pair already exists");

        tradingPairs[pairId] = TradingPair({
            securityToken: _securityToken,
            paymentToken: _paymentToken,
            active: true,
            lastPrice: 0,
            totalVolume: 0,
            tradesCount: 0,
            createdAt: block.timestamp
        });

        emit TradingPairCreated(_securityToken, _paymentToken, pairId);
        return pairId;
    }

    function createPairForToken(address _securityToken) external onlyRole(FACTORY_ROLE) returns (bytes32) {
        require(autoCreatePairs, "Auto-create disabled");
        return _createTradingPair(_securityToken, defaultPaymentToken);
    }

    function createPairsForToken(
        address _securityToken,
        address[] calldata _paymentTokens
    ) external onlyRole(OPERATOR_ROLE) {
        for (uint256 i = 0; i < _paymentTokens.length; i++) {
            if (acceptedPaymentTokens[_paymentTokens[i]]) {
                bytes32 pairId = keccak256(abi.encodePacked(_securityToken, _paymentTokens[i]));
                if (tradingPairs[pairId].securityToken == address(0)) {
                    _createTradingPair(_securityToken, _paymentTokens[i]);
                }
            }
        }
    }

    function setTradingPairStatus(bytes32 _pairId, bool _active) external onlyRole(OPERATOR_ROLE) {
        require(tradingPairs[_pairId].securityToken != address(0), "Pair does not exist");
        tradingPairs[_pairId].active = _active;
        emit TradingPairStatusChanged(_pairId, _active);
    }

    // ============================================================================
    // ORDER MANAGEMENT
    // ============================================================================

    function createOrder(
        address _securityToken,
        address _paymentToken,
        OrderSide _side,
        uint256 _price,
        uint256 _amount
    ) external nonReentrant whenNotPaused returns (uint256 orderId) {
        require(_price > 0, "Price must be greater than 0");
        require(_amount > 0, "Amount must be greater than 0");
        require(identityRegistry.isVerified(msg.sender), "Trader not verified");

        bytes32 pairId = keccak256(abi.encodePacked(_securityToken, _paymentToken));
        TradingPair storage pair = tradingPairs[pairId];
        require(pair.active, "Trading pair not active");

        IRWASecurityToken secToken = IRWASecurityToken(_securityToken);
        require(!secToken.frozen(msg.sender), "Account is frozen");
        
        if (_side == OrderSide.Sell) {
            require(!secToken.isLocked(msg.sender), "Tokens are locked");
            IERC20(_securityToken).safeTransferFrom(msg.sender, address(this), _amount);
        } else {
            uint256 totalCost = (_price * _amount) / 1e18;
            IERC20(_paymentToken).safeTransferFrom(msg.sender, address(this), totalCost);
        }

        _orderCounter++;
        orderId = _orderCounter;

        orders[orderId] = Order({
            id: orderId,
            trader: msg.sender,
            securityToken: _securityToken,
            paymentToken: _paymentToken,
            side: _side,
            price: _price,
            amount: _amount,
            filled: 0,
            createdAt: block.timestamp,
            status: OrderStatus.Active
        });

        userOrders[msg.sender].push(orderId);

        if (_side == OrderSide.Buy) {
            _insertBuyOrder(pairId, orderId, _price);
        } else {
            _insertSellOrder(pairId, orderId, _price);
        }

        emit OrderCreated(orderId, msg.sender, _securityToken, _paymentToken, _side, _price, _amount);

        _matchOrders(pairId);

        return orderId;
    }

    function cancelOrder(uint256 _orderId) external nonReentrant {
        Order storage order = orders[_orderId];
        require(order.trader == msg.sender, "Not order owner");
        require(order.status == OrderStatus.Active || order.status == OrderStatus.PartiallyFilled, "Cannot cancel");

        uint256 remainingAmount = order.amount - order.filled;
        order.status = OrderStatus.Cancelled;

        bytes32 pairId = keccak256(abi.encodePacked(order.securityToken, order.paymentToken));
        
        if (order.side == OrderSide.Buy) {
            _removeFromOrderBook(buyOrderBook[pairId], _orderId);
            uint256 refund = (order.price * remainingAmount) / 1e18;
            IERC20(order.paymentToken).safeTransfer(msg.sender, refund);
        } else {
            _removeFromOrderBook(sellOrderBook[pairId], _orderId);
            IERC20(order.securityToken).safeTransfer(msg.sender, remainingAmount);
        }

        emit OrderCancelled(_orderId);
    }

    // ============================================================================
    // ORDER MATCHING
    // ============================================================================

    function _matchOrders(bytes32 _pairId) internal {
        uint256[] storage buyOrders = buyOrderBook[_pairId];
        uint256[] storage sellOrders = sellOrderBook[_pairId];

        while (buyOrders.length > 0 && sellOrders.length > 0) {
            Order storage buyOrder = orders[buyOrders[0]];
            Order storage sellOrder = orders[sellOrders[0]];

            if (buyOrder.price < sellOrder.price) {
                break;
            }

            uint256 buyRemaining = buyOrder.amount - buyOrder.filled;
            uint256 sellRemaining = sellOrder.amount - sellOrder.filled;
            uint256 tradeAmount = buyRemaining < sellRemaining ? buyRemaining : sellRemaining;

            _executeTrade(buyOrder, sellOrder, sellOrder.price, tradeAmount, _pairId);

            if (buyOrder.filled == buyOrder.amount) {
                buyOrder.status = OrderStatus.Filled;
                _removeFirstFromOrderBook(buyOrders);
            } else {
                buyOrder.status = OrderStatus.PartiallyFilled;
            }

            if (sellOrder.filled == sellOrder.amount) {
                sellOrder.status = OrderStatus.Filled;
                _removeFirstFromOrderBook(sellOrders);
            } else {
                sellOrder.status = OrderStatus.PartiallyFilled;
            }
        }
    }

    function _executeTrade(
        Order storage _buyOrder,
        Order storage _sellOrder,
        uint256 _price,
        uint256 _amount,
        bytes32 _pairId
    ) internal {
        uint256 paymentAmount = (_price * _amount) / 1e18;
        
        uint256 buyerFee = (paymentAmount * takerFeeBps) / 10000;
        uint256 sellerFee = (paymentAmount * makerFeeBps) / 10000;
        
        if (_buyOrder.createdAt < _sellOrder.createdAt) {
            uint256 temp = buyerFee;
            buyerFee = sellerFee;
            sellerFee = temp;
        }

        _buyOrder.filled += _amount;
        _sellOrder.filled += _amount;

        IERC20(_buyOrder.securityToken).safeTransfer(_buyOrder.trader, _amount);
        IERC20(_buyOrder.paymentToken).safeTransfer(_sellOrder.trader, paymentAmount - sellerFee);
        
        uint256 buyerPaid = (_buyOrder.price * _amount) / 1e18;
        uint256 buyerRefund = buyerPaid - paymentAmount - buyerFee;
        if (buyerRefund > 0) {
            IERC20(_buyOrder.paymentToken).safeTransfer(_buyOrder.trader, buyerRefund);
        }
        
        uint256 totalFees = buyerFee + sellerFee;
        if (totalFees > 0 && feeCollector != address(0)) {
            IERC20(_buyOrder.paymentToken).safeTransfer(feeCollector, totalFees);
        }

        _tradeCounter++;
        trades[_tradeCounter] = Trade({
            id: _tradeCounter,
            buyOrderId: _buyOrder.id,
            sellOrderId: _sellOrder.id,
            buyer: _buyOrder.trader,
            seller: _sellOrder.trader,
            securityToken: _buyOrder.securityToken,
            paymentToken: _buyOrder.paymentToken,
            price: _price,
            amount: _amount,
            timestamp: block.timestamp
        });

        pairTrades[_pairId].push(_tradeCounter);

        TradingPair storage pair = tradingPairs[_pairId];
        pair.lastPrice = _price;
        pair.totalVolume += paymentAmount;
        pair.tradesCount++;

        emit TradeExecuted(
            _tradeCounter,
            _buyOrder.id,
            _sellOrder.id,
            _buyOrder.trader,
            _sellOrder.trader,
            _price,
            _amount,
            buyerFee,
            sellerFee
        );

        emit OrderFilled(_buyOrder.id, _buyOrder.filled, _buyOrder.amount - _buyOrder.filled);
        emit OrderFilled(_sellOrder.id, _sellOrder.filled, _sellOrder.amount - _sellOrder.filled);
    }

    // ============================================================================
    // ORDER BOOK HELPERS
    // ============================================================================

    function _insertBuyOrder(bytes32 _pairId, uint256 _orderId, uint256 _price) internal {
        uint256[] storage book = buyOrderBook[_pairId];
        uint256 i = book.length;
        book.push(_orderId);
        
        while (i > 0 && orders[book[i - 1]].price < _price) {
            book[i] = book[i - 1];
            i--;
        }
        book[i] = _orderId;
    }

    function _insertSellOrder(bytes32 _pairId, uint256 _orderId, uint256 _price) internal {
        uint256[] storage book = sellOrderBook[_pairId];
        uint256 i = book.length;
        book.push(_orderId);
        
        while (i > 0 && orders[book[i - 1]].price > _price) {
            book[i] = book[i - 1];
            i--;
        }
        book[i] = _orderId;
    }

    function _removeFromOrderBook(uint256[] storage _book, uint256 _orderId) internal {
        for (uint256 i = 0; i < _book.length; i++) {
            if (_book[i] == _orderId) {
                _book[i] = _book[_book.length - 1];
                _book.pop();
                break;
            }
        }
    }

    function _removeFirstFromOrderBook(uint256[] storage _book) internal {
        if (_book.length > 0) {
            for (uint256 i = 0; i < _book.length - 1; i++) {
                _book[i] = _book[i + 1];
            }
            _book.pop();
        }
    }

    // ============================================================================
    // VIEW FUNCTIONS
    // ============================================================================

    function getPairId(address _securityToken, address _paymentToken) external pure returns (bytes32) {
        return keccak256(abi.encodePacked(_securityToken, _paymentToken));
    }

    function getTradingPair(address _securityToken, address _paymentToken) external view returns (TradingPair memory) {
        bytes32 pairId = keccak256(abi.encodePacked(_securityToken, _paymentToken));
        return tradingPairs[pairId];
    }

    function validPairs(address _securityToken, address _paymentToken) external view returns (bool) {
        bytes32 pairId = keccak256(abi.encodePacked(_securityToken, _paymentToken));
        return tradingPairs[pairId].active;
    }

    function getOrder(uint256 _orderId) external view returns (Order memory) {
        return orders[_orderId];
    }

    function getUserOrders(address _user) external view returns (uint256[] memory) {
        return userOrders[_user];
    }

    function getUserActiveOrders(address _user) external view returns (Order[] memory) {
        uint256[] memory orderIds = userOrders[_user];
        uint256 activeCount = 0;
        
        for (uint256 i = 0; i < orderIds.length; i++) {
            if (orders[orderIds[i]].status == OrderStatus.Active || 
                orders[orderIds[i]].status == OrderStatus.PartiallyFilled) {
                activeCount++;
            }
        }
        
        Order[] memory activeOrders = new Order[](activeCount);
        uint256 index = 0;
        
        for (uint256 i = 0; i < orderIds.length; i++) {
            if (orders[orderIds[i]].status == OrderStatus.Active || 
                orders[orderIds[i]].status == OrderStatus.PartiallyFilled) {
                activeOrders[index] = orders[orderIds[i]];
                index++;
            }
        }
        
        return activeOrders;
    }

    function getOrderBook(
        address _securityToken,
        address _paymentToken,
        uint256 _limit
    ) external view returns (Order[] memory buyOrders, Order[] memory sellOrders) {
        bytes32 pairId = keccak256(abi.encodePacked(_securityToken, _paymentToken));
        
        uint256[] storage buyIds = buyOrderBook[pairId];
        uint256[] storage sellIds = sellOrderBook[pairId];
        
        uint256 buyCount = buyIds.length < _limit ? buyIds.length : _limit;
        uint256 sellCount = sellIds.length < _limit ? sellIds.length : _limit;
        
        buyOrders = new Order[](buyCount);
        sellOrders = new Order[](sellCount);
        
        for (uint256 i = 0; i < buyCount; i++) {
            buyOrders[i] = orders[buyIds[i]];
        }
        
        for (uint256 i = 0; i < sellCount; i++) {
            sellOrders[i] = orders[sellIds[i]];
        }
        
        return (buyOrders, sellOrders);
    }

    function getTrade(uint256 _tradeId) external view returns (Trade memory) {
        return trades[_tradeId];
    }

    function getPairTrades(bytes32 _pairId, uint256 _limit) external view returns (Trade[] memory) {
        uint256[] storage tradeIds = pairTrades[_pairId];
        uint256 count = tradeIds.length < _limit ? tradeIds.length : _limit;
        
        Trade[] memory result = new Trade[](count);
        
        for (uint256 i = 0; i < count; i++) {
            result[i] = trades[tradeIds[tradeIds.length - 1 - i]];
        }
        
        return result;
    }

    function getTotalOrders() external view returns (uint256) {
        return _orderCounter;
    }

    function getTotalTrades() external view returns (uint256) {
        return _tradeCounter;
    }

    // ============================================================================
    // ADMIN FUNCTIONS
    // ============================================================================

    function setFees(uint256 _makerFeeBps, uint256 _takerFeeBps) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_makerFeeBps <= 100, "Maker fee too high");
        require(_takerFeeBps <= 100, "Taker fee too high");
        makerFeeBps = _makerFeeBps;
        takerFeeBps = _takerFeeBps;
        emit FeesUpdated(_makerFeeBps, _takerFeeBps);
    }

    function setFeeCollector(address _feeCollector) external onlyRole(DEFAULT_ADMIN_ROLE) {
        feeCollector = _feeCollector;
        emit FeeCollectorUpdated(_feeCollector);
    }

    function setAcceptedPaymentToken(address _token, bool _accepted) external onlyRole(OPERATOR_ROLE) {
        acceptedPaymentTokens[_token] = _accepted;
    }

    function setAutoCreatePairs(bool _enabled) external onlyRole(OPERATOR_ROLE) {
        autoCreatePairs = _enabled;
    }

    function setIdentityRegistry(address _identityRegistry) external onlyRole(DEFAULT_ADMIN_ROLE) {
        identityRegistry = IIdentityRegistry(_identityRegistry);
    }

    function setDefaultPaymentToken(address _token) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(acceptedPaymentTokens[_token], "Token not accepted");
        defaultPaymentToken = _token;
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    function emergencyWithdraw(address _token, uint256 _amount) external onlyRole(DEFAULT_ADMIN_ROLE) {
        IERC20(_token).safeTransfer(msg.sender, _amount);
    }

    function _authorizeUpgrade(address newImplementation) internal override onlyRole(UPGRADER_ROLE) {}
}
